INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_restorative-reproductive-medicine', 'restorative-reproductive-medicine', 'Restorative Reproductive Medicine (RRM)', 'I', 0, '<p><strong>A specialized field of medicine that diagnoses and treats the underlying health conditions causing reproductive dysfunction in women and men, cooperating with and restoring the natural physiology and anatomy of the reproductive system rather than bypassing or suppressing it.</strong><sup class="cite-ref"><a href="#ref-1">1</a></sup> RRM applies across the reproductive lifespan to conditions including <a href="#infertility" class="gloss-xref">infertility</a>, recurrent miscarriage, <a href="#pcos" class="gloss-xref">PCOS</a>, <a href="#endometriosis" class="gloss-xref">endometriosis</a>, <a href="#pms" class="gloss-xref">PMS</a>/PMDD, irregular or painful periods, hormonal dysfunction, male factor conditions, and <a href="#perimenopause" class="gloss-xref">perimenopause</a>. Care draws on cycle charting as a clinical diagnostic instrument, targeted medical workup, hormone and pharmacologic therapies, <a href="#restorative-as-a-principle" class="gloss-xref">restorative</a> surgery and andrology, and lifestyle interventions.<sup class="cite-ref"><a href="#ref-2">2</a></sup> The goal is a body functioning at its healthy physiologic state, with restored reproductive abilities such as fertility as a natural outcome.<sup class="cite-ref"><a href="#ref-3">3</a></sup></p>', 'RRM', '/what-is-rrm/', 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_root-cause-diagnosis', 'root-cause-diagnosis', 'Root Cause Diagnosis', 'I', 1, '<p><strong>The foundational <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> principle that reproductive health problems (including <a href="#infertility" class="gloss-xref">infertility</a>, abnormal bleeding, and chronic pain) are symptoms of identifiable underlying causes, not final diagnoses in themselves.</strong> Underlying causes may include hormonal imbalances, structural abnormalities (e.g., tubal blockage, uterine defects), inflammatory conditions, autoimmune disorders, metabolic dysfunction, or iatrogenic factors such as C-section scar defects or prior surgical complications. RRM does not accept "<a href="#unexplained-infertility" class="gloss-xref">unexplained infertility</a>" as a final answer, but continues deeper investigation to find treatable hidden causes.<sup class="cite-ref"><a href="#ref-3">3</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_restorative-as-a-principle', 'restorative-as-a-principle', 'Restorative (as a Principle)', 'I', 2, '<p><strong>Pertaining to the goal of repairing, healing, and optimizing the natural function of the reproductive system.</strong> The restorative approach contrasts with suppressive therapies (e.g., hormonal contraception used to mask cycle symptoms) and bypass therapies (e.g., <a href="#ivf" class="gloss-xref">IVF</a> circumventing tubal disease). It also encompasses removal of problematic devices and reversal of prior procedures such as tubal ligation to restore health or fertility potential.<sup class="cite-ref"><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_natural-fertility', 'natural-fertility', 'Natural Fertility', 'I', 3, '<p><strong>The inherent biological capacity for reproduction through in vivo (in the body) conception, without gamete removal or external fertilization.</strong> <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> aims to restore or optimize natural fertility through corrective medical and surgical interventions, including procedures like tubal reversal.<sup class="cite-ref"><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_body-literacy', 'body-literacy', 'Body Literacy', 'I', 4, '<p><strong>An individual''s informed understanding of their own biological signs and reproductive cycle,</strong> typically developed through systematic <a href="#fertility-charting" class="gloss-xref">fertility charting</a>. Body literacy empowers patients to recognize abnormalities early, time intercourse and diagnostics appropriately, and participate actively in their own care.<sup class="cite-ref"><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_comprehensive-evaluation', 'comprehensive-evaluation', 'Comprehensive Evaluation', 'I', 5, '<p><strong>A thorough <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> assessment designed to identify underlying conditions.</strong> Typically includes detailed cycle charting (using the Creighton Model or other <a href="#fabms" class="gloss-xref">FABMs</a>), timed hormonal blood tests, ultrasound series (including saline infusion sonohysterogram for structural assessment), <a href="#hsg" class="gloss-xref">hysterosalpingogram</a> (HSG), <a href="#semen-analysis" class="gloss-xref">semen analysis</a>, and targeted testing for endocrine, immune, clotting, or genetic factors. Diagnostic and/or operative <a href="#laparoscopy-operative" class="gloss-xref">laparoscopy</a> and <a href="#hysteroscopy-operative" class="gloss-xref">hysteroscopy</a> are employed when indicated, essential for definitive diagnosis of <a href="#endometriosis" class="gloss-xref">endometriosis</a>, <a href="#pelvic-adhesions" class="gloss-xref">pelvic adhesions</a>, <a href="#chronic-endometritis" class="gloss-xref">chronic endometritis</a>, and isthmoceles.<sup class="cite-ref"><a href="#ref-3">3</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_personalized-treatment', 'personalized-treatment', 'Personalized Treatment', 'I', 6, '<p><strong>The practice of tailoring medical and/or surgical interventions to the specific underlying conditions identified during evaluation,</strong> incorporating patient goals (e.g., desire for future fertility influences the choice of <a href="#isthmocele-repair-laparoscopic" class="gloss-xref">isthmocele repair</a> method). Treatment plans may include targeted hormonal therapy, ovulation induction, <a href="#luteal-phase" class="gloss-xref">luteal phase</a> support, nutritional protocols, lifestyle modifications, and specialized surgery.<sup class="cite-ref"><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_holistic-approach', 'holistic-approach', 'Holistic Approach', 'I', 7, '<p><strong>Consideration of the whole person and the interplay of bodily systems</strong> (endocrine, immune, metabolic, inflammatory, musculoskeletal) and their collective impact on reproductive health. <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> addresses genetics, lifestyle, prior interventions, and overall systemic wellness alongside specific pelvic pathology.<sup class="cite-ref"><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_reproductive-health-optimization', 'reproductive-health-optimization', 'Reproductive Health Optimization', 'I', 8, '<p><strong>The overarching <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> goal of improving the overall health and function of the reproductive system</strong>: encompassing fertility, cycle regularity, absence of pain or abnormal bleeding, hormonal balance, and long-term gynecologic wellness. Achieving pregnancy is a result of restored health, not merely the isolated procedural endpoint.<sup class="cite-ref"><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_corrective-vs-bypass', 'corrective-vs-bypass', 'Corrective vs. Bypass/Suppressive', 'I', 9, '<p><strong>A key <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> conceptual distinction.</strong> RRM aims to correct underlying anatomical, hormonal, or immunological problems (e.g., surgical repair of fallopian tubes, isthmocele reconstruction, adhesion excision), whereas bypass therapies circumvent <a href="#infertility" class="gloss-xref">infertility</a> problems (<a href="#ivf" class="gloss-xref">IVF</a> bypasses tubal blockage), suppressive therapies mask symptoms (hormonal contraception <a href="#excision-surgery" class="gloss-xref">for endometriosis</a> pain), and hysterectomy removes the affected organ entirely.<sup class="cite-ref"><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_fabms', 'fabms', 'Fertility Awareness-Based Methods (FABMs)', 'II', 0, '<p><strong>An umbrella term for scientific methods used to monitor and interpret biological signs of fertility (<a href="#biomarkers" class="gloss-xref">biomarkers</a>) throughout the menstrual cycle.</strong> FABMs can be used for health monitoring, timing diagnostics and treatments in <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a>, and achieving or avoiding pregnancy. A 2025 systematic review of 20,339 participants from 16 studies found that FABMs, when used correctly, were associated with a success rate of over 90% for both contraception and conception purposes. FABMs encourage partner involvement, improve communication, and enhance <a href="#body-literacy" class="gloss-xref">body literacy</a> by tracking female biomarkers to determine fertility status, and can also help diagnose ovulation-related disorders such as <a href="#pcos" class="gloss-xref">PCOS</a> and <a href="#endometriosis" class="gloss-xref">endometriosis</a>. Note: The <a href="#creighton-model" class="gloss-xref">Creighton Model FertilityCare System</a> is specifically classified as an <a href="#nfp" class="gloss-xref">NFP</a> method by its developers and is distinct from the FABM umbrella.<sup class="cite-ref"><a href="#ref-5">5</a></sup><sup class="cite-ref"><a href="#ref-6">6</a></sup></p>', 'FABMs', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_fertility-charting', 'fertility-charting', 'Fertility Charting', 'II', 1, '<p><strong>The systematic daily recording of fertility <a href="#biomarkers" class="gloss-xref">biomarkers</a> according to a specific standardized method,</strong> such as the Creighton Model or another FABM. Chart data function analogously to an ECG for the reproductive system, revealing hormonal patterns, potential abnormalities, and optimal windows for diagnostics, treatment timing, and intercourse. Changes in charting patterns serve as a form of biofeedback to assess treatment efficacy.<sup class="cite-ref"><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_biomarkers', 'biomarkers', 'Biomarkers (Fertility)', 'II', 2, '<p><strong>Observable biological signs that change predictably across the menstrual cycle and indicate reproductive status.</strong> Primary biomarkers directly reflect hormonal activity: the cervical <a href="#mucus-pattern" class="gloss-xref">mucus pattern</a> (appearance, sensation, elasticity) shifts with rising estrogen, <a href="#bbt" class="gloss-xref">basal body temperature</a> (BBT) rises 0.2 to 0.5 degrees C after progesterone release, and hormone levels (<a href="#lh" class="gloss-xref">LH</a>, <a href="#fsh" class="gloss-xref">FSH</a>, estradiol, progesterone) are measurable via blood tests or urine metabolites. Secondary biomarkers include cycle length patterns, bleeding characteristics, cervical position and texture, mittelschmerz (mid-cycle pelvic pain), and breast tenderness. In <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a>, biomarkers function clinically rather than merely observationally: charted patterns identify the fertile window, confirm ovulation, flag <a href="#luteal-phase-deficiency" class="gloss-xref">luteal phase deficiency</a>, and time cycle-phase-specific diagnostics and treatments.<sup class="cite-ref"><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_nfp', 'nfp', 'Natural Family Planning (NFP)', 'II', 3, '<p><strong>Methods used to achieve or avoid pregnancy based on identifying the fertile window through observation of biological signs.</strong> The <a href="#creighton-model" class="gloss-xref">Creighton Model FertilityCare System</a> is a specific, standardized NFP method foundational to <a href="#naprotechnology-definition" class="gloss-xref">NaProTECHNOLOGY</a>. NFP and FABM are sometimes used interchangeably in clinical literature, though they are not identical categories.</p>', 'NFP', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_creighton-model', 'creighton-model', 'Creighton Model FertilityCare System (CrMS)', 'II', 4, '<p><strong>A standardized, prospective method of <a href="#nfp" class="gloss-xref">Natural Family Planning</a> (NFP) focused on detailed observation and classification of cervical mucus patterns and other biological markers,</strong> developed at the Pope Paul VI Institute by Dr. Thomas Hilgers. The CrMS is distinct from the broader FABM category. Its developers specifically distinguish it as an NFP method. The CrMS provides precise information for monitoring gynecologic health and fertility and forms the diagnostic foundation for <a href="#naprotechnology-definition" class="gloss-xref">NaProTECHNOLOGY</a>, allowing cycle-phase-specific timing of blood tests and medical treatments. Published effectiveness data show CrMS is up to 98% effective for achieving pregnancy in couples with normal fertility and, in conjunction with NaPro, up to 80% effective for couples experiencing <a href="#infertility" class="gloss-xref">infertility</a>. A prospective cohort study (CEIBA) in 17 CrMS centers across the USA and Canada found the highest 13-cycle pregnancy rate with correct use to conceive was 89.6%, when intercourse was timed to peak-type mucus days.<sup class="cite-ref"><a href="#ref-7">7</a></sup><sup class="cite-ref"><a href="#ref-8">8</a></sup><sup class="cite-ref"><a href="#ref-9">9</a></sup></p>', 'CrMS', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_peak-day', 'peak-day', 'Peak Day', 'II', 5, '<p><strong>In mucus-based methods (including the <a href="#billings-ovulation-method" class="gloss-xref">Billings Ovulation Method</a>), the last day of fertile-type cervical mucus</strong> (characterized as clear, stretchy, or lubricative) correlating closely with the time of ovulation. Peak Day marks the transition point in the <a href="#mucus-pattern" class="gloss-xref">mucus pattern</a> from fertile-type to post-ovulatory. In <a href="#creighton-model" class="gloss-xref">CrMS</a>, Peak Day identification is critical for timing luteal progesterone support in <a href="#napro-medical" class="gloss-xref">NaPro Medical</a> protocols.<sup class="cite-ref"><a href="#ref-8">8</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_billings-ovulation-method', 'billings-ovulation-method', 'Billings Ovulation Method', 'II', 6, '<p><strong>A standardized FABM developed by Australian physicians Drs. John and Evelyn Billings in the 1960s, based entirely on the sensation and appearance of cervical mucus at the vulva to identify the fertile window.</strong> The Billings method requires no temperature taking and no instruments, making it globally accessible across cultural and resource settings; it has been studied in field trials supported by the World Health Organization. Users record daily observations according to standardized rules, identifying the "<a href="#peak-day" class="gloss-xref">Peak Day</a>" (the last day of fertile-type mucus) and counting subsequent infertile days. Published effectiveness data from large multi-country trials report method-related pregnancy rates of approximately 1% per year when used correctly to avoid pregnancy.<sup class="cite-ref"><a href="#ref-85">85</a></sup> Billings is the foundational mucus-based method from which the Creighton Model was later standardized; it shares core mucus methodology with <a href="#creighton-model" class="gloss-xref">CrMS</a> while remaining a distinct method with its own teaching network.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_femm', 'femm', 'FEMM (Fertility Education and Medical Management)', 'II', 7, '<p><strong>An FABM program integrating hormonal science with cycle charting and providing a structured framework for medical management based on cycle data.</strong> FEMM incorporates hormone monitoring alongside mucus observations and is used both for family planning and for gynecological health management within <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a>.<sup class="cite-ref"><a href="#ref-1">1</a></sup></p>', NULL, '/femm/', 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_sympto-thermal-method', 'sympto-thermal-method', 'Sympto-Thermal Method (STM)', 'II', 8, '<p><strong>A cycle charting method combining multiple <a href="#biomarkers" class="gloss-xref">biomarkers</a></strong> (primarily cervical mucus changes and <a href="#bbt" class="gloss-xref">basal body temperature</a> (BBT) shifts) to identify the fertile window. BBT rises approximately 0.2 to 0.5 degrees C following ovulation due to progesterone secretion from the <a href="#corpus-luteum" class="gloss-xref">corpus luteum</a>. STM identifies the pre-ovulatory and post-ovulatory infertile phases using both markers.</p>', 'STM', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_marquette-method', 'marquette-method', 'Marquette Method', 'II', 9, '<p><strong>A FABM developed at Marquette University by Dr. Richard Fehring and colleagues that uses the ClearBlue Fertility Monitor to measure urinary estrogen and <a href="#lh" class="gloss-xref">LH</a> metabolites, producing objective low, high, and peak fertility readings.</strong> The monitor-based protocol can be used alone or combined with cervical mucus and <a href="#bbt" class="gloss-xref">basal body temperature</a> observations, depending on user preference. Quantifiable hormone data provides a second independent confirmation of fertility status, which is particularly valuable for women with irregular cycles, postpartum and breastfeeding women, and women in <a href="#perimenopause" class="gloss-xref">perimenopause</a>, where mucus patterns alone may be harder to interpret. Published effectiveness data from prospective cohort studies report perfect-use pregnancy rates of approximately 2% per year to avoid pregnancy. Marquette is also used clinically through the FACTS (Fertility Appreciation Collaborative to Teach the Science) training program; see <a href="#marquette-protocol" class="gloss-xref">Marquette Method Clinical Protocol</a> for the medical-management arm.<sup class="cite-ref"><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_bbt', 'bbt', 'Basal Body Temperature (BBT)', 'II', 10, '<p><strong>The body''s resting temperature, measured orally or vaginally first thing in the morning after at least three hours of uninterrupted sleep and before any activity, eating, or drinking.</strong> BBT rises 0.2 to 0.5 degrees C within one to three days after ovulation due to the thermogenic effect of progesterone released by the <a href="#corpus-luteum" class="gloss-xref">corpus luteum</a>; this sustained shift produces a characteristic biphasic pattern on a cycle chart. A thermal shift confirms that ovulation has occurred but cannot predict ovulation in advance. BBT is therefore useful for retrospective ovulation confirmation, <a href="#luteal-phase" class="gloss-xref">luteal phase</a> length measurement, and detection of a short luteal phase (&lt;10 days) or anovulation, but is not reliable as the sole marker for identifying the fertile window. Accuracy depends on consistent timing, adequate sleep, and the absence of confounders (illness, alcohol, disturbed sleep, shift work). BBT is a core component of sympto-thermal methods and a secondary confirmatory marker in several other <a href="#fabms" class="gloss-xref">FABMs</a>.</p>', 'BBT', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_mucus-pattern', 'mucus-pattern', 'Mucus Pattern', 'II', 11, '<p><strong>The characteristic sequence of cervical mucus changes that occurs across the menstrual cycle,</strong> observable through sensation and visual inspection. Estrogen stimulates cervical crypts to produce mucus that becomes progressively more fluid, stretchable, and lubricative as ovulation approaches. After ovulation, progesterone causes an abrupt shift to a dry or tacky pattern. The transition from fertile-type to post-ovulatory mucus identifies <a href="#peak-day" class="gloss-xref">Peak Day</a>.</p> <p>Mucus pattern is a primary biomarker in every mucus-based FABM. The <a href="#creighton-model" class="gloss-xref">Creighton Model FertilityCare System</a>, the <a href="#billings-ovulation-method" class="gloss-xref">Billings Ovulation Method</a>, and <a href="#femm" class="gloss-xref">FEMM</a> all use standardized descriptors for mucus type, sensation, and appearance. Charted over time, the pattern gives clinicians direct evidence of estrogen activity, ovulation timing, and cervical factor status.</p> <p>Disrupted mucus patterns are clinically significant. Sparse or absent fertile-type mucus despite confirmed ovulation points toward <a href="#cervical-factor-infertility" class="gloss-xref">cervical factor infertility</a>. Prolonged mucus patches outside the expected fertile window can reflect hormonal dysregulation, chronic cervicitis, or medication effects. In <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> practice, mucus pattern data from the chart is not discarded as subjective. It is treated as observable cervical endocrine output.</p> <p>Research by Billings and colleagues established the physiological basis for mucus charting as a fertility signal.<sup class="cite-ref"><a href="#ref-74">74</a></sup> For couples pursuing fertility restoration, mucus pattern interpretation is often the first diagnostic data point available, well before laboratory panels or imaging.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_peak-symptom', 'peak-symptom', 'Peak Symptom', 'II', 12, '<p><strong>The qualitative observation used to identify the last day of fertile-type cervical mucus, defined as the last day on which the discharge is clear and/or stretchy and/or lubricative, regardless of the amount of mucus present.</strong> The term distinguishes the observable quality from the chart marker: the Peak Symptom is what the woman observes; <a href="#peak-day" class="gloss-xref">Peak Day</a> is the label assigned to that day retrospectively. Hilgers established in his early work that mucus amount alone is an unreliable guide to identifying this transition. A day with heavy but cloudy, tacky mucus does not qualify. A day with minimal but clear or lubricative discharge does. This distinction matters clinically. Women and FertilityCare Practitioners learn to track quality descriptors, not volume, when locating the fertile window''s end. The <a href="#post-peak-phase" class="gloss-xref">post-Peak phase</a> cannot be counted correctly until the Peak Symptom is accurately identified.<sup class="cite-ref"><a href="#ref-78">78</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_pre-peak-phase', 'pre-peak-phase', 'Pre-Peak Phase', 'II', 13, '<p><strong>The phase of the menstrual cycle from the first day of menstruation through and including <a href="#peak-day" class="gloss-xref">Peak Day</a>, spanning the follicular and periovulatory period.</strong> The pre-Peak phase varies considerably across women and across cycles in the same woman. When ovulation is delayed by stress, illness, <a href="#pcos" class="gloss-xref">PCOS</a>, or perimenopausal hormonal changes, it is this phase that lengthens. The <a href="#post-peak-phase" class="gloss-xref">post-Peak phase</a>, by contrast, remains relatively stable. Hilgers documented this asymmetry directly, noting that cycle length variability is almost entirely a pre-Peak phenomenon.<sup class="cite-ref"><a href="#ref-79">79</a></sup> In clinical terms, a long or irregular cycle tells the <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> clinician to look at what is happening before ovulation, not after. Cross-referencing the pre-Peak length against mucus observations and cycle-timed hormone panels gives a precise picture of follicular development and ovulatory function. </p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_post-peak-phase', 'post-peak-phase', 'Post-Peak Phase', 'II', 14, '<p><strong>The phase of the menstrual cycle from the day after <a href="#peak-day" class="gloss-xref">Peak Day</a> through the last day before the next menstrual bleed, corresponding to the postovulatory or luteal period.</strong> Hilgers established that the post-Peak phase is the stable half of the cycle, typically lasting 11 to 16 days in healthy ovulatory cycles.<sup class="cite-ref"><a href="#ref-79">79</a></sup> This stability is what makes it clinically reliable. A post-Peak phase of 8 days or fewer meets the Hilgers criterion for Type I <a href="#luteal-phase-deficiency" class="gloss-xref">luteal phase deficiency</a>, indicating inadequate progesterone support for implantation and early pregnancy maintenance. Shortened post-Peak length is identified directly from the cycle chart, before any hormone panel is drawn. <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> clinicians use post-Peak length as a screening signal. It is one of the earliest detectable indicators of a correctable hormonal deficit. </p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_mucus-cycle', 'mucus-cycle', 'Mucus Cycle', 'II', 15, '<p><strong>The discrete window of fertile-type cervical mucus within a single menstrual cycle, beginning at the first observable change from the dry baseline (the <a href="#point-of-change" class="gloss-xref">Point of Change</a>) and ending on <a href="#peak-day" class="gloss-xref">Peak Day</a>.</strong> The mucus cycle is the fertile window in practical terms. It is distinct from the <a href="#mucus-pattern" class="gloss-xref">mucus pattern</a>, which refers to the full sequence of charted cervical observations across the entire cycle including pre-Peak dry days, the mucus cycle itself, and post-Peak dry days. Hilgers illustrated this architecture in early <a href="#creighton-model" class="gloss-xref">CrMS</a> training materials, charting the mucus cycle as its own bounded phase between menstruation and post-Peak dryness.<sup class="cite-ref"><a href="#ref-79">79</a></sup> The length and character of the mucus cycle varies. A shortened or atypical mucus cycle can point toward low estrogen output, <a href="#cervical-factor-infertility" class="gloss-xref">cervical factor infertility</a>, or the approach of anovulation. In <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> practice, tracking the mucus cycle across several months reveals patterns invisible in single-cycle data.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_dry-day', 'dry-day', 'Dry Day', 'II', 16, '<p><strong>A charted day on which no cervical mucus discharge is observed at the vulva, no bleeding is present, and no sensation of wetness or lubrication is noted.</strong> Dry days reflect two distinct physiological states depending on where they fall in the cycle. Pre-Peak dry days indicate the hormonally quiescent infertile state before follicular estrogen rises sufficiently to stimulate cervical crypt mucus production. Post-Peak dry days reflect progesterone-driven suppression of cervical mucus following ovulation.<sup class="cite-ref"><a href="#ref-79">79</a></sup> Accurate identification of dry days is foundational to <a href="#creighton-model" class="gloss-xref">CrMS</a> charting. Dry days, bleeding days, and mucus days together constitute the three primary observation categories in the system. When a woman reports continuous or recurring mucus where dry days would be expected, that pattern is diagnostically significant and warrants clinical evaluation rather than assumption.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_mucus-descriptors', 'mucus-descriptors', 'Mucus Quality Descriptors', 'II', 17, '<p><strong>The six standardized vocabulary terms used in the <a href="#creighton-model" class="gloss-xref">Creighton Model FertilityCare System</a> to describe the quality of observed cervical mucus: Sticky, Tacky, and Pasty indicate less-fertile mucus types; Clear, Stretchy, and Lubricative indicate fertile-type mucus.</strong> Each descriptor corresponds to a specific physical characteristic observed on folded white tissue during <a href="#vulvar-observation" class="gloss-xref">vulvar observation</a>. Stretch length in inches, color (cloudy or clear), and sensation (lubricative or not) are recorded alongside the primary descriptor. Combined, these data points produce a standardized entry in the <a href="#vdrs" class="gloss-xref">Vaginal Discharge Recording System</a>. The vocabulary is fixed by design. Standardized terms make observations interchangeable across practitioners and clinically interpretable at the chart level. A woman charting in one FertilityCare center uses the same vocabulary as a woman charting in another, so that both a Practitioner review and a <a href="#napro-medical" class="gloss-xref">NaPro medical</a> consult read the same language.<sup class="cite-ref"><a href="#ref-79">79</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_vulvar-observation', 'vulvar-observation', 'Vulvar Observation', 'II', 18, '<p><strong>The external observation of cervical discharge at the vulva, performed at each bathroom visit using folded white tissue to assess sensation, appearance, and elasticity of any discharge present.</strong> <a href="#creighton-model" class="gloss-xref">CrMS</a> standardizes the observation as entirely external. Internal or digital cervical checks are not part of the method, distinguishing it from some sympto-thermal applications that involve internal mucus sampling. What the woman observes at the vulva with tissue, in ambient lighting, at the moment of observation is the data point. Sensation during ambulation throughout the day is recorded alongside the tissue check.<sup class="cite-ref"><a href="#ref-79">79</a></sup> The external-only protocol has practical advantages: it is reproducible across a full day of activity, it requires no instruments, and it captures the same cervical output that Billings research established as a reliable fertility signal. All <a href="#vdrs" class="gloss-xref">VDRS</a> entries derive from these observations. </p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_vdrs', 'vdrs', 'Vaginal Discharge Recording System (VDRS)', 'II', 19, '<p><strong>The Vaginal Discharge Recording System (VDRS) is the standardized observation-and-coding framework used in the <a href="#creighton-model" class="gloss-xref">Creighton Model FertilityCare System</a> to record every charted day with a structured combination of mucus type, stretch length, color, and sensation.</strong> Hilgers introduced the VDRS as a proprietary component of CrMS to create a uniform charting language across practitioners and clinical settings.<sup class="cite-ref"><a href="#ref-79">79</a></sup> Each observation entry produces a coded descriptor that any trained <a href="#fcp" class="gloss-xref">FertilityCare Practitioner</a> or NaPro clinician can read and interpret consistently. This standardization transforms daily observations into clinically actionable data. A mucus entry is not just noted as present. It is coded with a type from the mucus quality descriptor vocabulary, a stretch measurement, a color category, and a sensation qualifier. That coded record feeds cycle-timed medical decisions, including progesterone protocol timing, surgical scheduling, and <a href="#infertility" class="gloss-xref">infertility</a> evaluation. </p>', 'VDRS', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_mucus-cycle-score', 'mucus-cycle-score', 'Mucus Cycle Score (MCS)', 'II', 20, '<p><strong>The Mucus Cycle Score (MCS) is a <a href="#creighton-model" class="gloss-xref">CrMS</a> quantitative classification that scores the six days ending on <a href="#peak-day" class="gloss-xref">Peak Day</a> to place a cycle on a five-tier fertility scale: regular, intermediate-regular, intermediate-limited, limited, or dry-cycle.</strong><sup class="cite-ref"><a href="#ref-78">78</a></sup></p><p>Developed by Hilgers as part of the CrMS charting system, the MCS replaces physician-dependent cervical mucus scoring (such as the Insler score) with a standardized method built entirely on external vulvar observations. Each of the six pre-Peak and Peak days receives a score based on mucus quality, and the average determines cycle classification. No speculum exam is required. The method is serially repeatable in any primary care setting.</p><p>Classification matters clinically. Limited and dry cycles correlate with <a href="#infertility" class="gloss-xref">infertility</a> and <a href="#rpl" class="gloss-xref">recurrent pregnancy loss</a>, signaling suboptimal follicular estrogen output. Regular cycles correlate with normal ovulatory hormonal production. The MCS gives CrMS charts diagnostic weight beyond fertility timing, supporting targeted <a href="#restorative-as-a-principle" class="gloss-xref">restorative</a> hormone evaluation. </p>', 'MCS', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_limited-mucus-cycle', 'limited-mucus-cycle', 'Limited Mucus Cycle', 'II', 21, '<p><strong>A limited mucus cycle is a <a href="#creighton-model" class="gloss-xref">CrMS</a> <a href="#mucus-cycle-score" class="gloss-xref">Mucus Cycle Score</a> classification in which observable cervical mucus is significantly reduced, reflecting suboptimal estrogen stimulation of the cervical crypts during the periovulatory phase.</strong><sup class="cite-ref"><a href="#ref-78">78</a></sup></p><p>The cervical crypts produce fertile-quality mucus in response to rising estradiol. When follicular development is inadequate, estrogen output falls short, and mucus production is diminished or absent across the pre-Peak window. A Mucus Cycle Score in the limited or intermediate-limited range records this pattern objectively across consecutive cycles.</p><p>Hilgers identified limited mucus cycles as statistically associated with both <a href="#infertility" class="gloss-xref">infertility</a> and <a href="#rpl" class="gloss-xref">recurrent pregnancy loss</a>. The finding is not a dead end. It points toward follicular phase support: the underlying hormonal deficit is identifiable, measurable, and treatable through <a href="#naprotechnology-definition" class="gloss-xref">NaProTechnology</a> protocols targeting follicular development and estrogen production. A limited <a href="#mucus-pattern" class="gloss-xref">mucus pattern</a> on a well-kept chart is clinical information. </p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_base-infertile-pattern', 'base-infertile-pattern', 'Base Infertile Pattern (BIP)', 'II', 22, '<p><strong>The Base Infertile Pattern (BIP) is the unchanging baseline of vulvar observations recorded by a woman experiencing continuous cervical discharge, used to identify which days are infertile by their sameness and which represent a departure toward fertility.</strong><sup class="cite-ref"><a href="#ref-79">79</a></sup></p><p>Many women cannot rely on the simple dry-day rule because they have an ongoing discharge: postpartum, while breastfeeding, in the post-pill transition, during <a href="#perimenopause" class="gloss-xref">perimenopause</a>, or during <a href="#anovulatory-cycles" class="gloss-xref">anovulatory cycles</a>. The BIP resolves this. Over several consecutive days of identical observations, the woman establishes her personal baseline. That pattern, once documented, defines <a href="#infertility" class="gloss-xref">infertility</a> for her. Any day matching the BIP is infertile. Any departure from the BIP marks the <a href="#point-of-change" class="gloss-xref">Point of Change</a> and signals the opening of the fertile window.</p><p>The BIP approach extends <a href="#creighton-model" class="gloss-xref">CrMS</a> charting to populations where standard charting rules do not apply, without requiring any internal exam or testing. Instruction by a certified <a href="#fcp" class="gloss-xref">FertilityCare Practitioner</a> is required before applying the BIP.</p>', 'BIP', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_point-of-change', 'point-of-change', 'Point of Change (POC)', 'II', 23, '<p><strong>The Point of Change (POC) is the day a <a href="#creighton-model" class="gloss-xref">CrMS</a> chart first departs from the established <a href="#base-infertile-pattern" class="gloss-xref">Base Infertile Pattern</a>, marking the start of fertile-phase mucus and the corresponding rise in estradiol.</strong><sup class="cite-ref"><a href="#ref-78">78</a></sup></p><p>For women charting with a Base Infertile Pattern, the POC is the functional equivalent of the first day of mucus observation in a standard cycle. Hilgers correlated the POC with rising estradiol-17&#946; and the beginning of the follicular phase. Any observation that differs from the established BIP, even subtly, qualifies as the POC and signals that the fertile window has opened.</p><p>The POC is practically important for postpartum women, those transitioning off suppressive medications, breastfeeding mothers, and perimenopausal women whose cycles do not follow a predictable pattern. Correctly identifying the POC requires a well-established BIP documented over prior consecutive days. Instruction through a certified <a href="#fcp" class="gloss-xref">FertilityCare Practitioner</a> is necessary for accurate application in these populations.</p>', 'POC', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_essential-sameness-pattern-yellow-stamps', 'essential-sameness-pattern-yellow-stamps', 'Essential Sameness Pattern and Yellow Stamps', 'II', 24, '<p><strong>The Essential Sameness Pattern (ESP) and Yellow Stamps are the <a href="#creighton-model" class="gloss-xref">CrMS</a> construct for charting <a href="#infertility" class="gloss-xref">infertility</a> windows when continuous discharge is present: the ESP defines pre-Peak infertile days through day-to-day identical observations, and Yellow Stamps are the chart symbol that records those days.</strong><sup class="cite-ref"><a href="#ref-78">78</a></sup></p><p>In women with chronic or continuous discharge, the standard green-stamp infertile day rule does not apply. The ESP addresses this. When a woman observes the same discharge pattern on consecutive days before Peak, those days carry the same fertility status as dry days in a standard cycle. The chart records them with a Yellow Stamp, indicating infertility despite the presence of discharge.</p><p>Post-Peak Yellow Stamps apply from Peak+4 onward in qualifying continuous-discharge cycles. Pre-Peak Yellow Stamps require the ESP criteria to be met. Both require formal instruction by a certified <a href="#fcp" class="gloss-xref">FertilityCare Practitioner</a>. The ESP and Yellow Stamp system is what makes CrMS usable for women whose charts would otherwise appear uniformly fertile. </p>', 'ESP', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_tail-end-brown-bleeding', 'tail-end-brown-bleeding', 'Tail-End Brown Bleeding (TEB)', 'II', 25, '<p><strong>Tail-end brown bleeding (TEB) is a <a href="#creighton-model" class="gloss-xref">CrMS</a>-defined biomarker consisting of two or more days of brown or black bleeding at the end of menstrual flow, after the heaviest days of menses have passed.</strong><sup class="cite-ref"><a href="#ref-78">78</a></sup><sup class="cite-ref"><a href="#ref-79">79</a></sup></p><p>TEB is not a normal variation in menstrual color. Brown blood at the tail end of flow indicates old, incompletely shed endometrial tissue, and Hilgers identifies it as a marker of underlying cycle pathology. Contributing causes include <a href="#luteal-phase-deficiency" class="gloss-xref">luteal phase deficiency</a>, insufficient prior <a href="#corpus-luteum" class="gloss-xref">corpus luteum</a> output, or <a href="#chronic-endometritis" class="gloss-xref">chronic endometritis</a>. Each represents a diagnosable, treatable condition.</p><p>Women frequently normalize TEB because they have experienced it for years and no clinician has flagged it. That is a missed diagnostic opportunity. A well-kept CrMS chart captures TEB precisely, giving the clinician a documented pattern rather than a single reported symptom. <a href="#restorative-as-a-principle" class="gloss-xref">Restorative</a> protocols targeting the underlying hormonal deficit typically resolve TEB once the root cause is identified and treated. </p>', 'TEB', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_premenstrual-bleeding', 'premenstrual-bleeding', 'Premenstrual Bleeding (PMB)', 'II', 26, '<p><strong>Premenstrual bleeding (PMB) is a <a href="#creighton-model" class="gloss-xref">CrMS</a>-defined biomarker consisting of three or more days of light, very light, or brown bleeding immediately before the first moderate-flow day of menses.</strong><sup class="cite-ref"><a href="#ref-78">78</a></sup></p><p>A healthy menstrual flow builds gradually and then tapers: the crescendo-decrescendo pattern reflects a <a href="#corpus-luteum" class="gloss-xref">corpus luteum</a> that maintained progesterone support until its natural regression triggered clean endometrial shedding. PMB breaks that pattern. Three or more days of pre-period spotting signal that the corpus luteum failed to sustain adequate progesterone, and the endometrium began breaking down prematurely.</p><p>This matters beyond cycle tracking. Premature corpus luteum regression is associated with <a href="#infertility" class="gloss-xref">infertility</a> and <a href="#early-pregnancy-loss" class="gloss-xref">early pregnancy loss</a>. The PMB pattern on a CrMS chart makes this deficiency visible and repeatable across cycles. Cycle-timed progesterone support, initiated after diagnostic hormone evaluation, addresses the underlying deficit directly. PMB is not a cosmetic charting detail. It is a signal of <a href="#luteal-phase" class="gloss-xref">luteal phase</a> insufficiency that warrants investigation. </p>', 'PMB', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_fertility-focused-intercourse', 'fertility-focused-intercourse', 'Fertility-Focused Intercourse (FFI)', 'II', 27, '<p><strong>Fertility-focused intercourse (FFI) is Hilgers'' term for intercourse timed by <a href="#creighton-model" class="gloss-xref">CrMS</a> biomarker observations to coincide with the identified fertile window, particularly <a href="#peak-day" class="gloss-xref">Peak Day</a> and the three preceding days.</strong><sup class="cite-ref"><a href="#ref-83">83</a></sup></p><p>In the landmark 1992 Hilgers, Daly, Prebil, and Hilgers cohort of 50 apparently-fertile couples, FFI produced cumulative pregnancy rates of 76% in cycle 1, 90% by cycle 3, and 98% by cycle 6.<sup class="cite-ref"><a href="#ref-83">83</a></sup> These are the most-cited CrMS achievement statistics, and they derive from a single clinical principle: when the fertile window is identified accurately, conception follows for nearly all couples without further intervention.</p><p>FFI reframes the clinical question. The standard approach asks whether a couple''s biology can support pregnancy. FFI asks whether the fertile window was actually used. For couples labeled with undiagnosed <a href="#infertility" class="gloss-xref">infertility</a>, accurate fertile-window identification through CrMS charting is frequently the missing variable. </p>', 'FFI', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_naprotechnology-definition', 'naprotechnology-definition', 'NaProTECHNOLOGY (Natural Procreative Technology)', 'III', 0, '<p><strong>A specific women''s health science focused on reproductive and gynecologic health, developed by Dr. Thomas Hilgers at the Pope Paul VI Institute.</strong> It utilizes the <a href="#creighton-model" class="gloss-xref">Creighton Model FertilityCare System</a> for precise cycle monitoring to guide targeted medical (<a href="#napro-medical" class="gloss-xref">NaPro Medical</a>) and surgical (NaPro Surgery/Advanced Reproductive Surgery) treatments based on identified cycle abnormalities. NaProTECHNOLOGY works cooperatively with the reproductive system and does not employ methods that are inherently suppressive, circumventive, or destructive. In Hilgers (2004), a cohort of 1,045 infertile patients reported cumulative live-birth rates exceeding 60% by 24 months and approximately 70% by 36 months.<sup class="cite-ref"><a href="#ref-10">10</a></sup> More recently, Sanchez-Mendez et al. (2025) followed 1,310 couples and reported cumulative live-birth rates of 50% at 24 months and 62.1% at 36 months or longer.<sup class="cite-ref"><a href="#ref-11">11</a></sup><sup class="cite-ref"><a href="#ref-12">12</a></sup> Both figures are comparable to or higher than cumulative live-birth rates achieved after one or more <a href="#ivf" class="gloss-xref">IVF</a> cycles</p>', NULL, '/naprotechnology/', 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_napro-medical', 'napro-medical', 'NaPro Medical', 'III', 1, '<p><strong>The medical management component of <a href="#naprotechnology-definition" class="gloss-xref">NaProTECHNOLOGY</a>, using timed medications and supplements based on Creighton Model charting data.</strong> Treatments are cycle-phase-specific (e.g., luteal progesterone support is timed to the <a href="#post-peak-phase" class="gloss-xref">post-peak phase</a>; ovulation induction agents are timed to the follicular phase). Common interventions include targeted hormone therapy (progesterone, estrogen, HCG), ovulation induction (clomiphene, letrozole), thyroid management, and treatment of conditions like <a href="#hyperprolactinemia" class="gloss-xref">hyperprolactinemia</a> or insulin resistance.<sup class="cite-ref"><a href="#ref-11">11</a></sup><sup class="cite-ref"><a href="#ref-12">12</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_napro-surgery', 'napro-surgery', 'NaPro Surgery / Advanced Reproductive Surgery', 'III', 2, '<p><strong>The specialized surgical component of <a href="#naprotechnology-definition" class="gloss-xref">NaProTECHNOLOGY</a>, employing meticulous, often minimally invasive techniques to restore anatomy and function or remove problematic conditions.</strong> Hallmarks include excision (rather than ablation/fulguration) of <a href="#endometriosis" class="gloss-xref">endometriosis</a>, meticulous <a href="#adhesiolysis" class="gloss-xref">adhesiolysis</a> with anti-adhesion barrier protocols, microsurgical tubal repair and reversal, multi-layer isthmocele reconstruction, and fertility-preserving ovarian surgery. Published results have documented adhesion scores dropping dramatically with the introduction of extensive Gore-Tex barrier use in NaPro surgeries, from a mean score of 33.3 to 6.0 over a decade.<sup class="cite-ref"><a href="#ref-10">10</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_fertilitas-study', 'fertilitas-study', 'Fertilitas Study', 'III', 3, '<p><strong>One of the largest single-center <a href="#naprotechnology-definition" class="gloss-xref">NaProTECHNOLOGY</a> cohort studies to date,</strong> demonstrating a take-home baby (THB) rate of 35.3% overall, rising to 62.1% among patients who remained with the program for the full duration of treatment. The study confirmed NaPro as associated with a notably high THB rate even in patients with unfavorable prognostic factors such as advanced maternal age, prolonged <a href="#infertility" class="gloss-xref">infertility</a> duration, and prior failed <a href="#art" class="gloss-xref">ART</a> attempts. Conditions associated with higher THB rates included <a href="#rpl" class="gloss-xref">recurrent pregnancy loss</a>, hormonal/functional disorders, <a href="#endometriosis" class="gloss-xref">endometriosis</a>, and <a href="#male-factor-infertility" class="gloss-xref">male factor infertility</a>.<sup class="cite-ref"><a href="#ref-13">13</a></sup><sup class="cite-ref"><a href="#ref-14">14</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_femm-medical-management', 'femm-medical-management', 'FEMM Medical Management', 'III', 4, '<p><strong>The clinical treatment arm of the FEMM (<a href="#femm" class="gloss-xref">Fertility Education and Medical Management</a>) program,</strong> in which trained medical providers use cycle charting data (cervical mucus observations and urinary <a href="#lh" class="gloss-xref">LH</a> testing) alongside cycle-timed lab work to diagnose and treat reproductive and hormonal disorders. FEMM Medical Providers follow protocols developed by the <a href="#rhri" class="gloss-xref">Reproductive Health Research Institute</a> (RHRI) under Dr. Pilar Vigil. Treatment categories include <a href="#pcos" class="gloss-xref">PCOS</a>, thyroid dysfunction, <a href="#luteal-phase-deficiency" class="gloss-xref">luteal phase deficiency</a>, <a href="#rpl" class="gloss-xref">recurrent pregnancy loss</a>, anovulation, and menopausal disorders. FEMM is distinct from <a href="#naprotechnology-definition" class="gloss-xref">NaProTechnology</a> in its charting method (sympto-hormonal rather than Creighton-only), institutional affiliation (RHRI rather than Saint Paul VI Institute), and protocol framework.<sup class="cite-ref"><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_femm-levels', 'femm-levels', 'FEMM Education Levels (Teen, Adult, Medical)', 'III', 5, '<p><strong><a href="#femm" class="gloss-xref">FEMM</a> offers three tiered pathways matched to life stage and clinical need.</strong> Teen FEMM introduces adolescent girls to the hormonal and ovulatory basis of the menstrual cycle as a vital sign of overall health, without contraceptive framing. Adult FEMM teaches cycle charting (sympto-hormonal approach with mucus observation and optional urinary <a href="#lh" class="gloss-xref">LH</a> testing) for use in family planning and health awareness. <a href="#femm-medical-management" class="gloss-xref">FEMM Medical Management</a> is the clinical arm in which trained FEMM Medical Providers use charting data alongside cycle-timed lab work to diagnose and treat hormonal and reproductive disorders (see FEMM Medical Management). The three tiers allow FEMM content to meet users at different stages of the reproductive life course with appropriate depth and clinical integration.<sup class="cite-ref"><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_rhri', 'rhri', 'Reproductive Health Research Institute (RHRI)', 'III', 6, '<p><strong>The research and training organization behind <a href="#femm" class="gloss-xref">FEMM</a>''s medical management protocols,</strong> founded by Dr. Pilar Vigil, a specialist in obstetrics, gynecology, and <a href="#reproductive-endocrinology" class="gloss-xref">reproductive endocrinology</a>. RHRI has championed clinical attention to chronic anovulation as a marker for long-term health risks including cardiovascular disease and Type 2 diabetes, and has developed clinical protocols for <a href="#pcos" class="gloss-xref">PCOS</a> phenotyping, thyroid-related cycle disruption, and immune evaluation for <a href="#rpl" class="gloss-xref">recurrent pregnancy loss</a>.<sup class="cite-ref"><a href="#ref-1">1</a></sup></p>', 'RHRI', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_sympto-hormonal-method', 'sympto-hormonal-method', 'Sympto-Hormonal Method', 'III', 7, '<p><strong>A fertility awareness-based method that combines cervical mucus observation with urinary hormone testing (typically <a href="#lh" class="gloss-xref">LH</a> strips) to track ovulation.</strong> <a href="#femm" class="gloss-xref">FEMM</a> uses a sympto-hormonal approach, distinguishing it from mucus-only methods (Creighton, Billings) and sympto-thermal methods (which add <a href="#bbt" class="gloss-xref">basal body temperature</a>). The addition of objective hormone data provides a second independent confirmation of ovulatory events.<sup class="cite-ref"><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_neofertility', 'neofertility', 'NeoFertility', 'III', 8, '<p><strong>A clinical system developed by Dr. Phil Boyle that builds on <a href="#naprotechnology-definition" class="gloss-xref">NaProTechnology</a> training with expanded diagnostic protocols, particularly in <a href="#reproductive-immunology" class="gloss-xref">reproductive immunology</a> and androgen evaluation.</strong> NeoFertility treats <a href="#infertility" class="gloss-xref">infertility</a>, recurrent miscarriage, and at-risk pregnancy using a structured three-phase process: comprehensive diagnosis (Phase 1), treatment and cycle optimization (Phase 2), and conception timing with confirmed follicle rupture (Phase 3). NeoFertility is method-agnostic: it accepts charting data from any FABM, not only the Creighton Model.<sup class="cite-ref"><a href="#ref-1">1</a></sup></p>', NULL, '/neofertility/', 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_chartneo', 'chartneo', 'ChartNeo', 'III', 9, '<p><strong><a href="#neofertility" class="gloss-xref">NeoFertility</a>''s digital charting platform that integrates patient charting data with the clinical workflow.</strong> ChartNeo connects patients, fertility advisors, and clinicians through shared data, enabling remote monitoring and telehealth delivery. Unlike standalone charting apps, ChartNeo is designed as a clinical tool that feeds directly into diagnostic and treatment decisions.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_ldn', 'ldn', 'Low-Dose Naltrexone (LDN)', 'III', 10, '<p><strong>An immune-modifying agent used at 4.5 mg nightly in the <a href="#neofertility" class="gloss-xref">NeoFertility</a> protocol for patients with reduced egg reserve, suspected immune-mediated implantation failure, and <a href="#clinical-endorphin-deficiency" class="gloss-xref">clinical endorphin deficiency</a>.</strong> Originally developed as an opioid antagonist at higher doses, LDN at low doses modulates immune function by temporarily blocking opioid receptors, triggering a compensatory increase in endorphin production. Published data from NeoFertility shows LDN use associated with significant enhancements in <a href="#endometrial-thickness" class="gloss-xref">endometrial thickness</a>, ovarian responsiveness, progesterone levels, and clinical pregnancy rates.</p>', 'LDN', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_dhea-supplementation', 'dhea-supplementation', 'DHEA (Dehydroepiandrosterone) in RRM', 'III', 11, '<p><strong>An androgen precursor used in <a href="#neofertility" class="gloss-xref">NeoFertility</a> protocols to address hypoandrogenemia, abnormally low androgen levels identified as a contributor to <a href="#rpl" class="gloss-xref">recurrent pregnancy loss</a> and <a href="#dor" class="gloss-xref">diminished ovarian reserve</a>.</strong> DHEA evaluation is part of NeoFertility''s expanded diagnostic panel. When indicated, supplementation aims to restore androgen levels that support follicular development and early pregnancy maintenance.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_immune-modifying-framework', 'immune-modifying-framework', 'Immune-Modifying Framework', 'III', 12, '<p><strong><a href="#neofertility" class="gloss-xref">NeoFertility</a>''s systematic approach to evaluating and treating immunological factors in <a href="#infertility" class="gloss-xref">infertility</a> and recurrent miscarriage.</strong> The framework includes <a href="#nk-cells" class="gloss-xref">NK</a> cell panels (natural killer cell activity), food antibody testing, chromosomal abnormality screening, blood clotting markers, and <a href="#chronic-endometritis" class="gloss-xref">chronic endometritis</a> investigation. Treatment may include <a href="#ldn" class="gloss-xref">LDN</a>, intralipid infusions, corticosteroids, and anticoagulation therapy. This represents one of NeoFertility''s most significant expansions beyond standard <a href="#naprotechnology-definition" class="gloss-xref">NaProTechnology</a> protocols.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_marquette-protocol', 'marquette-protocol', 'Marquette Method Clinical Protocol', 'III', 13, '<p><strong>A fertility awareness-based method that uses the ClearBlue Fertility Monitor to measure urinary estrogen and <a href="#lh" class="gloss-xref">LH</a> levels, providing objective hormone data alongside optional cervical mucus and temperature observations.</strong> Developed at Marquette University, the method has been integrated into clinical <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> practice through the FACTS training program. The monitor-based approach appeals to clinicians who want quantifiable hormone data as part of the diagnostic workup. Marquette-trained Medical Consultants use the charting data for <a href="#cycle-timed-diagnostics" class="gloss-xref">cycle-timed diagnostics</a> in a framework similar to <a href="#naprotechnology-definition" class="gloss-xref">NaProTechnology</a> and <a href="#femm" class="gloss-xref">FEMM</a>.<sup class="cite-ref"><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_hcg-trigger', 'hcg-trigger', 'HCG Trigger (Human Chorionic Gonadotropin Trigger)', 'III', 14, '<p><strong>A single injection of <a href="#hcg" class="gloss-xref">human chorionic gonadotropin</a> (hCG) given during an ovulation induction or monitored cycle to mimic the natural <a href="#lh" class="gloss-xref">LH</a> surge, triggering final follicular maturation and ovulation.</strong> In <a href="#napro-medical" class="gloss-xref">NaPro Medical</a> and related <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> protocols, hCG triggering is used selectively when cycle-timed monitoring identifies a mature follicle with a delayed or absent endogenous LH surge, or to improve the precision of ovulation timing in combination with ovulation induction agents such as clomiphene or letrozole. Post-ovulatory hCG "boosters" also support <a href="#corpus-luteum" class="gloss-xref">corpus luteum</a> function and early luteal progesterone production. Unlike <a href="#ivf" class="gloss-xref">IVF</a> protocols, which use hCG triggering to time oocyte retrieval, RRM protocols use it to support natural intercourse-timed conception within the body.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_cprt', 'cprt', 'Cooperative Progesterone Replacement Therapy (CPRT)', 'III', 15, '<p><strong>Cooperative Progesterone Replacement Therapy (CPRT) is a cycle-timed luteal-phase progesterone protocol developed by Dr. Thomas Hilgers as part of <a href="#naprotechnology-definition" class="gloss-xref">NaProTECHNOLOGY</a>, designed to support the <a href="#corpus-luteum" class="gloss-xref">corpus luteum</a>''s natural output without suppressing ovulation in subsequent cycles.</strong> The standard protocol uses oral micronized progesterone (sustained-release, 200 mg at bedtime) beginning on Peak +3 and ending on Peak +12, or at the onset of menses. Timing is determined by the woman''s <a href="#peak-day" class="gloss-xref">Peak Day</a> as identified through <a href="#creighton-model" class="gloss-xref">CrMS</a> charting.<sup class="cite-ref"><a href="#ref-78">78</a></sup></p><p>CPRT is Hilgers'' formal clinical alternative to continuous progestin regimens. It targets the specific window when progesterone is needed, then steps back. The corpus luteum is supported, not replaced. This distinction matters: continuous progestins suppress the next cycle''s ovulatory sequence. CPRT does not.</p><p>Clinical indications include Type I, II, and III <a href="#luteal-phase-deficiency" class="gloss-xref">luteal phase deficiency</a>, <a href="#pms" class="gloss-xref">premenstrual syndrome</a> with documented luteal hormone deficit, and recurrent <a href="#early-pregnancy-loss" class="gloss-xref">early pregnancy loss</a> with luteal insufficiency. Dosing is titrated against serial post-Peak progesterone levels drawn at Peak +5, +7, and +9. CPRT always uses isomolecular progesterone, not synthetic progestins.</p>', 'CPRT', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_cert', 'cert', 'Cooperative Estrogen Replacement Therapy (CERT)', 'III', 16, '<p><strong>Cooperative Estrogen Replacement Therapy (CERT) is a cycle-timed estradiol supplementation protocol used in <a href="#naprotechnology-definition" class="gloss-xref">NaProTECHNOLOGY</a> to correct deficient estrogen output in specific subtypes of <a href="#luteal-phase-deficiency" class="gloss-xref">luteal phase deficiency</a> and impaired follicular development.</strong><sup class="cite-ref"><a href="#ref-78">78</a></sup></p><p>CERT is the sister protocol to <a href="#cprt" class="gloss-xref">Cooperative Progesterone Replacement Therapy</a> (CPRT). It addresses Type V LPD, defined by isolated luteal estradiol deficit, and Type B or C follicular phase function grades where estradiol production is suboptimal across the pre-ovulatory phase. Like CPRT, it is not continuous. Dosing tracks the cycle; it does not override it.</p><p>CERT exclusively uses isomolecular 17&#946;-estradiol. Ethinyl estradiol, the synthetic estrin found in oral contraceptives, is a heteromolecular artimone and is not used in NaPro hormone protocols. Cycle-timed estradiol targeted to a confirmed ovulatory window and a documented deficiency is the clinical standard in NaPro practice.</p>', 'CERT', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_isomolecular-hormones', 'isomolecular-hormones', 'Isomolecular Hormones (IMH)', 'III', 17, '<p><strong>Isomolecular hormones are compounds whose molecular structure is identical to hormones produced endogenously by the human body, including progesterone, 17&#946;-estradiol, and testosterone.</strong> Dr. Thomas Hilgers coined and preferred the term "isomolecular" over the more commonly used "bioidentical," because it specifies the actual criterion: molecular identity, not a vague natural-versus-synthetic distinction.<sup class="cite-ref"><a href="#ref-78">78</a></sup></p><p>In <a href="#naprotechnology-definition" class="gloss-xref">NaProTECHNOLOGY</a> practice, isomolecular hormones are the pharmacological standard for all hormone replacement and supplementation protocols. This includes oral micronized progesterone (sustained-release) for <a href="#cprt" class="gloss-xref">CPRT</a>, 17&#946;-estradiol for <a href="#cert" class="gloss-xref">CERT</a>, postpartum progesterone protocols for mood support, and pregnancy-maintenance progesterone in the prematurity prevention program. The pregnancy safety profile of isomolecular progesterone is supported by published outcomes data.<sup class="cite-ref"><a href="#ref-82">82</a></sup></p><p>Hilgers distinguishes isomolecular hormones from <a href="#heteromolecular-artimones" class="gloss-xref">heteromolecular artimones</a>, the synthetic progestins and estrins found in oral contraceptives and most conventional <a href="#hrt" class="gloss-xref">hormone replacement therapy</a>. The molecular difference is not cosmetic. It affects receptor binding, downstream signaling, and clinical side-effect profiles. NaPro protocols do not substitute one for the other.</p>', 'IMH', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_heteromolecular-artimones', 'heteromolecular-artimones', 'Heteromolecular Artimones (HMA)', 'III', 18, '<p><strong>Heteromolecular artimones are synthetic compounds whose molecular structure has been altered from endogenous human hormones, coined by Dr. Thomas Hilgers as the antonym to <a href="#isomolecular-hormones" class="gloss-xref">isomolecular hormones</a>.</strong> The term "artimone" signals "altered hormone." Examples include norethindrone, levonorgestrel, medroxyprogesterone acetate, and ethinyl estradiol, the active agents in most oral contraceptives and conventional hormone replacement formulations.<sup class="cite-ref"><a href="#ref-78">78</a></sup></p><p>Hilgers argues that the molecular variance of heteromolecular artimones from endogenous hormones explains side-effect profiles that differ qualitatively, not just quantitatively, from isomolecular replacements. Synthetic progestins, for example, bind progesterone receptors but also bind androgen and glucocorticoid receptors. The downstream effects are not the same as endogenous progesterone.</p><p>In <a href="#naprotechnology-definition" class="gloss-xref">NaProTECHNOLOGY</a>, heteromolecular artimones are never used in hormone replacement or supplementation protocols. <a href="#cprt" class="gloss-xref">CPRT</a>, <a href="#cert" class="gloss-xref">CERT</a>, and pregnancy support protocols specify isomolecular compounds exclusively. The clinical distinction between these two pharmacological categories is foundational to Hilgers'' approach to <a href="#restorative-as-a-principle" class="gloss-xref">restorative</a> hormone therapy. When oral contraceptives are discussed in the NaPro framework, Hilgers refers to their active compounds by this category name.</p>', 'HMA', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_compounding-pharmacist-triad', 'compounding-pharmacist-triad', 'Compounding Pharmacist Triad', 'III', 19, '<p><strong>The Compounding Pharmacist Triad is the three-way clinical relationship in <a href="#naprotechnology-definition" class="gloss-xref">NaProTECHNOLOGY</a> practice connecting the patient, the FertilityCare Medical Consultant (<a href="#nfpmc" class="gloss-xref">NFPMC</a>) or <a href="#restorative-reproductive-medicine" class="gloss-xref">restorative reproductive medicine</a> clinician, and a licensed compounding pharmacist.</strong> Dr. Thomas Hilgers formalized this triad as a structural element of <a href="#napro-medical" class="gloss-xref">NaPro medical</a> care, not an optional add-on.<sup class="cite-ref"><a href="#ref-78">78</a></sup></p><p>The triad is necessary because most isomolecular hormone preparations used in NaPro protocols are not commercially available at the doses or delivery routes the protocols require. Oral micronized progesterone sustained-release capsules, transdermal estradiol creams calibrated to specific post-Peak assay targets, and micronized testosterone preparations typically require compounding. A pharmacist who understands the clinical rationale, the timing logic, and the assay-driven dose titration process is not interchangeable with a retail dispensing pharmacist.</p><p>Hilgers'' model treats the compounding pharmacist as a clinical collaborator. The pharmacist receives the hormone assay data through the clinician, compounds to the protocol specification, and participates in dose adjustments. Patients are counseled on how to work with all three members of the triad. The relationship is integrated, not transactional.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_prematurity-prevention-program', 'prematurity-prevention-program', 'NaProTECHNOLOGY Prematurity Prevention Program', 'III', 21, '<p><strong>The NaProTECHNOLOGY Prematurity Prevention Program uses cycle-timed isomolecular progesterone supplementation throughout pregnancy, combined with serial cervical and biomarker monitoring, to reduce preterm birth.</strong> Hilgers reports cohort prematurity rates of approximately 7%, compared with a 12.0% rate in the comparison group.<sup class="cite-ref"><a href="#ref-79">79</a></sup></p><p>The <a href="#restorative-as-a-principle" class="gloss-xref">restorative</a> principle: support <a href="#corpus-luteum" class="gloss-xref">corpus luteum</a> and placental hormone output through gestation rather than waiting for preterm labor to present. Progesterone plays a direct role in maintaining uterine quiescence. Women with documented progesterone insufficiency, prior preterm birth, or cervical insufficiency are candidates for the program. Isomolecular progesterone, not synthetic progestins, is the pharmacological standard throughout.<sup class="cite-ref"><a href="#ref-82">82</a></sup></p><p>The program integrates the woman''s prior <a href="#creighton-model" class="gloss-xref">CrMS</a> chart data and pre-pregnancy hormone assay history to individualize her supplementation protocol. A woman who entered pregnancy with a documented <a href="#luteal-phase-deficiency" class="gloss-xref">luteal phase deficiency</a> requires different support than one with normal pre-pregnancy progesterone profiles. The chart is not discarded at conception. It informs the entire gestational protocol.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_achieving-related-pregnancy-rate', 'achieving-related-pregnancy-rate', 'Achieving-Related Pregnancy Rate (ARPR)', 'III', 22, '<p><strong>The Achieving-Related Pregnancy Rate (ARPR) is a <a href="#creighton-model" class="gloss-xref">CrMS</a> use-effectiveness statistic that measures pregnancy outcomes in couples who intentionally shift from avoiding to achieving conception, calculated using Hilgers'' life-table adaptation of the Tietze-Lewit framework.</strong> The foundational dataset includes a five-study composite of 1,876 couples across 17,130.5 couple-months.<sup class="cite-ref"><a href="#ref-78">78</a></sup><sup class="cite-ref"><a href="#ref-83">83</a></sup></p><p>The ARPR is methodologically distinct from generic cumulative pregnancy rates. Most fertility effectiveness statistics count all exposure cycles, regardless of whether the couple was timing intercourse to achieve or avoid. The ARPR isolates <a href="#fertility-focused-intercourse" class="gloss-xref">fertility-focused intercourse</a> cycles identified via <a href="#peak-day" class="gloss-xref">Peak Day</a> timing on the Creighton Model chart. It then calculates conception probability within 12 ordinal months. The denominator is controlled for intent and method use.</p><p>This distinction matters clinically. A couple using fertility-focused intercourse timed to the fertile window is not statistically comparable to a couple having intercourse without cycle awareness. The ARPR accounts for this. It is the foundational effectiveness measure underlying CrMS achieving outcomes data and is cited in Hilgers'' treatment outcome analyses for conditions including <a href="#luteal-phase-deficiency" class="gloss-xref">luteal phase deficiency</a> and <a href="#endometriosis" class="gloss-xref">endometriosis</a>-related subfertility.</p>', 'ARPR', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_follicle-maturation-study', 'follicle-maturation-study', 'Follicle Maturation Study (Follicle Tracking / Follicular Ultrasound Series)', 'IV', 0, '<p><strong>A series of transvaginal ultrasounds performed across the follicular phase of the menstrual cycle</strong> to monitor <a href="#follicle-development" class="gloss-xref">follicle development</a>, dominant follicle selection, and ovulation. Findings inform diagnosis of luteinized unruptured follicle (<a href="#luf-syndrome" class="gloss-xref">LUF</a>) syndrome, ovulatory dysfunction, and are used to time hormonal interventions precisely.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_sis', 'sis', 'Saline Infusion Sonohysterogram (SIS) / "Bubble Test"', 'IV', 1, '<p><strong>A transvaginal ultrasound performed while infusing sterile saline into the uterine cavity,</strong> providing enhanced visualization of the endometrial cavity and uterine walls. SIS is the primary diagnostic tool for <a href="#isthmocele" class="gloss-xref">uterine isthmocele</a>, enabling measurement of the defect dimensions and residual myometrial thickness. It also detects endometrial polyps, submucosal fibroids, <a href="#ashermans-syndrome" class="gloss-xref">intrauterine adhesions</a>, and uterine septa, and can assess tubal patency.<sup class="cite-ref"><a href="#ref-15">15</a></sup><sup class="cite-ref"><a href="#ref-16">16</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_hsg', 'hsg', 'Hysterosalpingogram (HSG)', 'IV', 2, '<p><strong>A radiographic procedure in which contrast dye is introduced through the cervix into the uterine cavity and fallopian tubes under fluoroscopic guidance.</strong> HSG assesses uterine cavity morphology and tubal patency. It is often the first-line imaging tool for evaluating <a href="#tubal-factor-infertility" class="gloss-xref">tubal factor infertility</a>.<sup class="cite-ref"><a href="#ref-17">17</a></sup></p>', 'HSG', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_selective-salpingography', 'selective-salpingography', 'Selective Salpingography', 'IV', 3, '<p><strong>A specialized variant of <a href="#hsg" class="gloss-xref">HSG</a> in which contrast dye is injected selectively into each fallopian tube individually via a catheter.</strong> This allows targeted assessment and, in some cases, simultaneous therapeutic recanalization of proximal tubal blockages.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_hysteroscopy-diagnostic', 'hysteroscopy-diagnostic', 'Hysteroscopy (Diagnostic)', 'IV', 4, '<p><strong>Direct visualization of the uterine cavity and cervical canal using a hysteroscope (a thin, illuminated camera).</strong> Considered the gold standard for evaluation and management of intrauterine pathology. Diagnostic <a href="#hysteroscopy-operative" class="gloss-xref">hysteroscopy</a> is indicated for evaluation of abnormal uterine bleeding, recurrent miscarriage, repeated implantation failure, and suspected structural abnormalities. In premenopausal women with regular cycles, optimal timing is during the early follicular phase after menstruation.<sup class="cite-ref"><a href="#ref-18">18</a></sup><sup class="cite-ref"><a href="#ref-17">17</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_hysteroscopy-operative', 'hysteroscopy-operative', 'Hysteroscopy (Operative)', 'IV', 5, '<p><strong>A therapeutic extension of diagnostic hysteroscopy, used to treat intrauterine pathology identified during visualization.</strong> ACOG-recognized indications include removal of endometrial polyps, submucosal leiomyomas (fibroids), uterine septa, <a href="#ashermans-syndrome" class="gloss-xref">intrauterine adhesions</a> (synechiae), retained products, malpositioned IUDs, tubal cannulation, and treatment of isthmoceles. Ambulatory (office-based) hysteroscopy offers comparable outcomes to operating room procedures with reduced cost and avoidance of general anesthesia.<sup class="cite-ref"><a href="#ref-17">17</a></sup><sup class="cite-ref"><a href="#ref-18">18</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_laparoscopy-diagnostic', 'laparoscopy-diagnostic', 'Laparoscopy (Diagnostic)', 'IV', 6, '<p><strong>Minimally invasive visualization of the pelvic and abdominal organs through small incisions using a laparoscope.</strong> In <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a>, diagnostic <a href="#laparoscopy-operative" class="gloss-xref">laparoscopy</a> is often the definitive method for diagnosing <a href="#endometriosis" class="gloss-xref">endometriosis</a> and <a href="#pelvic-adhesions" class="gloss-xref">pelvic adhesions</a>, conditions frequently missed on imaging alone. The <a href="#s-map" class="gloss-xref">Systematic Mapping of the Abdomen and Pelvis</a> (S-MAP) protocol is employed during NaPro diagnostic laparoscopy for comprehensive abdominal and pelvic assessment.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_laparoscopy-operative', 'laparoscopy-operative', 'Laparoscopy (Operative)', 'IV', 7, '<p><strong>Minimally invasive surgical treatment performed laparoscopically</strong> for conditions including <a href="#endometriosis" class="gloss-xref">endometriosis</a> (via excision), <a href="#pelvic-adhesions" class="gloss-xref">pelvic adhesions</a> (<a href="#adhesiolysis" class="gloss-xref">adhesiolysis</a>), <a href="#uterine-fibroids" class="gloss-xref">uterine fibroids</a> (<a href="#myomectomy" class="gloss-xref">myomectomy</a>), ovarian cysts (cystectomy), fallopian tube disease (repair, reversal, neosalpingostomy), isthmocele (laparoscopic excision and multi-layer reconstruction), and <a href="#pcos" class="gloss-xref">PCOS</a> (ovarian wedge resection).<sup class="cite-ref"><a href="#ref-17">17</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_near-contact-laparoscopy', 'near-contact-laparoscopy', 'Near Contact Laparoscopy', 'IV', 8, '<p><strong>A specialized laparoscopic technique in which the laparoscope is brought into close proximity to tissue to achieve high-magnification visualization.</strong> Used in NaPro Surgery for precise identification of subtle <a href="#endometriosis" class="gloss-xref">endometriosis</a> implants and peritoneal disease that might be missed at standard laparoscopic distance.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_s-map', 's-map', 'S-MAP (Systematic Mapping of the Abdomen and Pelvis)', 'IV', 9, '<p><strong>A methodical, standardized protocol for comprehensive examination of all abdominal and pelvic structures during <a href="#laparoscopy-operative" class="gloss-xref">laparoscopy</a>,</strong> ensuring that no area of disease is overlooked. The S-MAP method follows the systematic evaluation sequence described by Dr. Thomas Hilgers in the <a href="#naprotechnology-definition" class="gloss-xref">NaProTECHNOLOGY</a> textbook (Chapter 63); the term "S-MAP" was coined by Dr. Naomi Whittaker. Used in combination with Near-Contact Laparoscopy (NCL), S-MAP evaluates the upper abdomen (diaphragm, gallbladder), lower abdomen (cecum, appendix), and all pelvic structures (anterior and posterior cul-de-sac) in the same reproducible sequence every time. Dr. Whittaker presented a case series at AAGL 2024 demonstrating that NCL/S-MAP led to the incidental diagnosis and curative treatment of four rare cancers during fertility/pain surgeries by a single surgeon over three years.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_semen-analysis', 'semen-analysis', 'Semen Analysis', 'IV', 10, '<p><strong>The primary diagnostic test for <a href="#male-factor-infertility" class="gloss-xref">male factor infertility</a>,</strong> evaluating sperm concentration (count), motility, morphology (shape), volume, and other parameters. A normal semen analysis does not exclude male factor, as it does not assess sperm DNA integrity; additional testing (see <a href="#sperm-dna-fragmentation" class="gloss-xref">Sperm DNA Fragmentation Index</a>) may be warranted in cases of <a href="#unexplained-infertility" class="gloss-xref">unexplained infertility</a> or recurrent miscarriage.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_sperm-dna-fragmentation', 'sperm-dna-fragmentation', 'Sperm DNA Fragmentation Index (DFI)', 'IV', 11, '<p><strong>A measure of the proportion of sperm with damaged or fragmented DNA.</strong> A high <a href="#sperm-dna-fragmentation-extended" class="gloss-xref">DFI</a> is associated with poor reproductive outcomes including reduced natural conception rates, failed <a href="#iui" class="gloss-xref">IUI</a>, increased miscarriage risk, and impaired embryo development. Standard <a href="#semen-analysis" class="gloss-xref">semen analysis</a> does not assess DNA integrity, making DFI testing an important adjunct in evaluating <a href="#unexplained-infertility" class="gloss-xref">unexplained infertility</a>, <a href="#rpl" class="gloss-xref">recurrent pregnancy loss</a>, and repeated <a href="#art" class="gloss-xref">ART</a> failure. Treatment strategies include lifestyle modification, <a href="#antioxidant-therapy" class="gloss-xref">antioxidant therapy</a>, <a href="#varicocele" class="gloss-xref">varicocele</a> repair, and in select cases, testicular sperm retrieval.<sup class="cite-ref"><a href="#ref-19">19</a></sup><sup class="cite-ref"><a href="#ref-20">20</a></sup><sup class="cite-ref"><a href="#ref-21">21</a></sup><sup class="cite-ref"><a href="#ref-22">22</a></sup></p>', 'DFI', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_era', 'era', 'Endometrial Receptivity Analysis (ERA)', 'IV', 12, '<p><strong>A molecular diagnostic test that evaluates gene expression in an endometrial biopsy sample</strong> to determine the personalized "<a href="#window-of-implantation" class="gloss-xref">window of implantation</a>" (WOI), the period during which the endometrium is most receptive to embryo implantation. The ERA analyzes the expression profile of 236 to 238 genes related to endometrial receptivity status. In approximately 20 to 25% of women with recurrent implantation failure, the WOI is displaced from the standard timing. A study of 3,605 patients found that clinical pregnancy rate and live birth rate improved after personalized embryo transfer guided by ERA results, particularly in recurrent implantation failure patients.<sup class="cite-ref"><a href="#ref-23">23</a></sup><sup class="cite-ref"><a href="#ref-24">24</a></sup><sup class="cite-ref"><a href="#ref-25">25</a></sup></p>', 'ERA', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_cd138', 'cd138', 'CD138 (Syndecan-1) Immunohistochemistry', 'IV', 13, '<p><strong>A staining technique used on endometrial biopsy specimens to identify plasma cells,</strong> which are pathognomonic (definitively diagnostic) for <a href="#chronic-endometritis" class="gloss-xref">chronic endometritis</a>. CD138 IHC is more sensitive than routine histology alone for detecting chronic endometritis and is the current standard for diagnosis when chronic endometritis is suspected.<sup class="cite-ref"><a href="#ref-26">26</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_emma-alice', 'emma-alice', 'EMMA / ALICE (Endometrial Microbiome Testing)', 'IV', 14, '<p><strong>Molecular diagnostic tests that analyze the endometrial microbiome from a biopsy sample.</strong> EMMA (Endometrial Microbiome Metagenomic Analysis) measures the abundance and composition of endometrial bacteria, including the proportion of Lactobacillus (considered protective) and the presence of dysbiotic organisms. ALICE (Analysis of Infectious <a href="#chronic-endometritis" class="gloss-xref">Chronic Endometritis</a>) identifies pathogenic bacteria specifically associated with chronic endometritis. EMMA and ALICE are often ordered together with <a href="#era" class="gloss-xref">Endometrial Receptivity Analysis</a> (ERA) from a single biopsy as an "EndomeTRIO" panel. Microbiome-targeted probiotic and antibiotic treatments guided by these results have been studied as adjuncts for women with recurrent implantation failure and <a href="#rpl" class="gloss-xref">recurrent pregnancy loss</a>, though evidence quality varies across studies.<sup class="cite-ref"><a href="#ref-65">65</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_pgt-a', 'pgt-a', 'PGT-A (Preimplantation Genetic Testing for Aneuploidy)', 'IV', 15, '<p><strong>Preimplantation genetic testing for aneuploidy (PGT-A) is a laboratory test performed on an embryo biopsy during <a href="#ivf" class="gloss-xref">IVF</a> to screen for chromosomal aneuploidy before transfer.</strong> Formerly called PGS (preimplantation genetic screening), PGT-A is marketed as a tool to improve IVF success rates by selecting only chromosomally normal (euploid) embryos for transfer. The evidence for routine use in good-prognosis patients does not support the marketing claim. The STAR trial, a multicenter randomized controlled trial in good-prognosis IVF patients, found no significant difference in ongoing pregnancy rates at 20 weeks between PGT-A selection and morphology-based selection alone: 41.8% (138/330) with PGT-A versus 43.5% (144/331) with morphology, by intention-to-treat analysis.<sup class="cite-ref"><a href="#ref-59">59</a></sup> PGT-A improves per-transfer success rates by removing aneuploid embryos from the transfer queue, but it does not improve cumulative outcomes because it simultaneously reduces the number of embryos available for transfer. An additional concern: embryos classified as mosaic (partially aneuploid) are often excluded from transfer, yet mosaic embryos are capable of producing healthy pregnancies. PGT-A is specific to IVF. <a href="/what-is-rrm/">RRM</a> does not involve embryo creation outside the body, embryo biopsy, or embryo selection. The question of which embryo to transfer does not arise in <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> practice.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_amh', 'amh', 'Anti-Müllerian Hormone (AMH)', 'IV', 16, '<p>AMH measures the number of small antral follicles currently active in the ovaries. It reflects current activity, not a fixed inventory. That distinction matters: AMH is a snapshot of this cycle''s follicular activity, not a permanent verdict on reproductive potential.</p> <p>What AMH does not measure is equally important. It does not measure egg quality, follicle quality, or how well ovulation is functioning. A woman with a low AMH result may still produce a competent follicle this cycle. For natural conception, one good egg per cycle is all that is required.</p> <p>AMH''s significance as a "low" number is largely anchored to protocols that require retrieving six to fifteen eggs at once. That is the <a href="#ivf" class="gloss-xref">IVF</a> context. An <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> clinician asks a different question: what is this cycle''s follicle doing? A single well-developed, well-supported follicle is the clinical target. The total pool size is a starting point for the workup, not the answer.</p> <p>A low AMH result is a diagnostic signal, not a sentence. The question is why. Age is one factor. But autoimmune conditions, prior ovarian surgery, <a href="#endometriosis" class="gloss-xref">endometriosis</a>, vitamin D deficiency, and thyroid dysfunction can all reduce AMH before age alone explains it. AMH can also change. A meta-analysis of 8 studies found DHEA supplementation significantly raised serum AMH in women with <a href="#dor" class="gloss-xref">diminished ovarian reserve</a> (Yin et al., BMC Endocrine Disorders, 2022).<sup class="cite-ref"><a href="#ref-77">77</a></sup> Vitamin D repletion shows a similar effect. Treating correctable contributors is the first step, not a last resort.</p> <p>AMH also has a ceiling problem. In <a href="#pcos" class="gloss-xref">PCOS</a>, AMH is often markedly elevated because many small follicles accumulate without maturing. A high AMH number is not simply reassuring. It reflects a pattern of arrested <a href="#follicle-development" class="gloss-xref">follicle development</a> that warrants investigation.</p> <p>Unlike <a href="#fsh" class="gloss-xref">FSH</a>, AMH does not fluctuate significantly across the menstrual cycle. It can be drawn on any cycle day, which makes it useful for tracking trends over time. But a single result should not anchor a clinical course. In RRM practice, AMH is interpreted alongside <a href="#afc" class="gloss-xref">AFC</a>, cycle chart patterns, timed hormonal panels, and a <a href="#follicle-maturation-study" class="gloss-xref">follicle maturation study</a> when indicated. A low AMH with normal AFC and regular ovulatory cycles tells a different story than a low AMH with <a href="#anovulatory-cycles" class="gloss-xref">anovulatory cycles</a> and a <a href="#shortened-luteal-phase" class="gloss-xref">shortened luteal phase</a>. The number alone is not the diagnosis. It is the beginning of the workup.</p>', 'AMH', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_afc', 'afc', 'Antral Follicle Count (AFC)', 'IV', 17, '<p>The antral follicle count is a transvaginal ultrasound measurement taken in the early follicular phase. The sonographer counts small fluid-filled follicles, typically 2 to 10 mm in diameter, visible in both ovaries. The total is the AFC.</p> <p>AFC reflects the number of follicles beginning development at the start of this cycle. A lower count indicates fewer follicles starting that cycle. Like <a href="#amh" class="gloss-xref">AMH</a>, AFC is a marker of <a href="#ovarian-reserve" class="gloss-xref">ovarian reserve</a>, not a standalone diagnosis. A low AFC in a 38-year-old with a surgical history is a different clinical finding than the same count in a 28-year-old with unexplained cycle irregularity. Context drives interpretation.</p> <p>The right question is not how many follicles are present, but what the one dominant follicle is doing. Natural conception requires one well-developed follicle that ovulates at the right time. AFC tells the clinician what the ovary is starting with this cycle. The <a href="#follicle-maturation-study" class="gloss-xref">follicle maturation study</a> tracks what it does next.</p> <p>AFC varies more than AMH across cycles and between sonographers. Technique, equipment, and timing within the follicular phase all affect the count. A single AFC should not be used to make irreversible conclusions about prognosis. Serial measurements over two or three cycles give a more reliable picture.</p> <p>In <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> practice, AFC is most useful in context. Combined with AMH, cycle chart data, and timed hormonal panels, it helps identify correctable contributors to poor follicular development: thyroid dysfunction, <a href="#endometriosis" class="gloss-xref">endometriosis</a>, autoimmune conditions, or the suppressive effect of hormonal medications on follicle recruitment. An RRM clinician uses this picture to find and treat what is driving the finding. When ovulation support is indicated, RRM uses targeted, cycle-timed interventions designed to support this cycle''s follicle, not stimulate the ovary toward a large retrieval. AFC is central to that protocol planning.</p>', 'AFC', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_ovarian-reserve', 'ovarian-reserve', 'Ovarian Reserve', 'IV', 18, '<p><strong>The ovarian reserve describes the pool of follicles currently available in the ovaries, estimated through surrogate markers: <a href="#amh" class="gloss-xref">AMH</a>, <a href="#afc" class="gloss-xref">AFC</a>, and basal <a href="#fsh" class="gloss-xref">FSH</a>.</strong> Clinicians cannot count oocytes directly. These markers are proxies for follicular activity, not a balance sheet of remaining eggs.</p> <p>Low reserve markers are a starting question, not a finishing answer. A low AMH or low AFC tells you the pool of visible follicles is smaller than average for age. It does not tell you why. And it does not close the door on natural conception. One competent follicle per cycle is all that is needed. The clinical question is what that follicle is doing, not how many follicles exist in the background.</p> <p>Each marker captures something different. AMH reflects the number of small growing follicles actively producing the hormone. AFC counts the antral follicles visible on early-cycle ultrasound. Basal FSH rises as the pituitary increases its recruitment signal to a smaller follicular pool. Used together, these markers build a picture of current ovarian function. No single marker is definitive.</p> <p>For women with reduced reserve, <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> evaluation looks for correctable contributors to the decline. Autoimmune thyroid disease accelerates follicle loss and responds to thyroid optimization. Vitamin D deficiency suppresses AMH and is correctable with repletion. <a href="#endometriosis" class="gloss-xref">Endometriosis</a> causes direct ovarian damage through endometriomas and surgical scarring; excision addresses the structural source. Prior ovarian surgery may have reduced functional tissue, but what remains can often be supported. In documented low-DHEA-S cases, a meta-analysis of 8 studies found DHEA supplementation significantly raised AMH in women with <a href="#dor" class="gloss-xref">diminished ovarian reserve</a>.<sup class="cite-ref"><a href="#ref-77">77</a></sup> These are starting points for investigation, not triage criteria.</p> <p>For women with <a href="#poi" class="gloss-xref">premature ovarian insufficiency</a>, reserve assessment is part of a broader workup including genetic screening and autoimmune evaluation. For women with diminished ovarian reserve without a POI diagnosis, identifying and addressing the underlying driver is the first clinical priority. Reserve markers point toward the question. An RRM clinician builds the answer from the full picture: cycle chart, <a href="#follicle-maturation-study" class="gloss-xref">follicle maturation study</a>, timed hormonal panels, and systemic workup.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_follicle-development', 'follicle-development', 'Follicle Development', 'IV', 19, '<p><strong>The process by which primordial follicles in the ovary are recruited, grow, and either ovulate or undergo atresia (cell death) across the menstrual cycle.</strong> Each cycle, a cohort of follicles begins maturing under <a href="#fsh" class="gloss-xref">FSH</a> stimulation. Typically one dominant follicle is selected, growing to 18 to 24 mm before the <a href="#lh" class="gloss-xref">LH</a> surge triggers ovulation. The remaining follicles in the cohort regress.</p> <p>Clinicians monitor follicle development directly through a <a href="#follicle-maturation-study" class="gloss-xref">follicle maturation study</a>. Serial transvaginal ultrasounds across the follicular phase show the growth rate, timing of dominant follicle selection, and whether ovulation actually occurs or the follicle fails to rupture. That last distinction matters: a follicle can luteinize without releasing the oocyte, a condition called <a href="#luf-syndrome" class="gloss-xref">LUF</a> syndrome, which standard lab tests will not detect.</p> <p>Inadequate follicle development has downstream consequences. A follicle that does not reach full maturity before ovulation produces a <a href="#corpus-luteum" class="gloss-xref">corpus luteum</a> with reduced progesterone output. That sets up <a href="#luteal-phase-deficiency" class="gloss-xref">luteal phase deficiency</a> even in a cycle that appeared ovulatory on a basal temperature chart. Treating the <a href="#luteal-phase" class="gloss-xref">luteal phase</a> problem without addressing the follicular phase problem leaves the root cause unresolved.</p> <p>In <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> practice, ovulation induction agents (clomiphene, letrozole) are used when follicle development is inadequate, timed to the follicular phase based on chart data. Monitoring with serial ultrasound confirms the response and guides trigger decisions. The goal is to restore the follicle development pattern the body was not producing on its own.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_peak-plus-series', 'peak-plus-series', 'Targeted Post-Peak Progesterone Series (Peak +3, +5, +7, +9, +11)', 'IV', 20, '<p><strong>The Targeted Post-Peak Progesterone Series is a Hilgers-developed protocol of five serial serum progesterone draws obtained at <a href="#peak-day" class="gloss-xref">Peak Day</a> +3, +5, +7, +9, and +11, designed to characterize the full luteal-phase hormonal profile rather than a single mid-luteal snapshot.</strong></p><p>Standard <a href="#reproductive-endocrinology" class="gloss-xref">reproductive endocrinology</a> relies on a single "day-21 progesterone" draw. That number tells you almost nothing. It cannot distinguish an adequate <a href="#luteal-phase" class="gloss-xref">luteal phase</a> from a deficient one, and it cannot locate where in the luteal arc the deficit falls. The Peak +3 through +11 series captures early, mid, and late luteal output in a single protocol block. Results are interpreted as individual raw values, three-value sums (Peak +5/+7/+9), four-value sums, and five-value means.</p><p>The Peak +3 draw carries its own diagnostic weight. Hilgers established two clinical thresholds: a value of 2.3 ng/mL or higher confirms ovulation has occurred; 3.0 ng/mL or higher marks the beginning of the absolute postovulation period of <a href="#infertility" class="gloss-xref">infertility</a>.<sup class="cite-ref"><a href="#ref-81">81</a></sup> The full five-point series identifies Type I through V <a href="#luteal-phase-deficiency" class="gloss-xref">luteal phase deficiency</a>, distinguishing early-luteal, late-luteal, and integrated deficits that require different <a href="#restorative-as-a-principle" class="gloss-xref">restorative</a> hormonal protocols.<sup class="cite-ref"><a href="#ref-78">78</a></sup> Reduced luteal output may also reflect <a href="#corpus-luteum-deficiency" class="gloss-xref">corpus luteum deficiency</a> or a disorder of Peak Day identification. Cycle-timed measurement, not a calendar estimate, is what makes the data actionable.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_sonographic-ovulation-classification', 'sonographic-ovulation-classification', 'Sonographic Classification of Ovulation Disorders (Hilgers Classification)', 'IV', 21, '<p><strong>The Hilgers Sonographic Classification of Ovulation Disorders is an eight-category serial-ultrasound framework that characterizes the quality of the ovulatory event, distinguishing anatomically normal ovulation from six distinct pathological patterns and one anovulatory variant.</strong></p><p>A positive ovulation predictor kit tells a woman that an <a href="#lh" class="gloss-xref">LH</a> surge occurred. It says nothing about whether the follicle matured adequately, ruptured fully, released the cumulus oophorus intact, or collapsed at a normal rate. Hilgers'' classification, developed from serial periovulatory ultrasound, captures what actually happened at the follicle.<sup class="cite-ref"><a href="#ref-78">78</a></sup></p><p>Normal ovulation requires a mature follicle of 1.90 cm or greater mean diameter, a positive cumulus oophorus sign, and complete rupture. Deviation from any criterion defines a disorder category. The eight categories are: anatomically normal ovulation; <a href="#luf-syndrome" class="gloss-xref">Luteinized Unruptured Follicle Syndrome</a> (LUF); Mature Follicle with Absent or Retained Cumulus; <a href="#immature-follicle-syndrome" class="gloss-xref">Immature Follicle Syndrome</a> (mean diameter below 1.90 cm at rupture); <a href="#partial-rupture-syndrome" class="gloss-xref">Partial Rupture Syndrome</a> (collapse of 7.5 mm or less over 24 hours); <a href="#delayed-rupture-syndrome" class="gloss-xref">Delayed Rupture Syndrome</a> (rupture spread across 48 hours); <a href="#afollicularism" class="gloss-xref">Afollicularism</a> (no follicle reaches dominance); and <a href="#empty-follicle-syndrome" class="gloss-xref">Empty Follicle Syndrome</a> (absent cumulus oophorus on ultrasound). Each category carries distinct downstream fertility implications and maps to specific <a href="#restorative-as-a-principle" class="gloss-xref">restorative</a> interventions. A <a href="#follicle-maturation-study" class="gloss-xref">follicle maturation study</a> is the ultrasound series used to generate this classification.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_tcft', 'tcft', 'Transcervical Catheterization of the Fallopian Tubes (TCFT)', 'IV', 22, '<p><strong>Transcervical Catheterization of the Fallopian Tubes (TCFT) is the Hilgers-Yeung protocol for clearing partial proximal tubal occlusion using a 3 French delivery catheter and a 0.018-inch flexible-tipped guidewire advanced under fluoroscopic guidance, performed in conjunction with selective hysterosalpingography and <a href="#intratubal-pressure" class="gloss-xref">intratubal pressure</a> measurement.</strong></p><p>Proximal tubal occlusion identified on standard <a href="#hsg" class="gloss-xref">HSG</a> is frequently over-diagnosed. Spasm, debris, and incomplete contrast filling produce false-positive blocks. TCFT does not simply confirm patency: it measures resistance before and after catheterization, confirming that a true mechanical obstruction was present and cleared.</p><p>The procedure uses a specialized catheter system advanced to the uterotubal junction under fluoroscopy. A LeVeen pressure-monitoring syringe records intratubal pressure at each step. Hilgers and Yeung reported that over 75% of partially obstructed tubes return to normal patency following catheterization.<sup class="cite-ref"><a href="#ref-84">84</a></sup> TCFT is performed during the proliferative phase and is distinct from generic tubal cannulation in its pressure-measurement component and cycle-timed execution.<sup class="cite-ref"><a href="#ref-78">78</a></sup></p><p>For couples with proximal tubal factor, TCFT restores the anatomical pathway for natural conception. It is a <a href="#restorative-as-a-principle" class="gloss-xref">restorative</a> alternative to bypassing the tube entirely. The procedure is complementary to <a href="#selective-salpingography" class="gloss-xref">selective salpingography</a> and, where occlusion is complete rather than partial, informs the decision for surgical evaluation via <a href="#fallopian-tube-recanalization" class="gloss-xref">fallopian tube recanalization</a>.</p>', 'TCFT', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_intratubal-pressure', 'intratubal-pressure', 'Intratubal Pressure (ITP)', 'IV', 23, '<p><strong>Intratubal pressure (ITP) is a quantitative measure of fallopian tube patency obtained by recording the pressure required to advance contrast through the tube during selective hysterosalpingography, using a LeVeen pressure-monitoring syringe.</strong></p><p>Standard <a href="#hsg" class="gloss-xref">HSG</a> reports tubes as patent or blocked. That binary tells clinicians nothing about the degree of obstruction, whether a partial block is amenable to catheterization, or whether an apparently patent tube is functioning at abnormal resistance. ITP converts the qualitative into the quantitative.</p><p>Hilgers and Yeung defined three pressure thresholds from measured data: freely patent tubes at a mean of 0.53 ATM, partially obstructed tubes at 1.23 ATM, and completely obstructed tubes at 2.79 ATM.<sup class="cite-ref"><a href="#ref-84">84</a></sup> An ITP at or above 0.7 ATM serves as the operational threshold triggering <a href="#tcft" class="gloss-xref">transcervical catheterization of the fallopian tubes</a>. Post-catheterization ITP confirms whether the obstruction resolved or persists.</p><p>ITP measurement is performed as part of <a href="#selective-salpingography" class="gloss-xref">selective salpingography</a> and pairs with HSG findings to guide <a href="#restorative-as-a-principle" class="gloss-xref">restorative</a> tubal intervention. Graded patency assessment allows clinicians to intervene before a couple reaches a point where tube bypass is presented as the only remaining option. The data drives the decision: not assumption, not calendar, not a single contrast image.</p>', 'ITP', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_excision-surgery', 'excision-surgery', 'Excision Surgery (for Endometriosis)', 'V', 0, '<p><strong>The surgical removal of endometriotic tissue by cutting it out, as opposed to ablation (burning/destroying it superficially).</strong> Considered the preferred surgical approach in <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> for endometriosis. A 2022 cohort study of 232 patients showed that excision improved outcomes across all 63 symptom measures evaluated (ranging from 28 to 46% improvement), while ablation only marginally improved period pain (11.3%) and heavy periods (8.5%) and worsened status in 23 of 24 quality-of-life measures. A meta-analysis found significantly greater reduction in dysmenorrhea (MD=0.99), dyschezia, and <a href="#chronic-pelvic-pain" class="gloss-xref">chronic pelvic pain</a> with excision compared to ablation at 12 months.<sup class="cite-ref"><a href="#ref-27">27</a></sup><sup class="cite-ref"><a href="#ref-28">28</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_fulguration-ablation', 'fulguration-ablation', 'Fulguration / Ablation / Cauterization (Endometriosis)', 'V', 1, '<p><strong>Superficial destruction of tissue using heat, electrical energy, or laser vaporization.</strong> As applied to <a href="#endometriosis" class="gloss-xref">endometriosis</a>, this approach destroys the visible surface of lesions without removing the tissue or underlying disease. Evidence consistently demonstrates it is less effective than excision for symptom resolution, quality-of-life improvement, and fertility outcomes, and is associated with higher recurrence rates. Not preferred in <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a>.<sup class="cite-ref"><a href="#ref-29">29</a></sup><sup class="cite-ref"><a href="#ref-27">27</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_adhesiolysis', 'adhesiolysis', 'Adhesiolysis', 'V', 2, '<p><strong>Surgical division and removal of adhesions (pelvic <a href="#pelvic-adhesions" class="gloss-xref">scar tissue</a>).</strong> In <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> and NaPro Surgery, adhesiolysis is performed meticulously, with hemostasis and anti-adhesion barrier placement to minimize adhesion reformation.<sup class="cite-ref"><a href="#ref-10">10</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_anti-adhesion-barriers', 'anti-adhesion-barriers', 'Anti-Adhesion Barriers', 'V', 3, '<p><strong>Materials placed during surgery to physically separate tissue surfaces during the healing period, reducing adhesion formation.</strong> In NaPro Surgery, Gore-Tex membrane (expanded polytetrafluoroethylene) has been used extensively, with published results showing dramatic reductions in adhesion reformation scores over time.<sup class="cite-ref"><a href="#ref-10">10</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_tubal-ligation-reversal', 'tubal-ligation-reversal', 'Tubo-tubal Anastomosis (Tubal Ligation Reversal)', 'V', 4, '<p><strong>Microsurgical reconnection of the fallopian tube segments following prior tubal ligation ("tubes tied"), allowing natural conception to resume.</strong> Can be performed via <a href="#laparoscopy-operative" class="gloss-xref">laparoscopy</a>, robotic assistance, or <a href="#mini-laparotomy" class="gloss-xref">mini-laparotomy</a>. Pregnancy rates after tubal reversal using microsurgical techniques range from 57% to 84%. A large series found that women under 30 with ring/clip sterilization reversals achieved an 88% pregnancy rate. Success depends most strongly on the woman''s age at time of reversal and the remaining tube length after reconstruction.<sup class="cite-ref"><a href="#ref-30">30</a></sup><sup class="cite-ref"><a href="#ref-31">31</a></sup><sup class="cite-ref"><a href="#ref-32">32</a></sup><sup class="cite-ref"><a href="#ref-33">33</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_vasectomy-reversal', 'vasectomy-reversal', 'Vasectomy Reversal (Vasovasostomy / Vasoepididymostomy)', 'V', 5, '<p><strong>Microsurgical reconnection of the vas deferens after prior vasectomy, restoring the potential for natural conception.</strong> Vasovasostomy joins the two cut ends of the vas deferens and is the standard procedure. Vasoepididymostomy, a more technically demanding variant, is required when a secondary epididymal blockage has developed upstream, which is more likely with obstructive intervals greater than 10 to 15 years. Patency rates (return of sperm to the ejaculate) exceed 90% for vasovasostomy performed by experienced microsurgeons; pregnancy rates vary by obstructive interval, female partner age, and surgical technique. Vasectomy reversal is the <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a>-aligned <a href="#restorative-as-a-principle" class="gloss-xref">restorative</a> alternative to surgical sperm retrieval combined with <a href="#ivf" class="gloss-xref">IVF</a>/<a href="#icsi" class="gloss-xref">ICSI</a> for couples seeking further pregnancies after prior vasectomy, treating the obstruction rather than bypassing it. See <a href="/neofertility/">NeoFertility''s male program</a> for an RRM-aligned clinical model that integrates vasectomy reversal within a full couple evaluation.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_fallopian-tube-recanalization', 'fallopian-tube-recanalization', 'Fallopian Tube Recanalization (Cannulation)', 'V', 6, '<p><strong>A procedure to open proximal (near the uterus) fallopian tube blockages through transcervical catheter passage, without open surgery.</strong> Often performed in conjunction with <a href="#hsg" class="gloss-xref">HSG</a>. Can be done in an office or interventional radiology setting.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_neosalpingostomy', 'neosalpingostomy', 'Neosalpingostomy / Fimbrioplasty', 'V', 7, '<p><strong>Laparoscopic surgical repair of distal (fimbrial end) fallopian tube damage,</strong> typically caused by pelvic inflammatory disease or prior infection. Neosalpingostomy creates a new opening in a completely blocked tube (<a href="#hydrosalpinx" class="gloss-xref">hydrosalpinx</a>), while fimbrioplasty reconstructs and opens a partially obstructed or agglutinated fimbrial end.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_lowr', 'lowr', 'Laparoscopic Ovarian Wedge Resection (LOWR)', 'V', 8, '<p><strong>A surgical procedure for select <a href="#pcos" class="gloss-xref">PCOS</a> cases, involving removal of a wedge of androgen-producing ovarian cortex to normalize hormonal balance and restore ovulation.</strong> Using microsurgical laser techniques, NaPro wedge resection has achieved approximately 70% pregnancy rates, over twice as effective as standard clomiphene citrate treatment (~30%) and higher than reported <a href="#ivf" class="gloss-xref">IVF</a> success rates in PCOS (~23%). This surgical solution restores regular ovulation and does not carry the risk of ovarian hyperstimulation.<sup class="cite-ref"><a href="#ref-10">10</a></sup></p>', 'LOWR', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_isthmocele-repair-hysteroscopic', 'isthmocele-repair-hysteroscopic', 'Isthmocele Repair (Hysteroscopic)', 'V', 9, '<p><strong>Hysteroscopic treatment of a cesarean scar defect (isthmocele) by shaving and cauterizing the defect internally,</strong> reducing the depth of the niche and improving drainage of retained blood. Best suited for symptomatic patients (primarily bleeding complaints) with a residual myometrial wall thickness of at least 2.5 to 3 mm who do not desire future pregnancy. Associated with faster recovery but lower rates of complete bleeding resolution and does not restore wall integrity for future pregnancy.<sup class="cite-ref"><a href="#ref-34">34</a></sup><sup class="cite-ref"><a href="#ref-15">15</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_isthmocele-repair-laparoscopic', 'isthmocele-repair-laparoscopic', 'Isthmocele Repair (Laparoscopic)', 'V', 10, '<p><strong>Laparoscopic excision of the defect with multi-layer reconstruction of the uterine muscular wall.</strong> Preferred when fertility preservation is desired or when residual myometrial thickness is less than 3 mm. Restores wall integrity for safer future pregnancy and is more likely to resolve bleeding symptoms. Longer recovery than hysteroscopic repair. Combined laparoscopic-hysteroscopic approaches are used for complex cases.<sup class="cite-ref"><a href="#ref-16">16</a></sup><sup class="cite-ref"><a href="#ref-15">15</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_myomectomy', 'myomectomy', 'Myomectomy', 'V', 11, '<p><strong>Surgical removal of <a href="#uterine-fibroids" class="gloss-xref">uterine fibroids</a> (leiomyomas) while preserving the uterus.</strong> Can be performed hysteroscopically (for submucosal fibroids), laparoscopically, robotically, or via laparotomy depending on fibroid type, size, and number. <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> prefers fertility-sparing myomectomy over hysterectomy when fibroids are contributing to <a href="#infertility" class="gloss-xref">infertility</a> or pregnancy loss.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_microsurgery', 'microsurgery', 'Microsurgery', 'V', 12, '<p><strong>Surgical technique performed under microscopic magnification using fine instruments and sutures</strong> (often 6-0 to 9-0 gauge), essential for tubal anastomosis in ligation reversal and repair. Microsurgical principles include minimal tissue handling, precise hemostasis, tension-free anastomosis, and meticulous layer-by-layer closure.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_mini-laparotomy', 'mini-laparotomy', 'Mini-laparotomy', 'V', 13, '<p><strong>A small (approximately 3 to 5 cm) "bikini line" incision surgery,</strong> sometimes used as an alternative to <a href="#laparoscopy-operative" class="gloss-xref">laparoscopy</a> for procedures such as <a href="#tubal-ligation-reversal" class="gloss-xref">tubal ligation reversal</a> in appropriately selected patients. Offers a smaller scar and reduced anesthesia risk compared to traditional open surgery.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_pears', 'pears', 'PEARS (Pelvic Excision And Repair Surgery)', 'V', 14, '<p><strong>PEARS (Pelvic Excision And Repair Surgery) is a form of plastic reconstructive surgery of the pelvis</strong> developed by Dr. Thomas Hilgers at the Pope Paul VI Institute.<sup class="cite-ref"><a href="#ref-78">78</a></sup> The name reflects the procedure''s dual mandate: complete excision of pelvic disease and systematic anatomic repair.</p><p>In PEARS, <a href="#endometriosis" class="gloss-xref">endometriosis</a> is excised rather than ablated. This is not a technical preference. Ablation destroys the surface of a lesion; excision removes it entirely, including the base. Disease masked by destruction continues to progress. Disease removed is gone.<sup class="cite-ref"><a href="#ref-27">27</a></sup><sup class="cite-ref"><a href="#ref-28">28</a></sup></p><p>Excision is only half the procedure. The repair component applies a layered system of anti-adhesion measures: micro-monopolar or CO&#8322;-laser technique, Prolene imbricating closure of the peritoneum and ovarian cortex with rough edges inverted internally, heparinized Ringer''s lactate irrigation, and talc-free hydro-pack bowel isolation. The imbricating closure leaves only smooth, glistening serosa exposed to the peritoneal cavity. This matters because post-operative adhesions are a leading cause of <a href="#secondary-infertility" class="gloss-xref">secondary infertility</a> after pelvic surgery.</p><p>PEARS applies across the full range of pelvic pathology: peritoneal endometriosis, ovarian endometriomas, polycystic ovaries, fibroids, fallopian tube disease, and adhesive disease.<sup class="cite-ref"><a href="#ref-78">78</a></sup> The goal is not symptom relief. The goal is anatomic restoration of fertility.</p>', 'PEARS', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_narps', 'narps', 'Near Adhesion-Free Reconstructive Pelvic Surgery (NARPS)', 'V', 15, '<p><strong>Near Adhesion-Free Reconstructive Pelvic Surgery (NARPS) is a surgical philosophy and protocol, developed by Dr. Thomas Hilgers, built on a single clinical observation: adhesion formation after pelvic surgery cannot be eliminated, but it can be minimized systematically.</strong><sup class="cite-ref"><a href="#ref-78">78</a></sup></p><p>NARPS is the framework. <a href="#pears" class="gloss-xref">PEARS</a> is the execution. Where PEARS describes a procedure applied to specific pathology, NARPS describes the set of more than ten anti-adhesion principles that govern every step of that procedure.</p><p>Those principles include: careful incision and dissection technique, Prolene imbricating closure with rough peritoneal edges inverted away from the peritoneal cavity, talc-free hydro-pack bowel isolation, heparinized Ringer''s lactate irrigation, fibrin sealant or barrier placement, micro-monopolar or CO&#8322;-laser excision, and meticulous hemostasis throughout.<sup class="cite-ref"><a href="#ref-78">78</a></sup></p><p>The 2010 outcomes paper by Hilgers, Stanford, Boyle, and colleagues documented three distinct phases of protocol refinement over 23 years: Phase I (1987 to 1993, 26 patients), Phase II (1994 to 2005, 44 patients), and Phase III (2006 to 2009, 25 patients).<sup class="cite-ref"><a href="#ref-80">80</a></sup> Postoperative AFS adhesion scores declined progressively across phases, from approximately 33.8 in Phase I to approximately 18 in Phase III. The data show measurable improvement with each iteration of the protocol.</p><p>For patients with the most extensive pelvic adhesive disease, NARPS represents the evidence base for expecting a near-adhesion-free postoperative outcome: not as a promise, but as a documented clinical target.</p>', 'NARPS', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_infertility', 'infertility', 'Infertility', 'VI', 0, '<p><strong>Clinically defined as failure to achieve pregnancy after 12 months of regular unprotected intercourse (6 months for women 35 years and older).</strong> In the <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> framework, infertility is understood as a symptom of one or more identifiable, underlying, treatable conditions, not a diagnosis in itself. Approximately 15% of couples worldwide are affected.<sup class="cite-ref"><a href="#ref-35">35</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_rpl', 'rpl', 'Recurrent Pregnancy Loss (RPL)', 'VI', 1, '<p><strong>Typically defined as two or more consecutive clinical pregnancy losses before 20 weeks of gestation.</strong> RPL is clinically distinct from isolated <a href="#early-pregnancy-loss" class="gloss-xref">early pregnancy loss</a>: a single loss is common and often attributable to sporadic chromosomal error, while recurrent loss warrants systematic evaluation for treatable maternal and paternal contributors. Assessment includes peripheral karyotype analysis of both partners, antiphospholipid antibody testing, uterine anatomical evaluation (SHG, <a href="#hsg" class="gloss-xref">HSG</a>, or <a href="#hysteroscopy-operative" class="gloss-xref">hysteroscopy</a>), thyroid and prolactin screening, and evaluation for hereditary thrombophilias. <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> pursues identification of underlying conditions including hormonal (progesterone deficiency, thyroid dysfunction), anatomical (isthmocele, septum, fibroids), immunologic (<a href="#aps" class="gloss-xref">APS</a>, <a href="#nk-cells" class="gloss-xref">NK</a> cell activity), and metabolic factors.<sup class="cite-ref"><a href="#ref-36">36</a></sup><sup class="cite-ref"><a href="#ref-37">37</a></sup></p>', 'RPL', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_endometriosis', 'endometriosis', 'Endometriosis', 'VI', 2, '<p><strong>A chronic inflammatory condition in which endometrial-like tissue is found outside the uterine cavity</strong>, most commonly on the ovaries, fallopian tubes, pelvic peritoneum, and rectovaginal septum. Affects approximately 1 in 10 women of reproductive age. <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a>''s preferred treatment is laparoscopic <a href="#excision-surgery" class="gloss-xref">excision surgery</a>, which demonstrates significantly greater improvement across all symptom domains (28 to 46% improvement range) compared to ablation, which failed to improve most symptoms and worsened quality of life in multiple measures. A key RRM principle is that hormonal suppression post-surgery (e.g., <a href="#oc" class="gloss-xref">oral contraceptive</a> pills) masks ongoing disease activity without treating the condition.<sup class="cite-ref"><a href="#ref-28">28</a></sup><sup class="cite-ref"><a href="#ref-27">27</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_endometrioma', 'endometrioma', 'Endometrioma', 'VI', 3, '<p><strong>An ovarian cyst formed by <a href="#endometriosis" class="gloss-xref">endometriosis</a>, filled with old menstrual blood</strong> (colloquially called a "chocolate cyst"). Endometriomas reduce <a href="#ovarian-reserve" class="gloss-xref">ovarian reserve</a> and impair oocyte quality. Surgical management with excisional cystectomy is generally preferred over drainage and ablation, though ovarian reserve impact of surgery must be considered.<sup class="cite-ref"><a href="#ref-38">38</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_pcos', 'pcos', 'PCOS (Polycystic Ovary Syndrome)', 'VI', 4, '<p><strong>A complex hormonal and metabolic disorder characterized by ovulatory dysfunction, hyperandrogenism (elevated androgens causing acne, hirsutism), and/or polycystic ovarian morphology on ultrasound.</strong> Insulin resistance and visceral adiposity are key pathophysiologic drivers, irrespective of obesity. <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a>''s multi-factorial approach includes lifestyle modification (5% weight loss can restore ovulation), insulin sensitization (metformin, <a href="#myo-inositol" class="gloss-xref">myo-inositol</a>), cycle charting and ovulation monitoring, targeted hormonal support, and in select cases, <a href="#lowr" class="gloss-xref">laparoscopic ovarian wedge resection</a>.<sup class="cite-ref"><a href="#ref-39">39</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_pcos-phenotypes', 'pcos-phenotypes', 'PCOS Phenotypes (Rotterdam A through D)', 'VI', 5, '<p><strong><a href="#pcos" class="gloss-xref">PCOS</a> is diagnosed when two of three Rotterdam criteria are met: ovulatory dysfunction, clinical or biochemical hyperandrogenism, and polycystic ovarian morphology on ultrasound.</strong> This produces four distinct phenotypes, each with a different metabolic and hormonal profile:</p> <ul> <li><strong>Phenotype A (Full/Classic):</strong> All three features present. The most pronounced metabolic dysfunction and highest insulin resistance. This is the phenotype most likely to require aggressive metabolic intervention.</li> <li><strong>Phenotype B:</strong> Ovulatory dysfunction plus hyperandrogenism, no polycystic morphology. Metabolic profile closely resembles Phenotype A.</li> <li><strong>Phenotype C (Ovulatory):</strong> Hyperandrogenism plus polycystic morphology, with regular ovulation preserved. Milder metabolic impact than A or B.</li> <li><strong>Phenotype D (Non-hyperandrogenic):</strong> Ovulatory dysfunction plus polycystic morphology, no hyperandrogenism. The least metabolically severe phenotype.</li> </ul> <p>Phenotyping matters for treatment. Phenotypes A and B typically need insulin sensitization and metabolic correction before ovulation returns reliably. Phenotype C may respond to targeted hormonal support. Phenotype D often responds to ovulation induction without the full metabolic workup. Flying blind on phenotype means treating every PCOS presentation the same way, and that is how patients cycle through protocols for years without resolution.<sup class="cite-ref"><a href="#ref-39">39</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_myo-inositol', 'myo-inositol', 'Myo-Inositol', 'VI', 6, '<p><strong>A naturally occurring carbocyclic sugar that acts as an insulin sensitizer and secondary messenger in <a href="#fsh" class="gloss-xref">FSH</a> signaling.</strong> Used as a supplement in <a href="#pcos" class="gloss-xref">PCOS</a> management. Evidence shows myo-inositol improves ovarian function, oocyte maturity rates, fertilization rates, and metabolic parameters (<a href="#lh" class="gloss-xref">LH</a>, FSH, HOMA-IR) in women with PCOS. A 2025 meta-analysis found statistically significant improvement in MII oocyte rate and fertilization rate, though evidence for clinical pregnancy rate improvement remains less conclusive.<sup class="cite-ref"><a href="#ref-40">40</a></sup><sup class="cite-ref"><a href="#ref-41">41</a></sup><sup class="cite-ref"><a href="#ref-42">42</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_isthmocele', 'isthmocele', 'Uterine Isthmocele (Cesarean Scar Defect / Uterine Niche)', 'VI', 7, '<p><strong>A myometrial defect (a pouch or indentation) in the anterior wall of the lower uterine segment (isthmus) at the site of a previous cesarean section scar,</strong> representing discontinuity of the myometrium. Caused by incomplete or defective healing of the uterine closure at the time of cesarean delivery. The defect creates a reservoir in which menstrual blood pools, then drains slowly, resulting in characteristic post-menstrual brown spotting. The retained blood creates a hostile microenvironment for sperm and may impair implantation, contributing to <a href="#secondary-infertility" class="gloss-xref">secondary infertility</a> and increased miscarriage risk when the wall is thin. Prevalence is approximately 20% or more in women with prior cesarean deliveries.<sup class="cite-ref"><a href="#ref-15">15</a></sup><sup class="cite-ref"><a href="#ref-16">16</a></sup><sup class="cite-ref"><a href="#ref-34">34</a></sup></p> <p><strong>Diagnosis:</strong> Transvaginal ultrasound (TVUS) and saline infusion sonohysterography (<a href="#sis" class="gloss-xref">SIS</a>) are the preferred diagnostic tools, both sensitive and cost-effective. SIS allows measurement of the defect dimensions and critically, the residual myometrial thickness (RMT). Treatment decisions depend on symptom profile, RMT, and future fertility desires.<sup class="cite-ref"><a href="#ref-43">43</a></sup><sup class="cite-ref"><a href="#ref-16">16</a></sup><sup class="cite-ref"><a href="#ref-15">15</a></sup></p> <p><strong>Treatment classification:</strong></p> <div class="table-wrap"> <table> <thead> <tr> <th>Approach</th> <th>Method</th> <th>Best For</th> <th>Key Consideration</th> </tr> </thead> <tbody> <tr><td>Hysteroscopic</td><td>Internal shaving/cautery of defect</td><td>Bleeding symptoms; RMT &gt;5mm; no future pregnancy desired</td><td>Faster recovery; may not fully resolve bleeding; does not rebuild wall<sup class="cite-ref"><a href="#ref-34">34</a></sup></td></tr> <tr><td>Laparoscopic</td><td>Excision + multi-layer reconstruction</td><td>Fertility desire; RMT &lt;5mm; preferred overall</td><td>Rebuilds wall integrity; better symptom resolution; longer recovery<sup class="cite-ref"><a href="#ref-15">15</a></sup></td></tr> <tr><td>Combined</td><td>Laparoscopic + hysteroscopic</td><td>Complex defects</td><td>Allows concurrent visualization of cavity and external repair</td></tr> </tbody> </table> </div>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_luteal-phase-deficiency', 'luteal-phase-deficiency', 'Luteal Phase Deficiency (LPD)', 'VI', 8, '<p><strong>A reproductive condition characterized by inadequate progesterone production or insufficient duration of the <a href="#luteal-phase" class="gloss-xref">luteal phase</a>,</strong> impairing endometrial preparation for implantation and early pregnancy support. Causes include impaired follicular development leading to insufficient <a href="#corpus-luteum" class="gloss-xref">corpus luteum</a> formation, hypothyroidism, <a href="#hyperprolactinemia" class="gloss-xref">hyperprolactinemia</a>, and GnRH pulsatility disruption. NaPro diagnosis is based on cycle-timed progesterone measurements aligned to the <a href="#peak-day" class="gloss-xref">Peak Day</a> and Peak+3 through Peak+11 series. Treatment involves ovulation induction (to optimize follicular development and subsequent corpus luteum function) and/or progesterone supplementation beginning 3 to 4 days after the Peak. LPD is a treatable hormonal pattern. With accurate cycle charting and targeted intervention, normal luteal function is restored in most cases. When the deficit originates specifically from inadequate corpus luteum output, see <a href="#corpus-luteum-deficiency" class="gloss-xref">Corpus Luteum Deficiency</a> (CLD) for the mechanism and targeted treatment approach.<sup class="cite-ref"><a href="#ref-44">44</a></sup><sup class="cite-ref"><a href="#ref-45">45</a></sup></p><p>Hilgers identified five distinct LPD subtypes, each requiring a different treatment strategy.<sup class="cite-ref"><a href="#ref-78">78</a></sup> Note that the NaPro post-Peak duration threshold is <strong>8 days</strong>, not the older 11-day <a href="#bbt" class="gloss-xref">BBT</a>-temperature-phase criterion from the Vollman/Jones era. That older standard measured a different endpoint from a different method. The 8-day post-Peak threshold applies here.</p><ul><li><strong>Type I:</strong> <a href="#post-peak-phase" class="gloss-xref">Post-Peak phase</a> of 8 days or fewer, combined with low end-luteal progesterone. Short luteal length with diminished hormone output throughout.</li><li><strong>Type II:</strong> Normal post-Peak duration, but suboptimal progesterone across the Peak+3 to Peak+11 window. Duration is adequate; integrated output is not.</li><li><strong>Type III:</strong> A late drop pattern defined by a 50% or greater fall in progesterone on Peak+9 or Peak+11 relative to the peak luteal value (Relative Progesterone Ratio below 50%). The corpus luteum collapses early before the luteal phase ends.</li><li><strong>Type IV:</strong> Early-luteal deficit with inadequate progesterone rise from Peak+3 to Peak+5. The corpus luteum fails to mount its initial output.</li><li><strong>Type V:</strong> Isolated luteal-phase estradiol deficit. Progesterone may be within range, but luteal estradiol is suboptimal. Treatment is <a href="#cert" class="gloss-xref">Cooperative Estrogen Replacement Therapy</a> (CERT). for progesterone-based protocols.</li></ul><p>The <strong>Peak+3 progesterone marker</strong> anchors ovulation confirmation in NaPro practice. A result of 2.3 ng/mL or above confirms that ovulation has occurred. A result of 3.0 ng/mL or above indicates that an absolute period of postovulation <a href="#infertility" class="gloss-xref">infertility</a> has begun. Values below these thresholds warrant evaluation for an ovulation disorder or early luteal deficit before any further cycle-timed treatment is planned. See Sonographic Ovulation Classification for the ultrasound correlates used alongside progesterone values to characterize ovulation quality.<sup class="cite-ref"><a href="#ref-81">81</a></sup></p>', 'LPD', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_luteal-phase', 'luteal-phase', 'Luteal Phase (LP)', 'VI', 9, '<p><strong>The period of the menstrual cycle following ovulation (post-peak) and preceding menstruation or implantation,</strong> typically lasting 12 to 16 days. During the luteal phase, the <a href="#corpus-luteum" class="gloss-xref">corpus luteum</a> secretes progesterone to prepare the endometrium for potential implantation. A short luteal phase (&lt;10 days) is associated with <a href="#infertility" class="gloss-xref">infertility</a> and impaired endometrial maturation.<sup class="cite-ref"><a href="#ref-44">44</a></sup></p>', 'LP', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_corpus-luteum', 'corpus-luteum', 'Corpus Luteum (CL)', 'VI', 10, '<p><strong>A temporary endocrine structure formed from the ruptured ovarian follicle after ovulation.</strong> The corpus luteum produces progesterone and estradiol during the <a href="#luteal-phase" class="gloss-xref">luteal phase</a>. If pregnancy occurs, <a href="#hcg" class="gloss-xref">hCG</a> from the implanting trophoblast rescues the corpus luteum, sustaining progesterone production until the placenta takes over (approximately 10 weeks). Inadequate CL function is the mechanism underlying <a href="#corpus-luteum-deficiency" class="gloss-xref">Corpus Luteum Deficiency</a> (CLD), a distinct subtype of <a href="#luteal-phase-deficiency" class="gloss-xref">luteal phase deficiency</a>.<sup class="cite-ref"><a href="#ref-44">44</a></sup></p>', 'CL', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_luf-syndrome', 'luf-syndrome', 'Luteinized Unruptured Follicle (LUF) Syndrome', 'VI', 11, '<p><strong>A condition in which the dominant follicle reaches maturity and undergoes apparent luteinization (progesterone production begins) without actually releasing the egg</strong> (anovulation occurs despite apparent cycle regularity). LUF can cause <a href="#unexplained-infertility" class="gloss-xref">unexplained infertility</a> despite normal menstrual cycles and is identified by follicle tracking ultrasound showing a persistent follicle that fails to collapse at expected ovulation time.<sup class="cite-ref"><a href="#ref-3">3</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_anovulatory-cycles', 'anovulatory-cycles', 'Anovulatory Cycles', 'VI', 12, '<p><strong>Menstrual cycles in which ovulation does not occur,</strong> potentially presenting as apparently normal or irregular periods. Associated with <a href="#pcos" class="gloss-xref">PCOS</a>, hypothalamic dysfunction, excessive exercise, low body weight, elevated prolactin, or thyroid disorders. Identified through cycle charting (absence of <a href="#post-peak-phase" class="gloss-xref">post-peak phase</a>), follicle tracking, or mid-luteal progesterone testing.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_shortened-luteal-phase', 'shortened-luteal-phase', 'Shortened Luteal Phase', 'VI', 13, '<p><strong>A <a href="#luteal-phase" class="gloss-xref">luteal phase</a> &lt;10 days in duration,</strong> associated with inadequate progesterone production, impaired endometrial maturation, and reduced fertility. Observed in conditions of hormonal imbalance, ovulation induction side effects, and physical stress.<sup class="cite-ref"><a href="#ref-3">3</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_tubal-factor-infertility', 'tubal-factor-infertility', 'Tubal Factor Infertility', 'VI', 14, '<p><strong><a href="#infertility" class="gloss-xref">Infertility</a> attributed to blocked, damaged, or functionally compromised fallopian tubes.</strong> Affects approximately 25 to 30% of women with infertility. Causes include prior pelvic inflammatory disease (PID), chlamydia, <a href="#endometriosis" class="gloss-xref">endometriosis</a>, <a href="#pelvic-adhesions" class="gloss-xref">pelvic adhesions</a>, or prior tubal surgery. <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> offers corrective surgical alternatives to <a href="#ivf" class="gloss-xref">IVF</a>: <a href="#fallopian-tube-recanalization" class="gloss-xref">fallopian tube recanalization</a> for proximal blockage, <a href="#tubal-ligation-reversal" class="gloss-xref">tubo-tubal anastomosis</a> for mid-segment disease, and neosalpingostomy/fimbrioplasty for distal disease.<sup class="cite-ref"><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_hydrosalpinx', 'hydrosalpinx', 'Hydrosalpinx', 'VI', 15, '<p><strong>A fluid-filled, distended, obstructed fallopian tube</strong>, typically the result of prior infection or <a href="#endometriosis" class="gloss-xref">endometriosis</a> causing complete distal tubal occlusion. Hydrosalpinges are associated with reduced <a href="#ivf" class="gloss-xref">IVF</a> success rates (the fluid may be embryotoxic). <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> options include neosalpingostomy (opening and repairing the tube) when tube quality is adequate, or salpingectomy if repair is not feasible.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_fallopian-tube-anatomy', 'fallopian-tube-anatomy', 'Fallopian Tube Anatomy Reference', 'VI', 16, '<p><strong>The fallopian tube has four anatomical segments, each relevant to <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> diagnosis and surgery:</strong><sup class="cite-ref"><a href="#ref-46">46</a></sup><sup class="cite-ref"><a href="#ref-47">47</a></sup></p> <ul> <li><strong>Interstitial (Intramural):</strong> Segment passing through the uterine wall, narrowest portion, most difficult to cannulate</li> <li><strong>Isthmus:</strong> Narrow segment adjacent to the uterus; site of distal ligation in many sterilization procedures; most favorable for anastomosis reversal</li> <li><strong>Ampulla:</strong> Widest, longest segment (5 cm, diameter up to 1 cm); most common site of fertilization and ectopic pregnancy<sup class="cite-ref"><a href="#ref-47">47</a></sup></li> <li><strong>Infundibulum / Fimbriae:</strong> Open, funnel-shaped distal end with finger-like fimbriae that sweep the ovulated egg into the tube; damage here causes <a href="#hydrosalpinx" class="gloss-xref">hydrosalpinx</a></li> </ul>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_pelvic-adhesions', 'pelvic-adhesions', 'Pelvic Adhesions (Scar Tissue)', 'VI', 17, '<p><strong>Bands of fibrous tissue that form between pelvic structures following inflammation, infection, <a href="#endometriosis" class="gloss-xref">endometriosis</a>, or prior surgery.</strong> Adhesions can distort pelvic anatomy, restrict tube and ovarian mobility, cause <a href="#chronic-pelvic-pain" class="gloss-xref">chronic pelvic pain</a>, and impair fertility. <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> treatment involves meticulous laparoscopic <a href="#adhesiolysis" class="gloss-xref">adhesiolysis</a> with anti-adhesion barrier placement.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_adenomyosis', 'adenomyosis', 'Adenomyosis', 'VI', 18, '<p><strong>A condition in which endometrial-like glands and stroma are present within the myometrium (uterine muscle wall),</strong> causing the uterus to enlarge and the junctional zone (the inner myometrium) to thicken. Adenomyosis is associated with heavy, painful periods and impaired fertility. A meta-analysis found women with adenomyosis had a 28% decreased probability of clinical pregnancy via <a href="#ivf" class="gloss-xref">IVF</a>/<a href="#icsi" class="gloss-xref">ICSI</a> compared to women without it, and higher miscarriage rates (OR 2.17). <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> approaches include hormonal management, and in selected cases, surgical resection of focal lesions.<sup class="cite-ref"><a href="#ref-48">48</a></sup><sup class="cite-ref"><a href="#ref-49">49</a></sup><sup class="cite-ref"><a href="#ref-50">50</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_uterine-fibroids', 'uterine-fibroids', 'Uterine Fibroids (Leiomyomas)', 'VI', 19, '<p><strong>Benign smooth muscle tumors of the uterus.</strong> Classification by location significantly affects fertility impact:</p> <ul> <li><strong>Submucosal:</strong> Protrude into the uterine cavity; most strongly associated with <a href="#infertility" class="gloss-xref">infertility</a> and pregnancy loss; treated hysteroscopically</li> <li><strong>Intramural:</strong> Within the uterine wall; may impair fertility when large or distorting</li> <li><strong>Subserosal:</strong> On the outer uterine surface; least impact on fertility</li> </ul> <p><a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> approach: <a href="#myomectomy" class="gloss-xref">myomectomy</a> (fertility-preserving fibroid removal) when fibroids are contributing to reproductive problems.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_uterine-septum', 'uterine-septum', 'Uterine Septum', 'VI', 20, '<p><strong>A congenital structural abnormality in which a fibromuscular wall (septum) divides part or all of the uterine cavity.</strong> Associated with increased risk of miscarriage (due to poor septum vascularization impairing implantation) and preterm labor. Treated hysteroscopically by incising and resecting the septum.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_ashermans-syndrome', 'ashermans-syndrome', 'Intrauterine Adhesions (Asherman''s Syndrome)', 'VI', 21, '<p><strong><a href="#pelvic-adhesions" class="gloss-xref">Scar tissue</a> within the uterine cavity, typically following uterine trauma</strong> (e.g., D&amp;C, <a href="#myomectomy" class="gloss-xref">myomectomy</a>, infection). Ranges from mild adhesions to obliteration of the cavity. Diagnosed by <a href="#sis" class="gloss-xref">SIS</a>, <a href="#hsg" class="gloss-xref">HSG</a>, or <a href="#hysteroscopy-operative" class="gloss-xref">hysteroscopy</a>. Treated by hysteroscopic <a href="#adhesiolysis" class="gloss-xref">adhesiolysis</a> with post-operative estrogen therapy to promote re-epithelialization.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_chronic-endometritis', 'chronic-endometritis', 'Chronic Endometritis (CE)', 'VI', 22, '<p><strong>A persistent, low-grade inflammatory condition of the endometrial lining caused by abnormal colonization of the endometrium by bacteria</strong> (e.g., Enterococcus, E. coli, Streptococcus). Often subclinical (no obvious symptoms). CE is significantly associated with recurrent implantation failure and <a href="#rpl" class="gloss-xref">recurrent pregnancy loss</a>. Diagnosed by office <a href="#hysteroscopy-operative" class="gloss-xref">hysteroscopy</a> (strawberry-pattern micropolypoid endometrium) confirmed by <a href="#cd138" class="gloss-xref">CD138 immunohistochemistry</a> on endometrial biopsy. Treated with targeted antibiotics (typically doxycycline, amoxicillin, or based on culture). A cohort study showed the biopsy/treatment group had significantly higher chances of pregnancy (HR 2.28) and live birth (HR 2.76) compared to hysteroscopy-only controls.<sup class="cite-ref"><a href="#ref-51">51</a></sup><sup class="cite-ref"><a href="#ref-26">26</a></sup></p>', 'CE', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_aps', 'aps', 'Antiphospholipid Syndrome (APS)', 'VI', 23, '<p><strong>An autoimmune condition in which antiphospholipid antibodies</strong> (including lupus anticoagulant, anticardiolipin antibodies (aCL), and anti-beta-2 glycoprotein I antibodies) cause a hypercoagulable state that can result in thrombosis and pregnancy complications including recurrent miscarriage, fetal loss, and stillbirth. Diagnosis requires both clinical criteria (vascular thrombosis or pregnancy morbidity) and laboratory criteria (confirmed antibodies on two occasions 12 or more weeks apart). <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> treatment: low-dose aspirin initiated preconceptionally, plus prophylactic-dose heparin (LMWH) from a positive pregnancy test through delivery. Multiple guidelines (EULAR, ESHRE, ACCP, ACOG) support this protocol.<sup class="cite-ref"><a href="#ref-52">52</a></sup><sup class="cite-ref"><a href="#ref-36">36</a></sup></p>', 'APS', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_autoimmune-thrombophilic', 'autoimmune-thrombophilic', 'Autoimmune/Thrombophilic Disorders (as RPL Causes)', 'VI', 24, '<p><strong>Beyond <a href="#aps" class="gloss-xref">APS</a>, <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> evaluates for inherited thrombophilias</strong> (Factor V Leiden, prothrombin mutation, protein C/S deficiency), natural killer (<a href="#nk-cells" class="gloss-xref">NK</a>) cell dysregulation, and systemic autoimmune conditions (antithyroid antibodies, antinuclear antibodies) in women with <a href="#rpl" class="gloss-xref">RPL</a>. Assessment guides individualized medical therapy. See <a href="#thrombophilia" class="gloss-xref">Clotting Disorder / Thrombophilia</a> for a full breakdown of inherited vs acquired subtypes, risk stratification, and treatment approach.<sup class="cite-ref"><a href="#ref-37">37</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_methylated-folate', 'methylated-folate', 'Methylated Folate (L-Methylfolate) and MTHFR', 'VI', 25, '<p><strong>Methylated folate (5-methyltetrahydrofolate, 5-MTHF) is the biologically active form of folate that participates directly in homocysteine remethylation, DNA synthesis, and the methylation reactions that matter most in early embryonic development.</strong> Most prenatal vitamins and fortified foods contain synthetic folic acid, not 5-MTHF. To become active, folic acid requires enzymatic conversion by methylenetetrahydrofolate reductase (MTHFR). Two common MTHFR gene variants, C677T and A1298C, reduce that enzyme''s activity. Reduced activity means impaired folate metabolism. Impaired folate metabolism can raise homocysteine, increase thrombophilic risk, and contribute to <a href="#rpl" class="gloss-xref">recurrent pregnancy loss</a> in affected individuals. This is not a rare edge case. MTHFR variants are common, and most patients who carry them have never been tested. <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> protocols specify L-methylfolate preconceptionally for women with known MTHFR variants, recurrent miscarriage, or elevated homocysteine. That means skipping the conversion step entirely and delivering the active form directly.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_varicocele', 'varicocele', 'Varicocele', 'VI', 26, '<p><strong>An abnormal dilation of the veins within the scrotum (pampiniform plexus),</strong> present in 15% of the male population and in approximately 35% of men evaluated for <a href="#infertility" class="gloss-xref">infertility</a>. Varicoceles raise scrotal temperature and increase oxidative stress, impairing spermatogenesis and increasing sperm DNA fragmentation. Varicocele repair (varicocelectomy) results in significant improvement in semen parameters in 60 to 80% of men, with natural pregnancy rates of 43% at one year and 69% at two years when female factors are excluded. Microsurgical subinguinal varicocelectomy is the preferred technique, associated with the highest spontaneous pregnancy rates and lowest complication rates.<sup class="cite-ref"><a href="#ref-53">53</a></sup><sup class="cite-ref"><a href="#ref-54">54</a></sup><sup class="cite-ref"><a href="#ref-55">55</a></sup><sup class="cite-ref"><a href="#ref-56">56</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_male-factor-infertility', 'male-factor-infertility', 'Male Factor Infertility', 'VI', 27, '<p><strong><a href="#infertility" class="gloss-xref">Infertility</a> attributable to male reproductive factors, estimated to contribute to approximately 50% of infertility cases when assessed comprehensively.</strong> <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> evaluates male partners with <a href="#semen-analysis" class="gloss-xref">semen analysis</a>, sperm DNA fragmentation testing, hormonal testing, and where indicated, surgical evaluation (<a href="#varicocele" class="gloss-xref">varicocele</a> assessment). Treatments include varicocele repair, lifestyle modification, <a href="#antioxidant-therapy" class="gloss-xref">antioxidant therapy</a>, hormonal correction, and in severe cases (<a href="#azoospermia" class="gloss-xref">azoospermia</a>), microsurgical sperm retrieval.<sup class="cite-ref"><a href="#ref-35">35</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_oat-syndrome', 'oat-syndrome', 'Oligospermia / Asthenospermia / Teratospermia', 'VI', 28, '<p><strong>Reduced sperm parameters defined by WHO reference values:</strong></p> <ul> <li><strong>Oligospermia:</strong> Sperm concentration &lt;16 million/mL</li> <li><strong>Asthenospermia:</strong> Progressive motility &lt;30%</li> <li><strong>Teratospermia:</strong> Normal morphology &lt;4% (Kruger strict criteria)</li> </ul> <p>Often co-exist; combined deficits are termed oligoasthenoteratospermia (OAT syndrome).</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_azoospermia', 'azoospermia', 'Azoospermia', 'VI', 29, '<p><strong>Complete absence of sperm in the ejaculate.</strong> Classified as:</p> <ul> <li><strong>Obstructive:</strong> Sperm production is normal but outflow is blocked (e.g., prior vasectomy, epididymal blockage); potentially correctable surgically</li> <li><strong>Non-obstructive:</strong> Impaired spermatogenesis (e.g., Sertoli cell-only syndrome, maturation arrest); may still have focal sperm production accessible via testicular sperm extraction (TESE)</li> </ul>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_oxidative-stress', 'oxidative-stress', 'Oxidative Stress / Reactive Oxygen Species (ROS)', 'VI', 30, '<p><strong>An imbalance between pro-oxidant species (ROS, reactive nitrogen species) and antioxidant defenses.</strong> At physiological levels, ROS play important roles in folliculogenesis, oocyte maturation, capacitation, and embryo development. Excess ROS, however, damages sperm DNA, impairs sperm motility, disrupts oocyte quality, damages embryos, and is linked to <a href="#endometriosis" class="gloss-xref">endometriosis</a>, <a href="#pcos" class="gloss-xref">PCOS</a>, <a href="#unexplained-infertility" class="gloss-xref">unexplained infertility</a>, recurrent miscarriage, and preeclampsia. <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> addresses oxidative stress through targeted antioxidant supplementation (vitamin C, E, CoQ10, zinc, selenium, L-carnitine, N-acetylcysteine), lifestyle modification (smoking cessation, weight management), and treatment of underlying conditions.<sup class="cite-ref"><a href="#ref-57">57</a></sup><sup class="cite-ref"><a href="#ref-58">58</a></sup><sup class="cite-ref"><a href="#ref-35">35</a></sup></p>', 'ROS', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_sperm-dna-fragmentation-extended', 'sperm-dna-fragmentation-extended', 'Sperm DNA Fragmentation Index (DFI): Extended', 'VI', 31, '<p><strong>High DFI (generally defined as &gt;25 to 30%) is independently associated with poor reproductive outcomes,</strong> including failed natural conception and <a href="#iui" class="gloss-xref">IUI</a>, and is a significant predictor of miscarriage. Treatment strategies in <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> include: antioxidant supplementation (reduces DFI and improves pregnancy rates); <a href="#varicocele" class="gloss-xref">varicocele</a> repair (meta-analysis: 3.37% mean DFI reduction post-repair); lifestyle changes (smoking cessation, weight optimization, stress reduction); treating genital tract infections; and shortened ejaculatory abstinence periods. Testicular sperm extraction yields sperm with lower DFI than ejaculated sperm in severe cases.<sup class="cite-ref"><a href="#ref-20">20</a></sup><sup class="cite-ref"><a href="#ref-21">21</a></sup><sup class="cite-ref"><a href="#ref-19">19</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_hormonal-abnormalities', 'hormonal-abnormalities', 'Hormonal Abnormalities', 'VI', 32, '<p><strong>Imbalances disrupting the menstrual cycle, ovulation, or early pregnancy.</strong> <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> diagnoses these through cycle-timed blood tests guided by <a href="#fertility-charting" class="gloss-xref">fertility charting</a>. Key hormones evaluated include:</p> <ul> <li><strong>FSH (<a href="#fsh" class="gloss-xref">Follicle-Stimulating Hormone</a>):</strong> Stimulates follicular development; elevated early-cycle FSH indicates <a href="#dor" class="gloss-xref">diminished ovarian reserve</a></li> <li><strong>LH (<a href="#lh" class="gloss-xref">Luteinizing Hormone</a>):</strong> Surge triggers ovulation; chronically elevated in <a href="#pcos" class="gloss-xref">PCOS</a></li> <li><strong>Estradiol (E2):</strong> Primary estrogen; supports follicular development, cervical mucus production, and endometrial proliferation</li> <li><strong>Progesterone (P4):</strong> <a href="#luteal-phase" class="gloss-xref">Luteal phase</a> hormone critical for endometrial receptivity and early pregnancy; measured at post-peak +7 in NaPro protocols</li> <li><strong>hCG (<a href="#hcg" class="gloss-xref">Human Chorionic Gonadotropin</a>):</strong> Produced by the implanting trophoblast; sustains the <a href="#corpus-luteum" class="gloss-xref">corpus luteum</a>; measured for early pregnancy confirmation and monitoring</li> <li><strong>Prolactin:</strong> Elevated levels (<a href="#hyperprolactinemia" class="gloss-xref">hyperprolactinemia</a>) suppress LH/FSH pulsatility, impairing ovulation and the luteal phase</li> <li><strong><a href="#amh" class="gloss-xref">AMH</a> (Anti-Mullerian Hormone):</strong> Secreted by ovarian granulosa cells; marker of <a href="#ovarian-reserve" class="gloss-xref">ovarian reserve</a>; low in diminished ovarian reserve (DOR)</li> </ul>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_hypothyroidism', 'hypothyroidism', 'Hypothyroidism / Subclinical Hypothyroidism', 'VI', 33, '<p><strong>Deficiency of thyroid hormone, most commonly due to autoimmune Hashimoto''s thyroiditis in iodine-sufficient regions.</strong> Even subclinical hypothyroidism (elevated <a href="#tsh" class="gloss-xref">TSH</a> with normal free T4) is associated with increased miscarriage risk, impaired fertility, and potential adverse pregnancy outcomes. <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> screens thyroid function and optimizes thyroid status before and during attempts at conception.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_hyperprolactinemia', 'hyperprolactinemia', 'Hyperprolactinemia', 'VI', 34, '<p><strong>Elevated serum prolactin levels, which suppress hypothalamic GnRH pulsatility, thereby reducing <a href="#lh" class="gloss-xref">LH</a> and <a href="#fsh" class="gloss-xref">FSH</a> secretion.</strong> Results in ovulatory dysfunction, <a href="#luteal-phase" class="gloss-xref">luteal phase</a> insufficiency, and impaired fertility. Common causes include pituitary microadenoma (prolactinoma), hypothyroidism, and medications. Treated with dopamine agonists (cabergoline, bromocriptine) or management of the underlying cause.<sup class="cite-ref"><a href="#ref-3">3</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_poi', 'poi', 'Premature Ovarian Insufficiency (POI)', 'VI', 35, '<p><strong>Loss of normal ovarian function before age 40,</strong> resulting in irregular or absent menstruation, <a href="#infertility" class="gloss-xref">infertility</a>, and hormonal deficiencies mimicking <a href="#menopause" class="gloss-xref">menopause</a>. Formerly known as Premature Ovarian Failure (POF); the contemporary term reflects that ovarian function may be intermittent rather than fully absent. Affects approximately 1% of women under 40. Causes include autoimmune, genetic (fragile X premutation), iatrogenic (chemotherapy, radiation), and idiopathic. <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> evaluation and management includes <a href="#hrt" class="gloss-xref">hormone replacement therapy</a>, fertility-preservation strategies, and treatment of underlying autoimmune conditions.<sup class="cite-ref"><a href="#ref-3">3</a></sup></p>', 'POI', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_dor', 'dor', 'Diminished Ovarian Reserve (DOR)', 'VI', 36, '<p><strong>A reduction in the quantity (and sometimes quality) of oocytes in the ovaries, leading to decreased fertility potential.</strong> Diagnosed by elevated <a href="#fsh" class="gloss-xref">FSH</a>, low <a href="#amh" class="gloss-xref">AMH</a>, and low <a href="#afc" class="gloss-xref">antral follicle count</a> (AFC) on ultrasound. DOR is age-related but can occur prematurely. <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> takes an aggressive diagnostic approach, evaluating for autoimmune, mitochondrial, inflammatory, and lifestyle contributors. See <a href="#ovarian-reserve" class="gloss-xref">Ovarian Reserve</a> for interpretation of reserve markers in clinical context.<sup class="cite-ref"><a href="#ref-3">3</a></sup></p>', 'DOR', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_insulin-resistance', 'insulin-resistance', 'Insulin Resistance / Metabolic Dysfunction', 'VI', 37, '<p><strong>A state of impaired cellular response to insulin, common in <a href="#pcos" class="gloss-xref">PCOS</a> (present in 50 to 70% of cases)</strong> and an independent contributor to ovulatory dysfunction, <a href="#infertility" class="gloss-xref">infertility</a>, and miscarriage. <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> addresses through dietary modification (low glycemic index diet), exercise, targeted supplementation (<a href="#myo-inositol" class="gloss-xref">myo-inositol</a>, alpha-lipoic acid, CoQ10), and medication (metformin) when indicated.<sup class="cite-ref"><a href="#ref-39">39</a></sup><sup class="cite-ref"><a href="#ref-3">3</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_secondary-infertility', 'secondary-infertility', 'Secondary Infertility', 'VI', 38, '<p><strong>Difficulty conceiving after a prior pregnancy.</strong> <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> re-evaluates comprehensively for new or evolving conditions, including C-section scar isthmocele, new-onset <a href="#endometriosis" class="gloss-xref">endometriosis</a> or adhesions, <a href="#chronic-endometritis" class="gloss-xref">chronic endometritis</a>, postpartum thyroiditis, or hormonal shifts.<sup class="cite-ref"><a href="#ref-3">3</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_unexplained-infertility', 'unexplained-infertility', 'Unexplained Infertility', 'VI', 39, '<p><strong>A clinical label given when no cause is identified through standard evaluation.</strong> <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> does not accept this as a final diagnosis but pursues deeper investigation including cycle-timed hormone panels, advanced sperm testing (SDF), <a href="#chronic-endometritis" class="gloss-xref">chronic endometritis</a> screening, immunologic testing, and laparoscopic assessment for subtle pelvic pathology.<sup class="cite-ref"><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_time-to-pregnancy', 'time-to-pregnancy', 'Time to Pregnancy (TTP)', 'VI', 40, '<p><strong>The number of menstrual cycles or months required to achieve a clinical pregnancy in a couple attempting conception.</strong> In the general fertile population, approximately 80% of couples conceive within six cycles and 90% within twelve cycles. TTP is an important framing concept in <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a>: procedural approaches are often reported as per-cycle success rates, whereas RRM is evaluated by cumulative outcomes across the full course of diagnosis and treatment. Published <a href="#naprotechnology-definition" class="gloss-xref">NaProTECHNOLOGY</a> cohort studies report cumulative live-birth rates at 24 and 36 months, reflecting the <a href="#restorative-as-a-principle" class="gloss-xref">restorative</a> time horizon in which underlying conditions are corrected and fertility resumes naturally.<sup class="cite-ref"><a href="#ref-10">10</a></sup><sup class="cite-ref"><a href="#ref-11">11</a></sup></p>', 'TTP', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_cervical-factor-infertility', 'cervical-factor-infertility', 'Cervical Factor Infertility', 'VI', 41, '<p><strong>Impaired cervical mucus production or quality, reducing sperm survival and transport.</strong> Contributing factors include low estrogen, prior cervical procedures (LEEP, cone biopsy), cervical inflammation, or mucus antibodies. <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> optimizes cervical mucus through hormonal support of estrogen adequacy and treatment of underlying hormonal deficiencies.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_poor-cervical-mucus', 'poor-cervical-mucus', 'Poor Cervical Mucus Production', 'VI', 42, '<p><strong>Cervical mucus that is insufficient in quantity, too thick, or does not exhibit fertile-quality characteristics</strong> (clear, stretchy, lubricative) near ovulation. Fertile mucus creates a protective environment for sperm, filtering defective sperm and providing a reservoir that sustains sperm for up to 5 days. Poor mucus production reduces the effective fertile window and impairs sperm ascent.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_endometrial-thickness', 'endometrial-thickness', 'Endometrial Thickness', 'VI', 43, '<p><strong>The measurement of the uterine lining as assessed by transvaginal ultrasound.</strong> Optimal endometrial thickness for implantation is generally 7 to 8 mm or more with a trilaminar (three-layer) pattern. Thin endometrium is associated with reduced implantation rates and is investigated for causes including prior uterine surgery, estrogen deficiency, poor blood flow, and <a href="#ashermans-syndrome" class="gloss-xref">Asherman''s syndrome</a>.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_endometrial-hyperplasia', 'endometrial-hyperplasia', 'Endometrial Hyperplasia', 'VI', 44, '<p><strong>A pathologic overgrowth of the endometrium characterized by increased number and crowding of endometrial glands, usually caused by prolonged estrogen exposure without sufficient progesterone (unopposed estrogen).</strong> This condition is not cancer, but some forms are precancerous and can progress to endometrial adenocarcinoma if untreated. Classified as "without atypia" (lower risk) or "atypical" (endometrial intraepithelial neoplasia, higher cancer risk). Often presents with abnormal uterine bleeding: heavy, frequent, irregular, or postmenopausal.</p> <p><strong><a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> relevance:</strong> Endometrial hyperplasia is driven by hormonal imbalance, especially chronic or intermittent anovulation and other causes of unopposed estrogen: <a href="#pcos" class="gloss-xref">PCOS</a>, obesity, estrogen-only therapy, and estrogen-secreting tumors. In RRM practice, cycle charting identifies anovulatory patterns early, and targeted progesterone therapy addresses the hormonal imbalance causing the overgrowth. For women with atypical hyperplasia who desire fertility, intensive progestin-based therapy with close surveillance may be an option before considering hysterectomy.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_window-of-implantation', 'window-of-implantation', 'Window of Implantation (WOI)', 'VI', 45, '<p><strong>The hormonally determined period during the secretory phase of the menstrual cycle</strong> (approximately cycle days 19 to 23 in a standard 28-day cycle) during which the endometrium is maximally receptive to embryo implantation. The WOI is precisely regulated by estrogen and progesterone and is displaced in approximately 20 to 25% of women with recurrent implantation failure, identifiable via <a href="#era" class="gloss-xref">ERA</a> testing.<sup class="cite-ref"><a href="#ref-24">24</a></sup><sup class="cite-ref"><a href="#ref-23">23</a></sup></p>', 'WOI', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_postpartum-fertility', 'postpartum-fertility', 'Postpartum Fertility Issues', 'VI', 46, '<p><strong>Fertility challenges arising in the postpartum period,</strong> including lactational amenorrhea (anovulation during breastfeeding due to prolactin elevation), retained placenta fragments, postpartum thyroiditis, hormonal dysregulation, and uterine scar defects (isthmocele from cesarean delivery). <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> offers specialized postpartum evaluations to identify and address these causes.<sup class="cite-ref"><a href="#ref-3">3</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_chronic-pelvic-pain', 'chronic-pelvic-pain', 'Chronic Pelvic Pain (CPP)', 'VI', 47, '<p><strong>Pelvic pain lasting 6 months or more,</strong> often involving multiple overlapping causes: gynecologic (<a href="#endometriosis" class="gloss-xref">endometriosis</a>, <a href="#adenomyosis" class="gloss-xref">adenomyosis</a>, <a href="#pelvic-adhesions" class="gloss-xref">pelvic adhesions</a>), musculoskeletal, urologic (interstitial cystitis), gastrointestinal, neuropathic, and psychosocial. <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> addresses gynecologic causes surgically (excision, <a href="#adhesiolysis" class="gloss-xref">adhesiolysis</a>) while recognizing the multidimensional nature of CPP and coordinating interdisciplinary care.</p>', 'CPP', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_lh', 'lh', 'Luteinizing Hormone (LH)', 'VI', 48, '<p>Luteinizing hormone is produced by the anterior pituitary gland. It drives two essential reproductive events: the mid-cycle LH surge, which triggers ovulation, and ongoing stimulation of the <a href="#corpus-luteum" class="gloss-xref">corpus luteum</a> to produce progesterone after ovulation.</p> <p>The LH surge is the signal that ovulation is imminent. Most urinary LH tests detect this surge 24 to 36 hours before follicle rupture. Timing intercourse or insemination to the surge is the basis of most ovulation-detection approaches. But surge detection is not the same as confirmed ovulation. In <a href="#luf-syndrome" class="gloss-xref">LUF</a> syndrome, the surge occurs normally while the follicle fails to rupture.</p> <p>Baseline LH levels on cycle day 2 or 3 are part of an <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> hormonal panel. An elevated LH-to-<a href="#fsh" class="gloss-xref">FSH</a> ratio is one finding consistent with <a href="#pcos" class="gloss-xref">PCOS</a>. Persistently elevated LH outside the expected surge window can reflect hypothalamic disruption, stress, or thyroid dysfunction.</p> <p>LH is also used therapeutically in RRM practice. Cycle-timed <a href="#hcg" class="gloss-xref">hCG</a> injections, which mimic the action of LH, can support corpus luteum function and assist with follicle release in cases where the endogenous surge is insufficient. This is a targeted, <a href="#restorative-as-a-principle" class="gloss-xref">restorative</a> intervention, not suppression.</p> <p>Without cycle chart data anchoring the timing, LH values lose much of their interpretive value. A single LH drawn without knowing where the patient is in her cycle is close to meaningless. Chart-based medicine avoids this problem.</p>', 'LH', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_fsh', 'fsh', 'Follicle-Stimulating Hormone (FSH)', 'VI', 49, '<p>Follicle-stimulating hormone is released by the anterior pituitary gland in response to signals from the hypothalamus. Its primary job is to stimulate the growth and maturation of ovarian follicles. Each month, FSH recruits a cohort of follicles, one of which typically becomes dominant and proceeds to ovulation.</p> <p>Basal FSH, drawn on cycle day 2, 3, or 4, is a standard component of an <a href="#ovarian-reserve" class="gloss-xref">ovarian reserve</a> panel. An elevated basal FSH signals that the pituitary is working harder than normal to recruit follicles. This elevation reflects reduced ovarian sensitivity, which is often an early indicator of declining reserve. The threshold for "elevated" varies by laboratory and by age.</p> <p>FSH is most useful in combination with other markers. A single elevated FSH in an otherwise normal cycle may be less meaningful than persistently elevated FSH across multiple cycles. Similarly, FSH must be read alongside <a href="#amh" class="gloss-xref">AMH</a>, <a href="#afc" class="gloss-xref">AFC</a>, and estradiol on the same draw date. Estradiol, if elevated on day 3, can suppress FSH artificially and mask the true reserve status.</p> <p>In men, FSH plays a parallel role: it stimulates the Sertoli cells of the testes, which support sperm production. Elevated FSH in a man with low sperm counts often signals primary testicular failure, meaning the testes are not responding adequately despite the pituitary''s signal. This finding changes the clinical approach significantly.</p> <p><a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> clinicians use FSH trends over time rather than single-point snapshots. A rising FSH in a woman in her mid-30s is a call to investigate and act, not to reassign her to a lower-prognosis category and recommend moving to donor egg.</p>', 'FSH', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_hcg', 'hcg', 'Human Chorionic Gonadotropin (hCG)', 'VI', 50, '<p>Human chorionic gonadotropin is produced by the developing trophoblast immediately after implantation. Its rise in early pregnancy is the basis of every pregnancy test. But hCG also has important therapeutic applications in <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> practice that extend well beyond diagnosis.</p> <p>Structurally, hCG closely resembles <a href="#lh" class="gloss-xref">LH</a>. It binds the same receptors. This means exogenous hCG can substitute for the mid-cycle LH surge to trigger ovulation, or it can provide ongoing <a href="#luteal-phase" class="gloss-xref">luteal phase</a> support after ovulation when the <a href="#corpus-luteum" class="gloss-xref">corpus luteum</a> needs reinforcement. Both uses are part of <a href="#restorative-as-a-principle" class="gloss-xref">restorative</a> care.</p> <p>In <a href="#rpl" class="gloss-xref">recurrent pregnancy loss</a>, low early-pregnancy hCG can reflect inadequate trophoblast support, which is often related to insufficient progesterone or underlying endometrial pathology. Targeted hCG supplementation in early pregnancy has been studied as a support strategy for women with a history of recurring loss. Quenby and Farquharson published a controlled trial examining this approach in 1994.<sup class="cite-ref"><a href="#ref-60">60</a></sup> The rationale is restorative: support the corpus luteum and the developing pregnancy rather than waiting for it to fail.</p> <p>hCG injections are also used in <a href="#naprotechnology-definition" class="gloss-xref">NaProTechnology</a> protocols to assist with ovulation induction and to support the luteal phase in women with documented deficiency. The timing is cycle-charted, not arbitrary. That precision is what makes the intervention restorative rather than generic hormonal loading.</p> <p>Serial quantitative hCG levels in early pregnancy are one of the most important early monitoring tools in RRM care. A doubling time that is slower than expected, or a plateau, prompts early investigation and intervention rather than a "wait and see" approach.</p>', 'hCG', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_nk-cells', 'nk-cells', 'Natural Killer (NK) Cells', 'VI', 51, '<p>Natural killer cells are a type of innate immune cell found throughout the body. In the uterine lining, a specialized population called uterine natural killer cells (uNK cells) plays a distinct role during implantation. These cells help remodel the spiral arteries of the uterus and regulate the immune environment at the maternal-fetal interface. They are not simply immune attackers. They are part of the architecture of a successful implantation.</p> <p>The relationship between NK cell activity and fertility is not straightforward. In <a href="#endometriosis" class="gloss-xref">endometriosis</a>, altered NK cell function has been documented: women with endometriosis show reduced cytotoxic activity against autologous endometrial cells, which may allow ectopic tissue to survive and proliferate.<sup class="cite-ref"><a href="#ref-61">61</a></sup> This immune dysregulation is one mechanism by which endometriosis may compromise implantation and contribute to both <a href="#infertility" class="gloss-xref">infertility</a> and recurrent loss.</p> <p>Peripheral blood NK cell testing measures circulating NK cells, not uterine NK cells. The two populations behave differently. Elevated peripheral NK cell counts do not reliably predict uterine NK cell dysfunction. Clinicians who draw conclusions about implantation failure from blood NK counts alone are measuring the wrong compartment.</p> <p><a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> clinicians who evaluate implantation failure look at the uterine environment directly, through endometrial biopsy, progesterone levels, and cycle timing, rather than relying on peripheral markers that have uncertain clinical correlation. Treating elevated NK cell counts on a blood test without diagnosing the underlying cause is not <a href="#restorative-as-a-principle" class="gloss-xref">restorative</a> medicine.</p> <p>When genuine immune dysregulation is contributing to implantation failure or recurrent loss, addressing the root condition matters. In endometriosis-related cases, excision of disease followed by targeted <a href="#luteal-phase" class="gloss-xref">luteal phase</a> support is the restorative approach. The goal is a uterine environment capable of sustaining pregnancy, not immune suppression layered on top of an unaddressed diagnosis.</p>', 'NK cells', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_pms', 'pms', 'Premenstrual Syndrome (PMS)', 'VI', 52, '<p><strong>Premenstrual syndrome (PMS)</strong> is a cyclical cluster of physical and emotional symptoms occurring in the <a href="#luteal-phase" class="gloss-xref">luteal phase</a> of the menstrual cycle and resolving with the onset of menstruation. Common symptoms include bloating, breast tenderness, mood changes, headache, and fatigue. These symptoms recur predictably in relation to ovulation and are absent in the follicular phase.</p> <p>Standard medicine often treats PMS as an inevitability. <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> treats it as a signal. PMS that is severe, recurrent, or cycle-consistent warrants investigation. In many cases, the underlying driver is <a href="#luteal-phase-deficiency" class="gloss-xref">luteal phase deficiency</a>: inadequate progesterone production by the <a href="#corpus-luteum" class="gloss-xref">corpus luteum</a> following ovulation. Thyroid dysfunction, particularly subclinical hypothyroidism, is another frequent and underdiagnosed contributor.</p> <p>RRM clinicians evaluate cycle charts alongside serum hormone levels drawn at timed intervals across the luteal phase. This approach distinguishes PMS driven by hormonal deficiency from PMDD (premenstrual dysphoric disorder), a more severe, psychiatrically classified condition. The distinction matters because the treatment pathways differ.<sup class="cite-ref"><a href="#ref-66">66</a></sup></p> <p>Hilgers documented that women with PMS show significantly decreased luteal phase progesterone, estradiol, and beta-endorphin levels compared to controls, and that cycle-timed hormonal support achieved marked improvement in the majority of cases.<sup class="cite-ref"><a href="#ref-67">67</a></sup></p> <p>PMS is information. It points toward a hormonal pattern. The clinician''s job is to read it.</p>', 'PMS', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_tsh', 'tsh', 'Thyroid-Stimulating Hormone (TSH)', 'VI', 53, '<p><strong>Thyroid-stimulating hormone (TSH)</strong> is secreted by the anterior pituitary gland and drives the thyroid gland to produce thyroxine (T4) and triiodothyronine (T3). When thyroid output falls, TSH rises. When output is high, TSH falls. It is the primary clinical marker for thyroid function.</p> <p>Standard laboratory reference ranges for TSH span roughly 0.5 to 4.5 mIU/L. "Within normal limits" is not the same as "optimal for reproduction." Research published in the <em>Journal of Clinical Endocrinology and Metabolism</em> found that higher TSH levels within the standard normal range were independently associated with <a href="#unexplained-infertility" class="gloss-xref">unexplained infertility</a>.<sup class="cite-ref"><a href="#ref-68">68</a></sup> For women trying to conceive, many <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> clinicians target a TSH below 2.5 mIU/L, because subclinical hypothyroidism at higher values within the standard range carries documented risk for anovulation, <a href="#luteal-phase" class="gloss-xref">luteal phase</a> insufficiency, and miscarriage.</p> <p>The practical implication: a TSH of 3.8 mIU/L may not trigger treatment from a general practitioner. An RRM clinician may read that same value as a contributor to cycle dysfunction and act on it.</p> <p>TSH should be evaluated alongside free T4, free T3, and thyroid antibody levels when reproductive concerns are present. Autoimmune thyroid disease can affect fertility even when TSH remains near-normal.</p>', 'TSH', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_bmi', 'bmi', 'Body Mass Index (BMI)', 'VI', 54, '<p><strong>Body mass index (BMI)</strong> is a calculation of weight relative to height (kg/m²). It functions as a population-level screening tool, not a precise measure of individual metabolic health. BMI does not account for muscle mass, body composition, fat distribution, or ethnicity-based variation. Clinicians use it as one data point, not a verdict.</p> <p>At the extremes, BMI has measurable effects on reproductive function. A BMI below 18.5 can suppress the hypothalamic-pituitary axis, reducing gonadotropin release and preventing ovulation. A BMI above 30 drives insulin resistance and elevated androgens, both of which blunt ovulatory signaling, particularly in women with <a href="#pcos" class="gloss-xref">PCOS</a>. Research confirms that both low and high preconception BMI elevate subfertility risk independently of other factors.<sup class="cite-ref"><a href="#ref-69">69</a></sup> Metabolic contributors to fertility disorders deserve systematic evaluation rather than a single number.<sup class="cite-ref"><a href="#ref-70">70</a></sup></p> <p><a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> does not moralize about weight. It identifies the metabolic pathway affecting ovulation and addresses it directly. Is this hypothalamic suppression from under-fueling? Is this insulin-mediated androgen excess? The answer changes the clinical approach.</p>', 'BMI', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_molimina', 'molimina', 'Molimina', 'VI', 55, '<p><strong>Molimina</strong> (from Latin: exertions) describes the cluster of mild physiological symptoms that occur in the late <a href="#luteal-phase" class="gloss-xref">luteal phase</a> as a direct result of progesterone production by the <a href="#corpus-luteum" class="gloss-xref">corpus luteum</a>. Typical symptoms include mild breast tenderness, a sense of pelvic fullness, subtle fluid retention, and slight shifts in energy or mood. These symptoms appear predictably before menstruation and resolve when it begins.</p> <p>Molimina is a positive diagnostic sign, not a pathological condition. When a patient reports these symptoms in a predictable cycle pattern correlated with peak-day timing, the clinician knows ovulation occurred and that a functioning corpus luteum formed. No serum progesterone test is required to confirm this. The chart confirms it.</p> <p>This distinguishes molimina from <a href="#pms" class="gloss-xref">PMS</a>. PMS is a symptom complex that often reflects hormonal imbalance, particularly <a href="#luteal-phase-deficiency" class="gloss-xref">luteal phase deficiency</a>. Molimina reflects normal luteal progesterone activity. Mild premenstrual awareness is not a problem to be eliminated. It is the body reporting that ovulation happened.</p> <p>In <a href="#naprotechnology-definition" class="gloss-xref">NaProTechnology</a>-informed practice, the Creighton Model chart captures the cycle pattern across months. The presence of consistent molimina, correlated with <a href="#peak-day" class="gloss-xref">peak day</a>, is clinical information. Absence of molimina in a patient who previously experienced it can signal a deteriorating luteal phase.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_clinical-endorphin-deficiency', 'clinical-endorphin-deficiency', 'Clinical Endorphin Deficiency', 'VI', 56, '<p><strong>A state of insufficient endogenous opioid (endorphin) activity that disrupts hormonal signaling involved in ovulation, immune regulation, and reproductive function.</strong> Endorphins modulate the hypothalamic-pituitary axis, influencing GnRH pulsatility and downstream <a href="#lh" class="gloss-xref">LH</a> and <a href="#fsh" class="gloss-xref">FSH</a> secretion. Deficient endorphin tone is associated with irregular cycles, poor follicular response, and implantation failure in some populations.</p> <p>The condition lacks a standardized diagnostic threshold. In <a href="#neofertility" class="gloss-xref">NeoFertility</a> protocols, clinical endorphin deficiency is inferred from the clinical pattern: reduced ovarian responsiveness, thin endometrium, and failure to conceive despite otherwise normal-appearing diagnostics. <a href="#ldn" class="gloss-xref">Low-dose naltrexone</a> at 4.5 mg nightly addresses this by transiently blocking opioid receptors. The temporary blockade triggers a compensatory rebound in endorphin production. See Low-Dose Naltrexone (LDN) for the mechanism and published outcomes data.</p> <p>This is an area where <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> practice is ahead of the published literature. The physiological rationale is established. Large controlled trials do not yet exist. Clinicians using LDN for this indication are making a clinically reasoned judgment from mechanism, case series, and cohort data. That is honest medicine. It is also different from saying the question is settled.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_thrombophilia', 'thrombophilia', 'Clotting Disorder / Thrombophilia', 'VI', 57, '<p><strong>A heritable or acquired tendency toward excessive blood clotting that can impair placentation and contribute to pregnancy loss.</strong> Inherited thrombophilias include Factor V Leiden mutation, prothrombin G20210A mutation, and protein C, protein S, or antithrombin deficiency. Acquired thrombophilia includes <a href="#aps" class="gloss-xref">antiphospholipid syndrome</a> (APS), which involves antibodies that interfere with phospholipid-binding proteins critical to normal coagulation and placental function.</p> <p>The mechanism of pregnancy loss is primarily vascular. Microthrombi in the early placental vasculature impair the implantation bed and restrict blood flow to the developing embryo. Not all inherited thrombophilias carry the same risk level. Factor V Leiden heterozygosity confers modest increased risk; homozygous mutations and combined thrombophilias carry substantially higher risk.</p> <p><a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> evaluation for thrombophilic conditions is part of the standard <a href="#rpl" class="gloss-xref">RPL</a> workup and is also considered in women with a history of placental abruption, late fetal loss, or unexplained preterm birth. Treatment, when indicated, typically involves low-molecular-weight heparin during pregnancy, sometimes combined with low-dose aspirin. See <a href="#autoimmune-thrombophilic" class="gloss-xref">Autoimmune/Thrombophilic Disorders</a> for the full RPL context and evaluation protocols.<sup class="cite-ref"><a href="#ref-75">75</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_early-pregnancy-loss', 'early-pregnancy-loss', 'Early Pregnancy Loss', 'VI', 58, '<p><strong>The loss of a clinically confirmed pregnancy before 13 weeks of gestation.</strong> Early pregnancy loss is the most common complication of pregnancy, occurring in approximately 10 to 20% of confirmed pregnancies. The majority result from chromosomal abnormalities in the embryo. But recurrent loss, defined as two or more losses, warrants systematic evaluation for treatable maternal factors.</p> <p>This distinction is central to <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a>''s approach. A single loss is statistically common and often attributable to sporadic chromosomal error. Two or more losses define <a href="#rpl" class="gloss-xref">Recurrent Pregnancy Loss</a> (RPL), a separate clinical entity with a different differential diagnosis and a different evaluation protocol. Conflating a single loss with recurrent loss understates the clinical significance of the pattern and delays workup.</p> <p>Treatable causes of early pregnancy loss include progesterone deficiency, thyroid dysfunction, uterine abnormalities (septum, submucous fibroids, isthmocele), <a href="#aps" class="gloss-xref">antiphospholipid syndrome</a>, inherited thrombophilias, and <a href="#chronic-endometritis" class="gloss-xref">chronic endometritis</a>. RRM protocols address these systematically rather than attributing losses to chance and advising the couple to try again without investigation.</p> <p>Early pregnancy loss is distinguished from biochemical pregnancy (positive <a href="#hcg" class="gloss-xref">hCG</a> with no ultrasound confirmation) and from stillbirth (fetal loss at or after 20 weeks). Each carries its own evaluation framework. RRM does not collapse these into a single category.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_corpus-luteum-deficiency', 'corpus-luteum-deficiency', 'Corpus Luteum Deficiency (CLD)', 'VI', 59, '<p><strong>Insufficient progesterone production from the <a href="#corpus-luteum" class="gloss-xref">corpus luteum</a> during the <a href="#luteal-phase" class="gloss-xref">luteal phase</a>,</strong> resulting in inadequate endometrial support for implantation and early pregnancy. CLD is a structural problem at the level of the corpus luteum itself. Clinicians distinguish CLD from <a href="#luteal-phase-deficiency" class="gloss-xref">Luteal Phase Deficiency</a> (LPD): LPD describes the hormonal pattern (low or short progesterone output), while CLD names the anatomical source of that deficit.</p> <p>The corpus luteum forms from the ruptured follicle after ovulation. Its capacity to produce progesterone depends heavily on how well the follicle developed beforehand. A follicle that was small at ovulation, grew slowly, or was triggered prematurely produces a suboptimal corpus luteum. Treating luteal phase deficiency with progesterone supplementation alone, without addressing the follicular phase problem, manages the downstream effect but leaves the upstream cause untreated.</p> <p><a href="#naprotechnology-definition" class="gloss-xref">NaProTechnology</a> identifies CLD through cycle-timed progesterone profiling: multiple measurements taken across the luteal phase rather than a single mid-luteal draw. A flat or declining progesterone curve identifies corpus luteum failure specifically. Treatment in <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> practice combines optimizing follicular development (ovulation induction when indicated) with post-Peak progesterone support timed to the chart.</p>', 'CLD', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_empty-follicle-syndrome', 'empty-follicle-syndrome', 'Empty Follicle Syndrome (EFS)', 'VI', 60, '<p><strong>Empty Follicle Syndrome (EFS) is an ovulation disorder in which the dominant follicle reaches mature size and ruptures appropriately, but no cumulus oophorus is sonographically visible on serial ultrasound.</strong><sup class="cite-ref"><a href="#ref-78">78</a></sup> The cumulus oophorus is the cellular complex that surrounds and carries the oocyte. Its absence on imaging indicates the follicle contained no retrievable egg.</p><p>The term was first described by Coulam in 1986 in the context of <a href="#ivf" class="gloss-xref">IVF</a> aspiration cycles. Hilgers adapted the concept for spontaneous, non-stimulated cycles using serial <a href="#follicle-maturation-study" class="gloss-xref">follicle maturation study</a> ultrasound. In that setting, EFS is diagnosed when the dominant follicle achieves a mature mean diameter, ruptures with appropriate follicular collapse, but cumulus visualization is absent across both longitudinal and transverse imaging planes.<sup class="cite-ref"><a href="#ref-78">78</a></sup></p><p>EFS reduces fecundity even when the <a href="#creighton-model" class="gloss-xref">CrMS</a> chart shows a clear <a href="#peak-day" class="gloss-xref">Peak Day</a> and post-Peak progesterone appears adequate. The follicle performs its external function but does not deliver a viable oocyte. It sits within Hilgers'' <a href="#sonographic-ovulation-classification" class="gloss-xref">sonographic classification of ovulation disorders</a> as a distinct, diagnosable entity.</p><p>Diagnosis requires serial follicular ultrasound. Chart observation alone cannot detect it. For couples with otherwise <a href="#unexplained-infertility" class="gloss-xref">unexplained infertility</a>, EFS is one of several ovulation-level diagnoses that imaging can reveal and <a href="#restorative-as-a-principle" class="gloss-xref">restorative</a> protocols can address.</p>', 'EFS', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_immature-follicle-syndrome', 'immature-follicle-syndrome', 'Immature Follicle Syndrome (IFS)', 'VI', 61, '<p><strong>Immature Follicle Syndrome (IFS) is an ovulation disorder in which the dominant follicle ruptures before reaching the maturity threshold, with mean follicular diameter below 1.90 cm at the time of collapse.</strong><sup class="cite-ref"><a href="#ref-78">78</a></sup> A follicle that ruptures too early cannot reliably release a fully developed oocyte or support adequate <a href="#corpus-luteum" class="gloss-xref">corpus luteum</a> formation.</p><p>Hilgers classified IFS as a named anatomic ovulation defect within his <a href="#sonographic-ovulation-classification" class="gloss-xref">sonographic classification of ovulation disorders</a>. Serial <a href="#follicle-maturation-study" class="gloss-xref">follicle maturation study</a> ultrasound across the periovulatory window makes the diagnosis: the dominant follicle collapses before reaching the 1.90 cm threshold.<sup class="cite-ref"><a href="#ref-78">78</a></sup> IFS often accompanies abnormal <a href="#peak-day" class="gloss-xref">Peak Day</a> timing on the <a href="#creighton-model" class="gloss-xref">CrMS</a> chart and low Peak +3 progesterone, both indicators that the cycle did not complete normal follicular development.</p><p>The consequences extend beyond that single cycle. Premature rupture produces a smaller, less functional corpus luteum. That structural deficit drives <a href="#luteal-phase-deficiency" class="gloss-xref">luteal phase deficiency</a> and elevates the risk of <a href="#early-pregnancy-loss" class="gloss-xref">early pregnancy loss</a> even when conception occurs.</p><p>IFS is treatable. <a href="#restorative-as-a-principle" class="gloss-xref">Restorative</a> ovulation induction protocols target follicular maturation directly, supporting the follicle to full size before rupture. Serial ultrasound confirms the response. The defect is identified, measured, and corrected.</p>', 'IFS', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_partial-rupture-syndrome', 'partial-rupture-syndrome', 'Partial Rupture Syndrome (PRS)', 'VI', 62, '<p><strong>Partial Rupture Syndrome (PRS) is an ovulation disorder in which the dominant follicle collapses by 7.5 mm or less over a 24-hour period, releasing the oocyte incompletely rather than fully rupturing.</strong><sup class="cite-ref"><a href="#ref-78">78</a></sup></p><p>PRS occupies a specific position in Hilgers'' <a href="#sonographic-ovulation-classification" class="gloss-xref">sonographic classification of ovulation disorders</a>. It is distinct from <a href="#luf-syndrome" class="gloss-xref">Luteinized Unruptured Follicle Syndrome</a>, in which the follicle does not rupture at all, and from <a href="#delayed-rupture-syndrome" class="gloss-xref">Delayed Rupture Syndrome</a>, in which complete collapse extends across 48 hours. In PRS, rupture initiates but stalls: follicular diameter decreases, but the collapse is insufficient to fully expel the oocyte-cumulus complex.<sup class="cite-ref"><a href="#ref-78">78</a></sup></p><p>The <a href="#corpus-luteum" class="gloss-xref">corpus luteum</a> that forms from a partially ruptured follicle is structurally compromised. Subnormal corpus luteum function follows, with reduced progesterone output across the <a href="#post-peak-phase" class="gloss-xref">post-Peak phase</a>. Fecundity in affected cycles is reduced even when the <a href="#creighton-model" class="gloss-xref">CrMS</a> chart appears to show normal ovulation timing.</p><p>Diagnosis requires serial <a href="#follicle-maturation-study" class="gloss-xref">follicle maturation study</a> ultrasound with measurements at 24-hour intervals across the periovulatory window. Chart observation alone cannot distinguish PRS from a normal ovulatory cycle. Imaging names the defect. <a href="#restorative-as-a-principle" class="gloss-xref">Restorative</a> protocols then address it at its source.</p>', 'PRS', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_delayed-rupture-syndrome', 'delayed-rupture-syndrome', 'Delayed Rupture Syndrome (DRS)', 'VI', 63, '<p><strong>Delayed Rupture Syndrome (DRS) is an ovulation disorder in which the dominant follicle ruptures gradually across approximately 48 hours rather than completing collapse within 24 hours.</strong><sup class="cite-ref"><a href="#ref-78">78</a></sup></p><p>On serial <a href="#follicle-maturation-study" class="gloss-xref">follicle maturation study</a> ultrasound, DRS presents as partial collapse on the first observation day, followed by completion of follicular collapse on the second. That two-day rupture pattern distinguishes it from normal ovulation and from <a href="#partial-rupture-syndrome" class="gloss-xref">Partial Rupture Syndrome</a>, which stalls within 24 hours and does not complete. It is also distinct from <a href="#luf-syndrome" class="gloss-xref">Luteinized Unruptured Follicle Syndrome</a>, in which no rupture occurs.<sup class="cite-ref"><a href="#ref-78">78</a></sup></p><p>DRS sits within Hilgers'' <a href="#sonographic-ovulation-classification" class="gloss-xref">sonographic classification of ovulation disorders</a> as a named entity associated with periovulatory endocrine abnormalities. Protracted rupture reflects dysregulation of the <a href="#lh" class="gloss-xref">LH</a> surge and follicular response. <a href="#corpus-luteum" class="gloss-xref">Corpus luteum</a> quality and post-Peak progesterone are affected in proportion to the timing disruption.</p><p>Fecundity is reduced in DRS cycles. <a href="#restorative-as-a-principle" class="gloss-xref">Restorative</a> interventions targeting follicular maturation and ovulation support can normalize rupture timing when the underlying endocrine defect is identified and treated.</p>', 'DRS', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_afollicularism', 'afollicularism', 'Afollicularism (AF)', 'VI', 64, '<p><strong>Afollicularism is an ovulation disorder in which a woman''s cycle proceeds with regular menses but serial follicular ultrasound shows no follicle ever reaching the dominant threshold: mean follicular diameter never exceeds 1.4 cm.</strong><sup class="cite-ref"><a href="#ref-78">78</a></sup> The cycle appears normal by external observation. No ovulation occurs.</p><p>Afollicularism sits within Hilgers'' <a href="#sonographic-ovulation-classification" class="gloss-xref">sonographic classification of ovulation disorders</a> as one of the most severe entries: a cycle with no functional follicular development at all. Cycle length, bleeding pattern, and <a href="#creighton-model" class="gloss-xref">CrMS</a> charting cannot detect it. The <a href="#peak-day" class="gloss-xref">Peak Day</a> may appear on the chart. Menses arrive on schedule. No dominant follicle formed.<sup class="cite-ref"><a href="#ref-78">78</a></sup></p><p>Hilgers'' cohort data showed zero spontaneous pregnancies in afollicular cycles.<sup class="cite-ref"><a href="#ref-78">78</a></sup> That outcome reinforces a core diagnostic principle in <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a>: <a href="#unexplained-infertility" class="gloss-xref">unexplained infertility</a> is almost always undiagnosed <a href="#infertility" class="gloss-xref">infertility</a>. Afollicularism is a clear example. The diagnosis is invisible without a <a href="#follicle-maturation-study" class="gloss-xref">follicle maturation study</a>. With imaging, it is definitive.</p><p>Identifying afollicularism opens a <a href="#restorative-as-a-principle" class="gloss-xref">restorative</a> pathway. Ovulation induction under RRM protocols targets the absent follicular response directly. The cause is named. Treatment follows the diagnosis.</p>', 'AF', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_follicular-deficiency', 'follicular-deficiency', 'Follicular Deficiency', 'VI', 65, '<p><strong>Follicular Deficiency is an ovulatory dysfunction in which the dominant follicle may reach adequate size and rupture on schedule, but it does not produce sufficient hormonal output to support normal fertilization and implantation. The defect is functional, not anatomic.</strong> Unlike the four named ovulation disorders in Hilgers'' sonographic classification (luteinized unruptured follicle, <a href="#immature-follicle-syndrome" class="gloss-xref">immature follicle syndrome</a>, <a href="#afollicularism" class="gloss-xref">afollicularism</a>, and <a href="#empty-follicle-syndrome" class="gloss-xref">empty follicle syndrome</a>), follicular deficiency does not announce itself on ultrasound. The follicle looks normal. It ruptures. The problem is invisible to imaging and only becomes legible through the hormonal record the cycle leaves behind.<sup class="cite-ref"><a href="#ref-78">78</a></sup></p><p>The diagnostic window is the post-Peak hormonal picture. In <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> practice, clinicians evaluate Peak +7 estradiol and progesterone as integrated markers of what the follicle actually produced. A well-functioning follicle generates a <a href="#corpus-luteum" class="gloss-xref">corpus luteum</a> capable of sustaining adequate mid-luteal hormone levels. When Peak +7 estradiol falls below the target range, or when progesterone is suboptimal despite a cycle that appeared ovulatory on all other measures (clear <a href="#peak-day" class="gloss-xref">Peak Day</a>, appropriate temperature shift, normal <a href="#mucus-pattern" class="gloss-xref">mucus pattern</a>), follicular deficiency is the explanation the chart cannot itself provide. Either marker can be affected. Both point to the same upstream failure: a follicle that completed its visible task without completing its physiological one. Serial <a href="#follicle-maturation-study" class="gloss-xref">follicle maturation study</a> ultrasound, read alongside cycle-timed blood work, gives clinicians the combined picture needed to make the diagnosis.</p><p>The downstream consequence is <a href="#luteal-phase-deficiency" class="gloss-xref">luteal phase deficiency</a>. The corpus luteum is only as capable as the follicle that preceded it. A follicle that produced inadequate estradiol cannot generate a corpus luteum with full progesterone-secreting capacity, and luteal support that addresses progesterone alone does not resolve the problem at its source. This relationship becomes clinically visible in cycles where luteal-phase hormonal rescue is attempted and fails to restore normal Peak +7 values. That failure pattern is diagnostic. If the follicle did not function adequately, the resulting corpus luteum has limited capacity to respond. The deficit begins in the follicular phase and propagates forward. Follicular deficiency is a recognized hidden contributor to luteal insufficiency, recurrent <a href="#early-pregnancy-loss" class="gloss-xref">early pregnancy loss</a>, and short <a href="#luteal-phase" class="gloss-xref">luteal phase</a> in cycles that otherwise carry no obvious diagnosis.</p><p>The <a href="#restorative-as-a-principle" class="gloss-xref">restorative</a> principle follows directly from the diagnosis. Chasing the luteal phase while the follicular phase remains unaddressed is treating a symptom, not a cause. RRM clinicians target follicular development itself: supporting the follicular phase so the follicle that forms is capable of sustaining the cycle that follows. The corpus luteum, the luteal hormones, and the implantation environment are all downstream of a follicle that functions. Name the cause. Treat the follicle. The rest of the cycle can follow.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_menopause', 'menopause', 'Menopause', 'VI', 66, '<p><strong>Menopause is the permanent cessation of menstrual cycles due to the natural aging of the ovaries.</strong> The average age of onset is approximately 50 years, with a normal physiologic range of 37 to 56 years.<sup class="cite-ref"><a href="#ref-78">78</a></sup> By clinical convention, menopause is confirmed when 12 consecutive months pass without a menstrual period.</p><p>Menopause is a physiologic transition, not a disease. The hormonal changes it involves, including shifts in estradiol, progesterone, <a href="#fsh" class="gloss-xref">FSH</a>, and <a href="#lh" class="gloss-xref">LH</a>, have downstream effects on cardiovascular risk, bone density, and neurological function that <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> clinicians evaluate individually.<sup class="cite-ref"><a href="#ref-78">78</a></sup> When menopause occurs before age 40, it meets the criteria for <a href="#poi" class="gloss-xref">Premature Ovarian Insufficiency</a> (POI) and is managed differently. </p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_premenopause', 'premenopause', 'Premenopause', 'VI', 67, '<p><strong>Premenopause is the period leading up to <a href="#menopause" class="gloss-xref">menopause</a>; in <a href="#naprotechnology-definition" class="gloss-xref">NaProTECHNOLOGY</a> practice, it applies to any woman age 40 or older.</strong> This is an explicitly practical, age-based working definition rather than a marker of any specific physiologic threshold.<sup class="cite-ref"><a href="#ref-78">78</a></sup> Its utility is clinical: it prompts <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> clinicians to consider the menopausal transition in evaluation and cycle interpretation for women in this age range.</p><p>The premenopausal years involve gradual hormonal shifts, changes in cycle length and <a href="#mucus-pattern" class="gloss-xref">mucus pattern</a>, and declining fertility. <a href="#creighton-model" class="gloss-xref">CrMS</a> charting captures these changes over time, providing data that guides clinical decisions.<sup class="cite-ref"><a href="#ref-78">78</a></sup> This term is distinct from <a href="#perimenopause" class="gloss-xref">Perimenopause</a>, which describes the physiologic transition itself rather than an age boundary. </p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_perimenopause', 'perimenopause', 'Perimenopause', 'VI', 68, '<p><strong>Perimenopause is the physiologic transition period during which ovarian function declines and the menstrual cycle becomes irregular, ending at confirmed <a href="#menopause" class="gloss-xref">menopause</a>.</strong> It is defined by biology, not by age. Cycle lengths may lengthen or shorten, mucus patterns shift, and hormone levels fluctuate, often producing vasomotor symptoms before periods stop entirely.<sup class="cite-ref"><a href="#ref-78">78</a></sup></p><p>In <a href="#naprotechnology-definition" class="gloss-xref">NaProTECHNOLOGY</a>, the term <a href="#premenopause" class="gloss-xref">Premenopause</a> serves as a parallel working definition for women age 40 and older, regardless of whether perimenopause has begun. Both terms describe the same general phase of life from different angles: perimenopause is the physiologic event; premenopause is the practical clinical label. <a href="#creighton-model" class="gloss-xref">CrMS</a> charting during this period captures real-time changes in cycle length, Peak-type mucus frequency, and <a href="#post-peak-phase" class="gloss-xref">post-Peak phase</a> length, providing objective data that guides hormonal evaluation and support decisions.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_mature_reproductive_age', 'mature-reproductive-age', 'Mature Reproductive Age', 'VI', 69, '<p><strong>Mature reproductive age, in <a href="#naprotechnology-definition" class="gloss-xref">NaProTECHNOLOGY</a>, refers to women age 35 and older who are pursuing pregnancy.</strong> The average age in Hilgers'' described population is 37.9 years.<sup class="cite-ref"><a href="#ref-78">78</a></sup> The term acknowledges the clinical reality of declining fertility potential with age without treating older maternal age as a barrier to <a href="#restorative-as-a-principle" class="gloss-xref">restorative</a> care.</p><p>NaProTECHNOLOGY diagnosis and treatment in this population focuses on identifying and correcting the underlying causes of subfertility. Outcomes reported in this group, including lower rates of multiple pregnancy, preterm birth, and low birth weight compared to published <a href="#art" class="gloss-xref">ART</a> outcomes, reflect the diagnostic depth NaPro applies to couples who might otherwise receive a direct referral to assisted reproduction.<sup class="cite-ref"><a href="#ref-78">78</a></sup> </p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_reproductive-endocrinology', 'reproductive-endocrinology', 'Reproductive Endocrinology', 'VII', 0, '<p><strong>The study of hormonal regulation of reproduction, encompassing the hypothalamic-pituitary-gonadal axis and its downstream effects on ovulation, implantation, and pregnancy maintenance.</strong> In <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a>, reproductive endocrinology is practiced with cycle-timed hormone evaluation (blood draws ordered at specific cycle phases identified by charting) rather than single random draws that miss dynamic hormonal patterns. This discipline is core to all RRM approaches, providing the diagnostic foundation for targeted medical treatment.<sup class="cite-ref"><a href="#ref-3">3</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_reproductive-immunology', 'reproductive-immunology', 'Reproductive Immunology', 'VII', 1, '<p><strong>The investigation of the immune system''s role in implantation failure, recurrent miscarriage, and conditions such as <a href="#endometriosis" class="gloss-xref">endometriosis</a>.</strong> Central to the <a href="#neofertility" class="gloss-xref">NeoFertility</a> protocol, reproductive immunology evaluation includes <a href="#nk-cells" class="gloss-xref">NK</a> cell panels (natural killer cell activity), antiphospholipid antibody testing, food antibody screening, and <a href="#chronic-endometritis" class="gloss-xref">chronic endometritis</a> workup.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_restorative-andrology', 'restorative-andrology', 'Restorative Andrology', 'VII', 2, '<p><strong>Male-partner evaluation and treatment within the <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> framework, focused on identifying and correcting the underlying causes of <a href="#male-factor-infertility" class="gloss-xref">male factor infertility</a>.</strong> Restorative andrology investigates <a href="#varicocele" class="gloss-xref">varicocele</a>, hormonal imbalance, oxidative stress, infection, sperm DNA fragmentation, and lifestyle contributors rather than bypassing male factor with <a href="#icsi" class="gloss-xref">intracytoplasmic sperm injection</a> (ICSI). Treatment includes varicocelectomy, <a href="#antioxidant-therapy" class="gloss-xref">antioxidant therapy</a>, hormonal correction, and lifestyle modification.<sup class="cite-ref"><a href="#ref-35">35</a></sup><sup class="cite-ref"><a href="#ref-53">53</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_migs', 'migs', 'Minimally Invasive Gynecologic Surgery (MIGS)', 'VII', 3, '<p><strong>Laparoscopic and hysteroscopic surgical techniques used in <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> for excision of <a href="#endometriosis" class="gloss-xref">endometriosis</a>, <a href="#adhesiolysis" class="gloss-xref">adhesiolysis</a>, <a href="#isthmocele-repair-laparoscopic" class="gloss-xref">isthmocele repair</a>, <a href="#myomectomy" class="gloss-xref">myomectomy</a>, and tubal surgery.</strong> MIGS emphasizes tissue preservation and fertility-sparing approaches, removing pathology while maintaining or restoring the structural and functional integrity of reproductive organs. Robotic-assisted and <a href="#mini-laparotomy" class="gloss-xref">mini-laparotomy</a> techniques are included under this umbrella.<sup class="cite-ref"><a href="#ref-10">10</a></sup><sup class="cite-ref"><a href="#ref-17">17</a></sup></p>', 'MIGS', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_cycle-timed-diagnostics', 'cycle-timed-diagnostics', 'Cycle-Timed Diagnostics', 'VII', 4, '<p><strong>The core <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> concept of ordering hormone panels, ultrasounds, and other tests at specific points in the menstrual cycle rather than on random calendar dates.</strong> By timing bloodwork to charting-identified events (e.g., post-<a href="#peak-day" class="gloss-xref">peak day</a> +7 for progesterone, early follicular phase for <a href="#fsh" class="gloss-xref">FSH</a> and estradiol), clinicians detect <a href="#luteal-phase-deficiency" class="gloss-xref">luteal phase deficiency</a>, anovulation, and hormonal patterns that random-draw testing misses. Cycle-timed diagnostics is what makes <a href="#fertility-charting" class="gloss-xref">fertility charting</a> clinically actionable, not merely observational.<sup class="cite-ref"><a href="#ref-3">3</a></sup><sup class="cite-ref"><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_pelvic-floor-physical-therapy', 'pelvic-floor-physical-therapy', 'Pelvic Floor Physical Therapy', 'VII', 5, '<p><strong>Specialized rehabilitation addressing musculoskeletal contributors to <a href="#chronic-pelvic-pain" class="gloss-xref">chronic pelvic pain</a>, dyspareunia, and voiding dysfunction.</strong> Part of the multidisciplinary <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> care team for patients with overlapping gynecologic and musculoskeletal pathology. Pelvic floor therapists assess and treat hypertonic pelvic floor muscles, myofascial trigger points, <a href="#pelvic-adhesions" class="gloss-xref">scar tissue</a> restrictions, and neuromuscular dysfunction that coexist with conditions like <a href="#endometriosis" class="gloss-xref">endometriosis</a> and <a href="#adenomyosis" class="gloss-xref">adenomyosis</a>.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_fertilitycare-practice', 'fertilitycare-practice', 'FertilityCare Practice', 'VII', 6, '<p><strong>The professional discipline of teaching fertility awareness charting methods to patients.</strong> FertilityCare Practitioners (FCPs) are credentialed through the American Academy of FertilityCare Professionals (AAFCP) and serve as the charting education arm of the NaPro care model. FCPs teach the <a href="#creighton-model" class="gloss-xref">Creighton Model FertilityCare System</a> and provide ongoing follow-up to ensure accurate charting. In <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> broadly, certified instructors for each method (<a href="#femm" class="gloss-xref">FEMM</a> Teachers, Marquette instructors, sympto-thermal educators) fill an equivalent role within their respective clinical systems.<sup class="cite-ref"><a href="#ref-7">7</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_functional-nutritional-medicine', 'functional-nutritional-medicine', 'Functional and Nutritional Medicine', 'VII', 7, '<p><strong>Assessment and optimization of nutritional status, metabolic markers, and lifestyle factors as part of reproductive health restoration.</strong> Includes evaluation of vitamin D, folate, B12, iron, zinc, omega-3 fatty acids, insulin resistance, inflammatory markers, and environmental toxin exposure. In <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a>, nutritional and metabolic assessment is not adjunctive. It is part of the core diagnostic workup, addressing modifiable factors that directly affect ovulation, implantation, and pregnancy maintenance.<sup class="cite-ref"><a href="#ref-3">3</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_fcp', 'fcp', 'FertilityCare Practitioner (FCP)', 'VII', 7, '<p>A FertilityCare Practitioner is a trained educator who teaches the <a href="#creighton-model" class="gloss-xref">Creighton Model FertilityCare System</a> to individual clients and couples. FCPs are not physicians. They are the entry point into <a href="#naprotechnology-definition" class="gloss-xref">NaProTechnology</a> care. They teach chart reading, support clients through cycle tracking, and prepare the standardized chart documentation that NaPro-trained physicians use for clinical decision-making.</p> <p>The FCP role is defined and credentialed through the FertilityCare Centers of America training program. Training includes instruction in the biological markers of the Creighton Model, chart interpretation, client education, and the interface between chart findings and medical referral. After initial training, FCPs maintain ongoing professional development.</p> <p>The distinction between an FCP and a physician matters clinically. The FCP builds the chart. The physician reads it in context. Neither is redundant. In NaProTechnology practice, the physician who has never seen the chart is practicing without the most important data set the patient can provide. The chart is the clinical record of what the cycle is doing over time, not a single hormone level drawn at an arbitrary point.<sup class="cite-ref"><a href="#ref-64">64</a></sup></p> <p>For couples using Creighton Model charting to achieve pregnancy, the FCP teaches them to identify the fertile window, observe and record <a href="#biomarkers" class="gloss-xref">biomarkers</a> accurately, and recognize patterns that may indicate underlying conditions worth evaluating. The FCP communicates those patterns to the physician. This is the communication infrastructure of <a href="#restorative-as-a-principle" class="gloss-xref">restorative</a> care.</p> <p>FCPs can also help couples using the Creighton Model to avoid pregnancy. The same chart that guides fertility-seeking couples guides those seeking to space pregnancies, without suppressive medications. The FCP''s role is the same in both contexts: teach accurate observation and support the couple in using their own fertility data.</p> <p>Finding an FCP is typically the first concrete step for couples who want to engage with NaProTechnology or <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> care. An RRM clinician cannot provide chart-based care without the chart. The FCP is what makes the chart possible.</p>', 'FCP', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_nfpmc', 'nfpmc', 'NaProTechnology Medical Consultant (NFPMC)', 'VII', 8, '<p>A <strong>NaProTechnology Medical Consultant (NFPMC)</strong> is a physician (MD or DO) who has completed formal postgraduate training in <a href="#naprotechnology-definition" class="gloss-xref">NaProTechnology</a> through an accredited program. Training routes include the fellowship at the Pope Paul VI Institute for the Study of Human Reproduction and the AAFCP Medical Consultant program. The credential is distinct from standard OBGYN or <a href="#reproductive-endocrinology" class="gloss-xref">reproductive endocrinology</a> training and requires specific coursework in Creighton Model charting interpretation, NaPro diagnostic protocols, and NaPro surgical technique.</p> <p>Patients frequently search for a "NaPro doctor," "NaPro OBGYN," or "NaPro surgeon." These terms all describe the NFPMC role.</p> <p>The NFPMC is distinct from an FCP (<a href="#fcp" class="gloss-xref">FertilityCare Practitioner</a>). An FCP is a credentialed instructor of the Creighton Model Fertility Care System who teaches patients to observe and record their cycle. The NFPMC receives that chart data, runs the diagnostic workup, orders cycle-timed hormone panels, interprets results, prescribes medications, and performs surgical intervention when indicated. The physician and the practitioner work as a team. Neither role replaces the other.</p> <p>The chart is not optional. An NFPMC practicing reproductive medicine without Creighton chart data is practicing without the diagnostic input that makes the NaPro approach function. The chart is the data source. The physician reads it.</p>', 'NFPMC', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_transdermal-estrogen', 'transdermal-estrogen', 'Transdermal Estrogen', 'VII', 9, '<p><strong>Estrogen delivered through the skin via patch, gel, or cream, bypassing first-pass hepatic metabolism.</strong> Unlike oral estrogen, which passes through the liver before reaching systemic circulation, transdermal delivery provides steady-state estrogen levels with significantly lower impact on coagulation factors, C-reactive protein, and triglycerides. This pharmacokinetic difference is clinically important for women with thrombophilic risk factors or metabolic concerns.</p> <p>In <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> practice, transdermal estrogen is used primarily for <a href="#poi" class="gloss-xref">premature ovarian insufficiency</a> and in selected perimenopausal management protocols. For women with POI, hormone replacement is not optional wellness support. It is medical necessity. Estrogen deficiency at age 28 or 34 carries cardiovascular, skeletal, and neurological consequences that accumulate silently without treatment. The goal is physiological replacement, not supraphysiologic dosing.</p> <p>Transdermal delivery allows more precise titration than oral preparations and avoids the hepatic triglyceride stimulation associated with oral estrogen. Combined with progesterone support (typically micronized progesterone or a progestin), transdermal regimens can be tailored to the individual''s hormonal profile, symptoms, and cycle remnants in women with partial ovarian function.</p> <p>The distinction between transdermal estrogen as physiological replacement and suppressive medications is fundamental to RRM framing. Physiological replacement restores what the body cannot produce. Suppressive medications override what the body is producing. These are different pharmacological goals requiring different clinical conversations.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_follicle-stimulation', 'follicle-stimulation', 'Follicle Stimulation / Ovulation Induction', 'VII', 10, '<p><strong>The use of pharmacological agents to stimulate <a href="#follicle-development" class="gloss-xref">follicle development</a> and ovulation in cycles where the natural process is inadequate or absent.</strong> In <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> and <a href="#napro-medical" class="gloss-xref">NaPro Medical</a> protocols, ovulation induction uses oral agents, primarily clomiphene citrate or letrozole, timed to the follicular phase based on Creighton Model charting. The goal is to support the body''s own ovulatory process, not to retrieve oocytes.</p> <p>Letrozole (an aromatase inhibitor) is the preferred first-line agent for ovulation induction in many RRM protocols, particularly for <a href="#pcos" class="gloss-xref">PCOS</a> and anovulatory <a href="#infertility" class="gloss-xref">infertility</a>. The NEJM trial by Legro and colleagues demonstrated letrozole''s superiority over clomiphene for live birth rates in PCOS.<sup class="cite-ref"><a href="#ref-76">76</a></sup> Clomiphene remains in use where letrozole is not indicated or available, and in combination protocols.</p> <p>Cycle monitoring during ovulation induction is standard in RRM practice. A <a href="#follicle-maturation-study" class="gloss-xref">follicle maturation study</a> confirms follicle growth, guides the decision to add an <a href="#hcg-trigger" class="gloss-xref">HCG trigger</a>, and identifies poor response early rather than after multiple failed cycles. Monitoring also prevents inadvertent multi-follicular development, which carries its own risks in natural conception protocols.</p> <p>Ovulation induction in this context is fundamentally different from controlled ovarian hyperstimulation (COH) used in <a href="#ivf" class="gloss-xref">IVF</a> protocols. COH intentionally stimulates multiple follicles for oocyte retrieval. RRM ovulation induction targets one well-developed follicle for in-body conception. The pharmacological agents may overlap. The clinical goals do not.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_napro-vs-rrm', 'napro-vs-rrm', 'NaProTECHNOLOGY vs. RRM', 'VIII', 0, '<p><strong><a href="#naprotechnology-definition" class="gloss-xref">NaProTECHNOLOGY</a> (NaPro) is the most established and studied approach within <a href="#restorative-reproductive-medicine" class="gloss-xref">restorative reproductive medicine</a></strong>, developed by Dr. Thomas Hilgers at the Pope Paul VI Institute and based on the Creighton Model. RRM is a broader category describing approaches that share the <a href="#restorative-as-a-principle" class="gloss-xref">restorative</a> philosophy. NaPro practitioners may or may not identify their work under the RRM label. Other approaches that share this philosophy include: <a href="#neofertility" class="gloss-xref">NeoFertility</a>, <a href="#marquette-method" class="gloss-xref">Marquette Method</a>-based medical management, <a href="#femm" class="gloss-xref">FEMM</a>-based care, and various symptothermal or sympto-hormonal approaches. All share the common framework of using biomarker data from cycle charting to optimize normal reproductive function.<sup class="cite-ref"><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_iui', 'iui', 'IUI (Intrauterine Insemination)', 'VIII', 1, '<p><strong>Intrauterine insemination (IUI) is a procedure in which washed and concentrated sperm are deposited directly into the uterine cavity via a thin catheter at the time of ovulation, bypassing cervical mucus filtration.</strong> IUI is less invasive than <a href="#ivf" class="gloss-xref">IVF</a> and does not involve external fertilization. Fertilization, if it occurs, happens in the fallopian tube. Indications include mild <a href="#male-factor-infertility" class="gloss-xref">male factor infertility</a>, <a href="#cervical-factor-infertility" class="gloss-xref">cervical factor infertility</a>, donor sperm use, and some cases of undiagnosed <a href="#infertility" class="gloss-xref">infertility</a>. Per-cycle clinical pregnancy rates vary widely by age, sperm parameters, and the underlying cause of reduced fertility. IUI bypasses the cervical environment. It does not correct what made that bypass necessary. Within <a href="/what-is-rrm/">RRM</a>, IUI is not a <a href="#restorative-as-a-principle" class="gloss-xref">restorative</a> therapy. <a href="#naprotechnology-definition" class="gloss-xref">NaProTECHNOLOGY</a> and <a href="#neofertility" class="gloss-xref">NeoFertility</a> protocols do not employ IUI. Instead, clinicians time natural intercourse to cycle-identified fertile windows and correct the underlying causes of subfertility in one or both partners.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_ivf', 'ivf', 'IVF (In Vitro Fertilization)', 'VIII', 2, '<p><strong>In vitro fertilization (IVF) is a form of <a href="#art" class="gloss-xref">assisted reproductive technology</a> in which mature oocytes are retrieved from the ovaries via transvaginal aspiration after controlled ovarian hyperstimulation, fertilized externally in the laboratory (by conventional IVF or <a href="#icsi" class="gloss-xref">intracytoplasmic sperm injection</a>, ICSI), cultured to cleavage or blastocyst stage, and transferred into the uterus as one or more embryos.</strong> IVF bypasses the reproductive process rather than restoring it. The underlying anatomical, hormonal, and immunologic problems that prevented conception remain uncorrected. Controlled hyperstimulation routinely produces more embryos than will be transferred. Those not transferred may be frozen, donated to other couples, donated for research, or destroyed. Each of those is a consequential decision, not a logistical one. Known risks include <a href="#ohss" class="gloss-xref">ovarian hyperstimulation syndrome</a> (OHSS), multiple pregnancy when more than one embryo is transferred, elevated rates of preterm birth and low birthweight, and ongoing uncertainty about long-term offspring outcomes at the registry level. Per-cycle live-birth rates decline sharply with maternal age. Within <a href="/what-is-rrm/">RRM</a>, IVF is a bypass technology. The question <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> asks is different: not how to work around a failing reproductive system, but what is causing it to fail, and whether that cause can be corrected. See <a href="#ivf-vs-rrm" class="gloss-xref">IVF vs. RRM: Key Conceptual Distinctions</a> for a side-by-side comparison.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_ivf-vs-rrm', 'ivf-vs-rrm', 'IVF vs. RRM: Key Conceptual Distinctions', 'VIII', 3, '<div class="table-wrap"> <table> <thead> <tr> <th>Dimension</th> <th><a href="#ivf" class="gloss-xref">IVF</a> / <a href="#art" class="gloss-xref">ART</a></th> <th><a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a></th> </tr> </thead> <tbody> <tr><td>Approach</td><td>Bypasses <a href="#infertility" class="gloss-xref">infertility</a> cause</td><td>Corrects infertility cause</td></tr> <tr><td>Conception</td><td>External fertilization (outside the body)</td><td>Natural conception (within the body)</td></tr> <tr><td>Cycle use</td><td>Suppresses/overrides natural cycle</td><td>Works with natural cycle</td></tr> <tr><td><a href="#time-to-pregnancy" class="gloss-xref">Time to pregnancy</a></td><td>Higher monthly success per cycle</td><td>Cumulative success over time</td></tr> <tr><td>Singleton outcomes</td><td>Higher multiple pregnancy risk</td><td>All natural pregnancies (no multiples)<sup class="cite-ref"><a href="#ref-10">10</a></sup></td></tr> <tr><td>Long-term health</td><td>Addresses procedure only</td><td>Improves overall reproductive health</td></tr> <tr><td>Cost</td><td>Often higher per-treatment cycle</td><td>Generally lower; may cost less overall<sup class="cite-ref"><a href="#ref-3">3</a></sup></td></tr> </tbody> </table> </div>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_patient-centered-care', 'patient-centered-care', 'Patient-Centered Care', 'VIII', 4, '<p><strong>A guiding <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> value emphasizing patient understanding, informed consent, and active participation in health decisions.</strong> <a href="#fertility-charting" class="gloss-xref">Fertility charting</a> education gives patients direct insight into their own hormonal and physiological patterns. When treating for <a href="#infertility" class="gloss-xref">infertility</a> or miscarriage, RRM clinicians treat the couple (both male and female) as a single unit.<sup class="cite-ref"><a href="#ref-1">1</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_couple-based-treatment', 'couple-based-treatment', 'Couple-Based Treatment', 'VIII', 5, '<p><strong>The <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> principle that when <a href="#infertility" class="gloss-xref">infertility</a> or recurrent miscarriage is the concern, both partners receive evaluation and treatment as a unit.</strong> Male factor is the sole cause of infertility in approximately 20% of couples and a contributing factor in another 30 to 40%. Both partners are always assessed in RRM. This approach supports the relationship and reduces the emotional burden that often falls disproportionately on the female partner.<sup class="cite-ref"><a href="#ref-35">35</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_adhesion-prevention', 'adhesion-prevention', 'Adhesion Prevention', 'VIII', 7, '<p><strong>The active strategy employed in <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a>/NaPro Surgery to minimize post-operative adhesion formation</strong> through meticulous hemostasis, careful tissue handling, thorough peritoneal irrigation, and the strategic use of <a href="#anti-adhesion-barriers" class="gloss-xref">anti-adhesion barriers</a> (Gore-Tex membrane). One published NaPro series documented a mean adhesion score reduction from 33.3 to 6.0 over 23 years with systematic barrier use.<sup class="cite-ref"><a href="#ref-10">10</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_antioxidant-therapy', 'antioxidant-therapy', 'Antioxidant Therapy', 'VIII', 8, '<p><strong>The therapeutic use of antioxidant compounds to reduce oxidative stress in both male and female reproductive contexts.</strong> In males, antioxidants (vitamin C, E, CoQ10, zinc, selenium, L-carnitine, N-acetylcysteine) reduce sperm DNA fragmentation and improve sperm parameters. In females, antioxidants support oocyte quality, reduce <a href="#endometriosis" class="gloss-xref">endometriosis</a>-related oxidative damage, and may support embryo development.<sup class="cite-ref"><a href="#ref-22">22</a></sup><sup class="cite-ref"><a href="#ref-19">19</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_nutritional-lifestyle-medicine', 'nutritional-lifestyle-medicine', 'Nutritional and Lifestyle Medicine', 'VIII', 9, '<p><strong><a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> incorporates assessment and optimization of nutritional status</strong> (vitamin D, folate, B12, iron, zinc, omega-3s) and lifestyle factors (sleep, stress, physical activity, body weight, environmental toxin exposure) as foundational elements of reproductive health restoration. Nutritional deficiencies and poor lifestyle factors are identified as contributing underlying factors, not peripheral concerns.<sup class="cite-ref"><a href="#ref-3">3</a></sup></p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_icsi', 'icsi', 'Intracytoplasmic Sperm Injection (ICSI)', 'VIII', 10, '<p>Intracytoplasmic sperm injection is a laboratory procedure in which a single sperm is selected and injected directly into an egg. It was developed in the early 1990s and became widespread as a solution for severe <a href="#male-factor-infertility" class="gloss-xref">male factor infertility</a>, where conventional <a href="#ivf" class="gloss-xref">IVF</a> fertilization rates were poor.</p> <p>ICSI has since expanded far beyond its original indication. It is now routinely used in IVF cycles even when sperm parameters are normal, often without clear clinical justification. When sperm quality is genuinely impaired, the underlying cause matters. ICSI bypasses the fertilization problem. It does not diagnose or treat the condition causing the impaired sperm.</p> <p>From an <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> perspective, the first question is always: why is the sperm quality abnormal? Sperm DNA fragmentation, <a href="#varicocele" class="gloss-xref">varicocele</a>, hormonal imbalance, oxidative stress, and infection are all treatable causes that can be identified and addressed. Treating the root cause can improve sperm quality for natural conception. ICSI, by contrast, works around the problem while leaving it in place.</p> <p>There are also recognized risks associated with ICSI that are not always discussed with couples before the procedure. The mechanical injection bypasses natural sperm selection mechanisms. The long-term safety data for offspring conceived via ICSI continues to be evaluated, and certain genetic risks, particularly in cases of severe male factor, may be transmissible to male offspring.<sup class="cite-ref"><a href="#ref-63">63</a></sup></p> <p>For couples where male factor is the primary barrier to natural conception, RRM evaluation of both partners is the starting point. Male evaluation, including <a href="#semen-analysis" class="gloss-xref">semen analysis</a>, hormonal panel, and sperm DNA fragmentation testing, identifies what is treatable. The goal is to restore fertility, not to engineer around it in a laboratory.</p>', 'ICSI', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_ohss', 'ohss', 'Ovarian Hyperstimulation Syndrome (OHSS)', 'VIII', 11, '<p>Ovarian hyperstimulation syndrome is a complication of ovarian stimulation, most commonly occurring in the context of <a href="#ivf" class="gloss-xref">IVF</a>. High doses of gonadotropins cause the ovaries to produce far more follicles than they would in a natural cycle. In susceptible women, this triggers a cascade of vascular permeability changes, fluid shifts, and electrolyte disturbances that can range from mild discomfort to a life-threatening medical emergency.</p> <p>Mild OHSS is common. Severe OHSS requiring hospitalization is less frequent but not rare. Major professional societies have published guidance on classification and prevention, recognizing OHSS as an iatrogenic complication of ovarian stimulation protocols.<sup class="cite-ref"><a href="#ref-62">62</a></sup> Women with <a href="#pcos" class="gloss-xref">PCOS</a> are at significantly higher risk because their ovaries already contain a large number of antral follicles that respond aggressively to stimulation.</p> <p>OHSS does not occur in <a href="#restorative-reproductive-medicine" class="gloss-xref">restorative reproductive medicine</a> protocols. RRM uses low-dose, cycle-timed hormonal support to assist the body''s own <a href="#follicle-development" class="gloss-xref">follicle development</a>. Medications are used at physiologic doses to correct documented deficiencies, not to override the ovarian cycle with pharmacologic superstimulation. The risk of OHSS is specific to the ovarian stimulation paradigm, not to hormonal medicine broadly.</p> <p>For women with PCOS who are offered IVF, OHSS risk should be part of an honest informed consent discussion. There are risk-reduction strategies within IVF protocols. But the more fundamental question is whether stimulation for IVF is the right starting point when the underlying cause of anovulation has not been evaluated or treated. Many women with PCOS can achieve natural conception with appropriate cycle support once the hormonal and metabolic contributors are identified.</p> <p>OHSS is one of several reasons why RRM clinicians evaluate PCOS and <a href="#anovulatory-cycles" class="gloss-xref">anovulatory cycles</a> with a <a href="#restorative-as-a-principle" class="gloss-xref">restorative</a> approach first. The goal is to support the cycle the patient has, not to replace it with an artificially stimulated one that carries its own risks.</p>', 'OHSS', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_art', 'art', 'Assisted Reproductive Technology (ART)', 'VIII', 12, '<p><strong>Assisted Reproductive Technology (ART)</strong> is the umbrella term for medical procedures that involve handling eggs, sperm, or embryos outside the body to achieve pregnancy. This includes <a href="#ivf" class="gloss-xref">in vitro fertilization</a> (IVF), <a href="#icsi" class="gloss-xref">intracytoplasmic sperm injection</a> (ICSI), <a href="#iui" class="gloss-xref">intrauterine insemination</a> (IUI), donor egg and donor sperm cycles, embryo transfer, and gestational surrogacy. Insurance documents, fertility clinic literature, and public health data all use ART as the standard classification.</p> <p>ART procedures are bypass technologies. They work around reproductive barriers without investigating or treating the underlying cause. A woman with undiagnosed <a href="#endometriosis" class="gloss-xref">endometriosis</a> who undergoes IVF still has endometriosis. A couple with undiagnosed male factor who pursues IUI still has an undiagnosed male factor. The conception method changes. The underlying condition does not.</p> <p><a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> is not ART. The two approaches reflect opposite premises. ART proceeds from the assumption that the body cannot succeed and builds technology around that assumption. RRM asks why the body has not succeeded, then treats the answer. These are different questions, not competing techniques.</p> <p>ART live-birth rates vary substantially by maternal age, diagnosis, and clinic. Per CDC and HFEA annual reporting, national averages for fresh non-donor IVF cycles decline sharply after age 35. Patients deserve accurate, age-stratified outcome data before consenting to any ART procedure.</p>', 'ART', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_oc', 'oc', 'Oral Contraceptive (OC)', 'VIII', 13, '<p><strong>Oral contraceptives (OCs)</strong> are hormone-based medications taken by mouth to prevent pregnancy. Combined oral contraceptives (COCs) contain synthetic estrogen and progestin. Progestin-only pills contain progestin alone. Both work primarily by suppressing pituitary gonadotropin release, preventing ovulation. The menstrual cycle is not regulated by the pill; it is suppressed and replaced by a withdrawal bleed timed to the pill-free interval.</p> <p>OCs are prescribed for contraception and for non-contraceptive indications: painful periods, <a href="#pcos" class="gloss-xref">PCOS</a> symptom management, <a href="#endometriosis" class="gloss-xref">endometriosis</a>-related pain, and acne. In each application, the mechanism is the same: cycle suppression. Symptoms may diminish while the medication is taken. The underlying condition does not change.</p> <p>When a patient stops an OC prescribed <a href="#excision-surgery" class="gloss-xref">for endometriosis</a> pain, the disease remains, at whatever stage it reached during suppression. When a patient stops an OC prescribed for PCOS, the androgen excess and anovulation return. The suppression was not treatment. <a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> clinicians use the term "suppressive medications" precisely because it names what these drugs do.</p> <p>Documented effects associated with long-term OC use include changes in bone mineral density, cardiovascular risk markers, and mood. The strength of the evidence varies by outcome, and these risks are rarely discussed in standard prescribing conversations. Patients using OCs for years deserve that information.<sup class="cite-ref"><a href="#ref-71">71</a></sup></p>', 'OC', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_iud', 'iud', 'Intrauterine Device (IUD)', 'VIII', 14, '<p>An <strong>intrauterine device (IUD)</strong> is a small, T-shaped device inserted into the uterine cavity for contraception. Two primary types are in clinical use.</p> <p>The copper IUD works without hormones. Copper ions impair sperm motility and reduce fertilization. At higher concentrations, copper may also affect implantation if fertilization occurs, though the primary mechanism operates before fertilization.</p> <p>The hormonal IUD releases levonorgestrel, a synthetic progestin, locally into the uterine cavity. It thickens cervical mucus, thins the endometrial lining, and may suppress ovulation in some users, particularly in the first year. Its primary mechanisms are cervical and endometrial. Whether post-fertilization effects occur remains a matter of scientific debate and is directly relevant to informed consent for couples who consider fertilization the beginning of a new life.<sup class="cite-ref"><a href="#ref-72">72</a></sup></p> <p>Side effects: the copper IUD frequently causes heavier menstrual bleeding and increased cramping. The hormonal IUD frequently causes irregular bleeding or amenorrhea. Amenorrhea eliminates menstrual cycle data as a diagnostic source. Both types carry a small risk of expulsion, uterine perforation at insertion, and infection during the insertion procedure.</p> <p><a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> does not prescribe or recommend IUDs. Understanding how they work is part of informed care.</p>', 'IUD', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_hrt', 'hrt', 'Hormone Replacement Therapy (HRT)', 'VIII', 15, '<p><strong>Hormone replacement therapy (HRT)</strong> refers to exogenous administration of estrogen, progesterone, or both, to supplement or replace hormonal production the body is no longer sustaining at adequate levels. Testosterone may also be included. HRT is used primarily for menopausal symptoms and for <a href="#poi" class="gloss-xref">premature ovarian insufficiency</a> (POI), a condition in which ovarian function declines before age 40.</p> <p><a href="#restorative-reproductive-medicine" class="gloss-xref">RRM</a> draws a clear distinction between two uses of exogenous hormones. The first: replacing what the body genuinely cannot produce. A 32-year-old with POI who has no functional ovarian estrogen production needs physiological replacement. That is <a href="#restorative-as-a-principle" class="gloss-xref">restorative</a> medicine. Without it, she faces accelerated bone loss, cardiovascular risk, and neurological effects. The second use: administering hormones to suppress or override normal reproductive function. RRM does not operate in the second category.</p> <p>When HRT is medically indicated, RRM clinicians generally favor bioidentical hormone formulations. Bioidentical hormones are structurally identical to the hormones the body produces. Synthetic formulations are not. The evidence comparing bioidentical and synthetic preparations continues to develop, and the difference matters for receptor binding, metabolism, and long-term safety profile.</p> <p>Patients with POI benefit from early, thorough evaluation before beginning HRT, including discussion of fertility implications. Evidence-based guidelines recommend HRT in POI until at least the average age of natural <a href="#menopause" class="gloss-xref">menopause</a>, given the documented risks of untreated estrogen deficiency.<sup class="cite-ref"><a href="#ref-73">73</a></sup></p>', 'HRT', NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
INSERT INTO glossary_term (id, slug, name, part, sort_order, body_html, abbreviation, pillar_link, status) VALUES ('term_endometritis_mock', 'endometritis', 'Endometritis', 'VI', 999, '<p><strong>Endometritis</strong> is inflammation of the endometrium (uterine lining), occurring in acute or chronic forms. Acute endometritis presents with fever, pelvic pain, abnormal uterine bleeding, and uterine tenderness, most commonly following childbirth, miscarriage, dilation-and-curettage, hysteroscopy, IUD placement, or as a sequela of pelvic inflammatory disease (PID). In Restorative Reproductive Medicine workups, endometritis (especially the chronic form) is a routine target for patients with infertility, recurrent pregnancy loss, or persistent abnormal bleeding patterns -- typically evaluated via endometrial biopsy with CD138 staining, hysteroscopic visualization ("strawberry pattern"), or molecular endometrial microbiome testing (EMMA/ALICE). Treatment involves targeted antibiotics followed by repeat biopsy to confirm resolution before further fertility intervention. See also <a href="#chronic-endometritis">Chronic Endometritis (CE)</a>.</p>', NULL, NULL, 'published') ON CONFLICT(slug) DO UPDATE SET name=excluded.name, part=excluded.part, sort_order=excluded.sort_order, body_html=excluded.body_html, abbreviation=excluded.abbreviation, pillar_link=excluded.pillar_link, updated_at=datetime('now');
